const QUESTION_BANK11 = [
  {"id": "q12000", "field": "古代", "difficulty": 3, "type": "short", "question": "縄文時代の遺物には、女性をかたどったものが多く、完全な形ではなく意図的に壊されたような状態で出土する例が目立つものがある。豊穣や再生への祈りに関わる呪術的な意味を持つと考えられているこの土製品を何というか。", "choices": [], "answer": "土偶", "modelAnswer": "土偶", "explanation": "土偶は縄文時代を代表する呪術的遺物で、乳房や妊娠を思わせる女性的特徴を持つものが多く、身体の一部が欠けた状態で発見されることが多い。生殖・収穫を祈願して用いた後、意図的に破壊したとする説が有力とされる。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12001", "field": "古代", "difficulty": 4, "type": "short", "question": "1984年から翌年にかけての発掘調査で、銅剣358本、銅矛16本、銅鐸6個がまとまって埋納された状態で発見され、それまでの青銅器分布に関する理解を大きく見直させることになった島根県の遺跡を何というか。", "choices": [], "answer": "荒神谷遺跡", "modelAnswer": "荒神谷遺跡", "explanation": "荒神谷遺跡(神庭荒神谷遺跡)は出雲地方にあり、銅剣・銅矛(従来北部九州・瀬戸内に多いとされた祭器)と銅鐸(近畿・東海に多いとされた祭器)がともにまとまって出土したことから、弥生時代の祭祀圏や政治的まとまりについての議論を活性化させた。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12002", "field": "古代", "difficulty": 4, "type": "truefalse", "question": "奈良県明日香村にあるキトラ古墳は、天文図や四神・十二支の壁画を持つ点で他に例を見ず、壁画のカビによる劣化が進んだため石室を解体し、壁画をはぎ取って保存処理が行われた。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "キトラ古墳は現存する古墳壁画の中で唯一、十二支の像がまとまって確認される古墳で、天文図・四神とあわせて貴重な資料となっている。保存環境の悪化に伴い、壁画を石室から剥ぎ取って修復・保存する方針がとられた。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12003", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文時代の人々が、山や巨木、岩などのあらゆる自然物・自然現象に霊威を認め、精霊が宿ると考えた信仰のあり方を、カタカナで何というか。", "choices": [], "answer": "アニミズム", "modelAnswer": "アニミズム", "explanation": "アニミズム(精霊崇拝)は自然物に霊魂の存在を認める信仰形態で、縄文時代の祭祀遺構や遺物の背景にある思想として考えられ、後の神道的な自然崇拝の源流の一つともされる。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12004", "field": "古代", "difficulty": 3, "type": "choice", "question": "8世紀の日本と友好的な使者の往来を続けながらも、たびたび国家意識の衝突から緊張が高まり、日本側で相手国への軍事的な征討計画が立てられたこともある朝鮮半島の国はどれか。", "choices": ["高句麗", "百済", "新羅", "高麗", "渤海"], "answer": 2, "modelAnswer": "", "explanation": "新羅とは遣新羅使・新羅使の往来が続いたが、律令国家としての対等意識のぶつかり合いから緊張が高まることもあり、8世紀半ばには新羅征討計画が立てられている。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12005", "field": "古代", "difficulty": 4, "type": "short", "question": "8世紀半ば、新羅との関係悪化を背景に新羅征討の計画を主導したとされる、当時太政官の実権を握っていた人物は誰か。", "choices": [], "answer": "藤原仲麻呂", "modelAnswer": "藤原仲麻呂", "explanation": "藤原仲麻呂(のちの恵美押勝)は孝謙天皇の信任のもとで権勢をふるい、新羅征討計画を進めたが、実際の派兵には至らなかった。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12006", "field": "古代", "difficulty": 3, "type": "short", "question": "高句麗の滅亡後にその後継国を称し、727年に初めて日本へ使者を派遣して以降、日本と友好的な通交を続けたが、926年に契丹(遼)によって滅ぼされた国はどこか。", "choices": [], "answer": "渤海", "modelAnswer": "渤海", "explanation": "渤海は大祚栄が建国し、高句麗の後継国を称して日本と通交、新羅との間の仲介的役割も果たしたが、926年に契丹(遼)によって滅ぼされ、日本との通交は途絶えた。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12007", "field": "中世", "difficulty": 3, "type": "short", "question": "1069年、後三条天皇が発した荘園整理令にともなって設置された、荘園の券契(証拠書類)を審査するための機関を何というか。", "choices": [], "answer": "記録荘園券契所", "modelAnswer": "記録荘園券契所", "explanation": "延久の荘園整理令では、記録荘園券契所(記録所)が設けられ、摂関家の荘園も含めて厳格な審査が行われ、証拠不十分な新立荘園が停止された。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12008", "field": "中世", "difficulty": 3, "type": "choice", "question": "白河天皇によって1077年に建立され、以後の堀河・鳥羽・待賢門院などによる同様の寺院建立の先例となった、六勝寺の最初の寺院はどれか。", "choices": ["法勝寺", "尊勝寺", "最勝寺", "円勝寺", "成勝寺"], "answer": 0, "modelAnswer": "", "explanation": "法勝寺は白河天皇の御願寺として建立された六勝寺の最初の寺院で、郡規模の荘園を寺領にあてて法会の運営費とするなど、院政期の荘園公領制と結びついた寺院経営の典型例とされる。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12009", "field": "中世", "difficulty": 4, "type": "short", "question": "鎌倉幕府が諸国に命じて作成させた、国内の荘園・公領を漏らさず記載した土地台帳を何というか。", "choices": [], "answer": "大田文", "modelAnswer": "大田文", "explanation": "大田文は国衙領・荘園の別なく田数などを国ごとに書き上げたもので、島津家文書に残る建久年間作成の「薩摩国図田帳」などが早い例として知られ、荘園公領制の枠組みを国レベルで固定する役割を果たした。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12010", "field": "中世", "difficulty": 3, "type": "short", "question": "1221年、後鳥羽上皇が鎌倉幕府打倒を企てて挙兵したが敗北し、これ以後、朝廷に対する幕府の優位が決定的となった戦いを何というか。", "choices": [], "answer": "承久の乱", "modelAnswer": "承久の乱", "explanation": "承久の乱の結果、幕府は京都に六波羅探題を設置して朝廷監視と西国支配を強化し、以後、大田文による荘園公領の掌握も全国的に広がっていった。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12011", "field": "近世", "difficulty": 3, "type": "choice", "question": "8代将軍徳川吉宗による享保の改革に関する記述として、誤っているものはどれか。", "choices": ["旗本の大岡忠相を町奉行に登用した", "目安箱を設置し庶民の意見を政治に反映させようとした", "上げ米の制を実施するかわりに参勤交代での江戸在住期間を短縮した", "公事方御定書を編纂し裁判の基準を整備した", "株仲間を全面的に解散させ自由な取引を促進した"], "answer": 4, "modelAnswer": "", "explanation": "享保の改革では株仲間はむしろ公認・活用され、酒・塩など同業者の組合として認められて統制の道具とされた。株仲間を全面的に解散させたのは天保の改革(水野忠邦)の政策であり、享保の改革の内容ではない。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12012", "field": "近世", "difficulty": 3, "type": "short", "question": "田沼意次が株仲間の結成を広く奨励した際、その営業独占の代償として、株仲間に毎年上納させた営業税を何というか(冥加金とあわせて2種のうちの一方)。", "choices": [], "answer": "運上金", "modelAnswer": "運上金", "explanation": "田沼意次は株仲間を江戸・大坂の問屋だけでなく在方町の商人にも広げ、運上金・冥加金を上納させることで幕府の新たな収入源とした。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12013", "field": "近世", "difficulty": 4, "type": "short", "question": "1823(文政6)年、摂津・河内・和泉3カ国1000カ村余りの村々が結集し、大坂の株仲間商人による木綿・菜種の流通独占に反対して起こした、訴訟という合法的手段による大規模な運動を何というか。", "choices": [], "answer": "国訴", "modelAnswer": "国訴", "explanation": "国訴は在方商人・農民が奉行所へ訴え出るという合法的な手段を用いて株仲間の流通独占に対抗した運動で、自由な販売を実現させ、株仲間による市場統制に打撃を与えた。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12014", "field": "近世", "difficulty": 4, "type": "short", "question": "天保の改革による株仲間解散がかえって商品流通を混乱させ物価上昇を招いたため、1851(嘉永4)年に株仲間を再興させるなど現実的な政策をとった、ペリー来航時の老中は誰か。", "choices": [], "answer": "阿部正弘", "modelAnswer": "阿部正弘", "explanation": "阿部正弘は株仲間解散による流通混乱を是正するため、新興商人も加えて株仲間を再興し、江戸・大坂への物資流入の増加と全国市場の統制を図った。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12015", "field": "近代", "difficulty": 3, "type": "short", "question": "明治政府が沖縄県設置後も旧慣を温存する一方、宮古・八重山諸島の住民に対して年齢・性別を基準に一律に課していた重税を何というか。", "choices": [], "answer": "人頭税", "modelAnswer": "人頭税", "explanation": "人頭税は所得の多寡に関わりなく人数に応じて課される重税で、宮古島の住民らはその廃止を求める運動を展開し、1903年に廃止が実現した。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12016", "field": "近代", "difficulty": 3, "type": "short", "question": "1899(明治32)年に制定され、アイヌ民族への農地給付などを名目としながら、実際には同化政策を進め差別と貧困を固定化する役割を果たした法律を何というか。", "choices": [], "answer": "北海道旧土人保護法", "modelAnswer": "北海道旧土人保護法", "explanation": "北海道旧土人保護法は日本式生活・日本語使用への同化を促す性格が強く、アイヌ固有の生業や文化を軽視する内容であったため、後年批判を受け1997年のアイヌ文化振興法制定により廃止された。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12017", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "足尾鉱毒事件では、衆議院議員を辞職した田中正造が明治天皇への直訴を試みたが、直訴状は警察によって取り押さえられ受理されず、翌年になって政府は鉱毒調査委員会を設置した。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "1901年、田中正造は足尾銅山の操業停止と被害民救済を訴えるため議員を辞職し天皇へ直訴を試みたが、直訴状は受理されなかった。世論の高まりを受け、政府は翌1902年に鉱毒調査委員会を設置するなど一定の対応を示した。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12018", "field": "近代", "difficulty": 3, "type": "short", "question": "1922(大正11)年、被差別部落の住民が全国的な団結のもとで差別からの解放を目指して結成した組織を何というか。", "choices": [], "answer": "全国水平社", "modelAnswer": "全国水平社", "explanation": "全国水平社は「人の世に熱あれ、人間に光あれ」で結ばれる水平社宣言のもとに創設され、部落差別の撤廃を求める組織的な解放運動の中心となった。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12019", "field": "現代", "difficulty": 3, "type": "choice", "question": "1951年に調印され、翌1952年の発効によって日本が主権を回復するとともに、同じ日に日米安全保障条約も締結されるきっかけとなった条約はどれか。", "choices": ["日米和親条約", "日ソ共同宣言", "サンフランシスコ平和条約", "日華平和条約", "日中平和友好条約"], "answer": 2, "modelAnswer": "", "explanation": "サンフランシスコ平和条約は1951年9月、アメリカなど48カ国との間で調印され、1952年4月に発効して日本は独立を回復した。同日、日米安全保障条約も締結され、日本はアメリカの東アジア戦略の重要な基地として位置づけられた。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12020", "field": "文化史", "difficulty": 3, "type": "short", "question": "1180年の南都焼討ち後、奈良仏師による興福寺復興事業の中心となり、写実的で力強い作風の木彫像として知られる興福寺北円堂の「無著・世親像」を制作した人物は誰か。", "choices": [], "answer": "運慶", "modelAnswer": "運慶", "explanation": "運慶は玉眼の技法や量感豊かな肉体表現を特色とし、東大寺南大門金剛力士像なども手がけた鎌倉時代を代表する仏師で、「無著・世親像」はその写実表現の到達点とされる。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12021", "field": "文化史", "difficulty": 3, "type": "short", "question": "1904(明治37)年、22歳の画家が房州の海辺での取材をもとに、大きなサメを担いで進む裸の漁師たちの群像を力強い筆致で描き、白馬会に出品した代表作を何というか。", "choices": [], "answer": "海の幸", "modelAnswer": "海の幸", "explanation": "「海の幸」は青木繁が房州布良での取材を経て描いたロマン主義的な作品で、白馬会に出品されて高く評価され、若き日の青木の代表作として知られる。(文学部2007年で問われた論点)", "source": "2007", "faculty": "文学部"},
  {"id": "q12040", "field": "古代", "difficulty": 2, "type": "truefalse", "question": "縄文時代の集落には、竪穴住居跡と墓域などが組み合わさった、一定のまとまりをもつ定型的な集落形態が広く認められる。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "縄文時代には比較的安定した定住生活が営まれ、竪穴住居跡や墓域などから構成される、一定の秩序をもった集落形態が各地の遺跡で確認されている。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12041", "field": "古代", "difficulty": 4, "type": "short", "question": "今から3000年ほど前から2000年ほど前の縄文後期・晩期にかけて、東北地方を中心に精巧な土器・土偶などの遺物を多く残し、東日本における呪術・儀礼の発達を示す代表的な遺跡はどこか。", "choices": [], "answer": "亀ヶ岡遺跡", "modelAnswer": "亀ヶ岡遺跡", "explanation": "亀ヶ岡遺跡(青森県)は縄文晩期を代表する遺跡で、遮光器土偶をはじめ精巧な土器・土製品が出土し、東日本における縄文後期・晩期の精神文化の発達を示す代表例とされる。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12042", "field": "古代", "difficulty": 2, "type": "short", "question": "弥生時代、水田農耕の広がりとともに営まれるようになった、周囲を堀で囲んだ集落を何というか。", "choices": [], "answer": "環濠集落", "modelAnswer": "環濠集落", "explanation": "環濠集落は水田を経営する共同体の防御・領域確保のために形成されたと考えられ、吉野ヶ里遺跡などが代表例として知られる。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12043", "field": "古代", "difficulty": 3, "type": "short", "question": "大宝律令の規定では、地方行政組織の末端単位である「里」は何戸から構成されると定められていたか、算用数字で答えよ。", "choices": [], "answer": "50", "modelAnswer": "50", "explanation": "大宝令では50戸をもって1里とし、この編成は大宝令発布以前から長く行われていた戸籍・計帳作成の基礎単位でもあった。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12044", "field": "古代", "difficulty": 3, "type": "short", "question": "律令制下、班給された口分田に対して課され、収穫の約3%程度を稲(のち春米)として納めさせた税を何というか。", "choices": [], "answer": "租", "modelAnswer": "租", "explanation": "租は口分田を班給された者に課された税で、収穫の約3%程度を稲や春米として郡家の正倉に納めさせるもので、地方財源として運用された。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12045", "field": "古代", "difficulty": 3, "type": "short", "question": "律令制の税のうち、絹・布など地方の産物を都へ貢納するもので、古くから「みつき」とも呼ばれたものは何か。", "choices": [], "answer": "調", "modelAnswer": "調", "explanation": "調は各地の特産品(絹・布などの繊維製品ほか)を都へ貢納する税で、「みつき」とも呼ばれた。労役に代えて布などを納める庸とあわせ、正丁を基準に課された。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12046", "field": "古代", "difficulty": 4, "type": "short", "question": "平安中期以降、任国に赴いた国司の最高責任者は国衙において強い実力を発揮し、しだいに徴税請負人的な性格を強めていった。この、現地に赴任した国司の最高責任者を何というか。", "choices": [], "answer": "受領", "modelAnswer": "受領", "explanation": "受領は任国に赴任する国司の最高責任者で、郡司の権限低下と対照的に実権を強め、有力農民(田堵)の経営力に依存しながら徴税を請け負う存在へと変質していった。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12047", "field": "中世", "difficulty": 3, "type": "short", "question": "摂関家に属した公家藤原兼実が著し、源平内乱期の政治情勢を知る上での重要な史料となっている日記を何というか。", "choices": [], "answer": "玉葉", "modelAnswer": "玉葉", "explanation": "『玉葉』は藤原兼実の日記で、源平内乱から鎌倉幕府成立期にかけての公家社会の動向や政治情勢を伝える貴重な史料である。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12048", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代後期、後深草天皇の流れをくむ持明院統と、亀山天皇の流れをくむ大覚寺統との間で、皇位の継承や皇室領荘園の相続をめぐって争われた状態を何というか。", "choices": [], "answer": "両統迭立", "modelAnswer": "両統迭立", "explanation": "両統迭立は持明院統と大覚寺統が交互に皇位につくという状態で、双方の対立は鎌倉幕府の調停を必要とするほど深刻化し、のちの南北朝の動乱の背景ともなった。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12049", "field": "中世", "difficulty": 3, "type": "short", "question": "建武の新政において、後醍醐天皇が所領に関する訴訟を扱うために設置した機関を何というか。", "choices": [], "answer": "雑訴決断所", "modelAnswer": "雑訴決断所", "explanation": "雑訴決断所は建武政権下で所領問題を中心とする訴訟を処理するために設けられた機関で、公家・武家双方の期待に応えようとしたが、実際の運用は混乱を招いた。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12050", "field": "近世", "difficulty": 3, "type": "short", "question": "1657(明暦3)年、水戸藩主徳川光圀の命によって編纂が始められた、南朝を正統とする立場で記された歴史書を何というか。", "choices": [], "answer": "大日本史", "modelAnswer": "大日本史", "explanation": "『大日本史』は徳川光圀の命により編纂が開始され、明治時代まで長期にわたって継続、南朝正統論をとる大義名分論的な史観は水戸学の形成に大きな影響を与えた。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12051", "field": "近世", "difficulty": 4, "type": "short", "question": "新井白石が、摂関政治の成立から江戸幕府の成立に至る経緯を14の段階に区分して論じた歴史書を何というか。", "choices": [], "answer": "読史余論", "modelAnswer": "読史余論", "explanation": "『読史余論』は新井白石が武家政権の成立過程を段階的に分析した歴史書で、幕府政治の正統性を歴史的に位置づけようとした試みとして知られる。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12052", "field": "近世", "difficulty": 3, "type": "short", "question": "19世紀初頭、源平二氏から徳川氏に至るまでの武家の興亡を論じた『日本外史』を著した儒学者は誰か。", "choices": [], "answer": "頼山陽", "modelAnswer": "頼山陽", "explanation": "頼山陽の『日本外史』は漢文体で武家の興亡を描いた著作で、幕末の尊王論者らに広く読まれ、思想的影響を与えた。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12053", "field": "近世", "difficulty": 4, "type": "short", "question": "1650(順治7)年に成立し、琉球王国の初代国王の系譜を源為朝の子であると記して日本との関係を説明した、琉球最初の歴史書を何というか。", "choices": [], "answer": "中山世鑑", "modelAnswer": "中山世鑑", "explanation": "『中山世鑑』は琉球王府によって編纂された最初の正史で、王統の由来を日本の武将源為朝と結びつけて説明する記述が特徴的である。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12054", "field": "近代", "difficulty": 4, "type": "short", "question": "大日本帝国憲法下で確立した「統帥権の独立」の原則のもとで、陸海軍の統帥部が内閣を経ずに天皇に直接軍事上の事項を奏上できるとされた慣行を何というか、漢字4字で答えよ。", "choices": [], "answer": "帷幄上奏", "modelAnswer": "帷幄上奏", "explanation": "統帥権の独立により、陸海軍の作戦・用兵に関する事項は内閣の輔弼の外に置かれ、参謀総長・軍令部総長らが内閣を経由せず天皇に直接上奏する帷幄上奏の慣行が確立し、軍部の政治的発言力を強める要因となった。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12055", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "下関条約の内容には、朝鮮の独立承認、遼東半島・台湾・澎湖諸島の割譲、賠償金2億両の支払い、沙市・重慶・蘇州・杭州の開市・開港が含まれるが、膠州湾の租借は下関条約とは無関係で、後にドイツが清国から獲得したものである。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "下関条約(1895年)は日清戦争の講和条約で、朝鮮の独立、遼東半島・台湾・澎湖諸島の割譲、賠償金2億両、新たな開市・開港場の設定などを定めた。膠州湾の租借は1898年にドイツが清国から獲得したもので、下関条約とは無関係である。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12056", "field": "近代", "difficulty": 3, "type": "short", "question": "1931(昭和6)年、関東軍が南満州鉄道の線路を自ら爆破し、これを中国側の行為であるとして軍事行動を開始するきっかけとした事件を何というか。", "choices": [], "answer": "柳条湖事件", "modelAnswer": "柳条湖事件", "explanation": "柳条湖事件を契機に関東軍は満州の主要地域を占領し、翌1932年には清朝最後の皇帝溥儀を執政(のち皇帝)とする傀儡国家「満州国」を建国、日本は国際的に孤立を深めた。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12057", "field": "近代", "difficulty": 3, "type": "short", "question": "1941(昭和16)年7月、資源確保などを目的に日本軍が進駐し、アメリカによる対日石油輸出全面禁止などの対抗措置を招く結果となった地域はどこか。", "choices": [], "answer": "南部仏印", "modelAnswer": "南部仏印", "explanation": "日本軍の南部仏印進駐は、アメリカの対日資産凍結・石油輸出全面禁止といった強硬な経済制裁を招き、日米関係を決定的に悪化させ、太平洋戦争開戦への道を早めることとなった。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12058", "field": "現代", "difficulty": 3, "type": "short", "question": "1954年、アメリカのビキニ環礁における水爆実験によって日本の漁船が被爆した事件をきっかけに、全国的な署名活動へと広がった日本の反核運動を何というか。", "choices": [], "answer": "原水爆禁止運動", "modelAnswer": "原水爆禁止運動", "explanation": "第五福竜丸事件をきっかけに原水爆禁止を求める署名運動が全国に広がり、翌1955年には原水爆禁止世界大会が開かれるなど、戦後日本を代表する平和運動へと発展した。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12059", "field": "文化史", "difficulty": 3, "type": "short", "question": "7世紀前半の飛鳥文化を代表する仏像で、渡来系の仏師鞍作鳥(止利仏師)の作と伝えられる、法隆寺金堂の本尊は何と呼ばれるか。", "choices": [], "answer": "釈迦三尊像", "modelAnswer": "釈迦三尊像", "explanation": "法隆寺金堂の釈迦三尊像は光背銘に鞍作鳥(止利仏師)の作と伝えられ、正面性を重んじる硬い表情や左右対称の衣文表現など、北魏様式の影響を受けた飛鳥文化彫刻の代表作とされる。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12060", "field": "文化史", "difficulty": 4, "type": "short", "question": "飛鳥文化に続く8世紀初め頃までの文化を白鳳文化というが、この時期の仏像彫刻を代表する遺品として知られ、もと山田寺の本尊であったとされる、現在奈良の興福寺に伝わる仏像の一部を何というか。", "choices": [], "answer": "興福寺仏頭", "modelAnswer": "興福寺仏頭", "explanation": "興福寺の仏頭はもと山田寺講堂本尊であったとされ、若々しく写実的な表情を特色とし、白鳳文化の仏像彫刻を代表する作例として重要視されている。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12061", "field": "文化史", "difficulty": 3, "type": "short", "question": "元禄期、俵屋宗達の装飾的な画法を取り入れて発展させ、後世「光琳派」と呼ばれる一派を起こした画家は誰か。", "choices": [], "answer": "尾形光琳", "modelAnswer": "尾形光琳", "explanation": "尾形光琳は俵屋宗達の作品から様式を学び、大胆な構図と装飾性豊かな作風で「風神雷神図屏風」や「紅白梅図屏風」などの作品を残し、以後の琳派の発展に大きな影響を与えた。(文学部2008年で問われた論点)", "source": "2008", "faculty": "文学部"},
  {"id": "q12080", "field": "文化史", "difficulty": 2, "type": "short", "question": "1993年、日本で初めて世界文化遺産に登録された、聖徳太子ゆかりの寺院を中心とする仏教建造物群は何と呼ばれるか。", "choices": [], "answer": "法隆寺地域の仏教建造物", "modelAnswer": "法隆寺地域の仏教建造物", "explanation": "法隆寺地域の仏教建造物群は姫路城とともに1993年に日本初の世界文化遺産に登録された。現存する世界最古の木造建築群として知られる法隆寺を中心とする。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12081", "field": "現代", "difficulty": 3, "type": "short", "question": "広島に所在し、戦争という悲惨な歴史や人類の愚行を記録する、いわゆる「負の遺産」として世界文化遺産に登録されている建造物は何か。", "choices": [], "answer": "原爆ドーム", "modelAnswer": "原爆ドーム", "explanation": "原爆ドームは1996年に世界文化遺産に登録された、広島への原子爆弾投下の惨禍を伝える建造物で、戦争の悲惨さを記憶する「負の遺産」として国際的に位置づけられている。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12082", "field": "中世", "difficulty": 3, "type": "short", "question": "1429年、それまで分立していた琉球の三王国(北山・中山・南山)を統一し、琉球王国を成立させた中山王は誰か。", "choices": [], "answer": "尚巴志", "modelAnswer": "尚巴志", "explanation": "尚巴志は中山王として山北・山南を征服・統合し、琉球王国を成立させ、以後首里城を拠点とする王府による統一支配が始まった。琉球王国のグスク及び関連遺産群は2000年に世界文化遺産に登録されている。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12083", "field": "古代", "difficulty": 4, "type": "short", "question": "大阪府にまたがる百舌鳥・古市古墳群のうち、日本最大の前方後円墳で「仁徳天皇陵」とも呼ばれる古墳を何というか。", "choices": [], "answer": "大仙陵古墳", "modelAnswer": "大仙陵古墳", "explanation": "大仙陵古墳(仁徳天皇陵古墳)は墳丘の全長が486メートルに及ぶ日本最大の前方後円墳で、古市古墳群の誉田御廟山古墳(応神天皇陵)とともに5世紀の巨大古墳を代表し、百舌鳥・古市古墳群として世界文化遺産に登録されている。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12084", "field": "古代", "difficulty": 3, "type": "short", "question": "8世紀初め、富本銭に続いて元明天皇の時代に鋳造され、平城京造営費用の支払いなどに用いられた貨幣を何というか。", "choices": [], "answer": "和同開珎", "modelAnswer": "和同開珎", "explanation": "和同開珎は708年、武蔵国から銅が献上されたことを機に鋳造された貨幣で、以後皇朝十二銭と呼ばれる貨幣鋳造の始まりとなった。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12085", "field": "古代", "difficulty": 3, "type": "short", "question": "720年に完成し、神代から持統天皇の時代までを編年体で記した、六国史の最初に位置づけられる史書を何というか。", "choices": [], "answer": "日本書紀", "modelAnswer": "日本書紀", "explanation": "『日本書紀』は舎人親王らによって編纂された編年体の史書で、六国史のさきがけとして位置づけられ、簡素な記事に終始する『古事記』とは対照的な大部の史書となっている。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12086", "field": "古代", "difficulty": 3, "type": "short", "question": "8世紀初め、元明天皇の命により諸国に対して編纂が命じられた、地名の由来や産物、伝承などをまとめて報告させた地誌を何というか。", "choices": [], "answer": "風土記", "modelAnswer": "風土記", "explanation": "風土記は諸国の国司に編纂・報告が命じられた地誌で、編纂の実態には国ごとの差異があり、現在ほぼ完全な形で伝わるのは出雲国風土記のみである。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12087", "field": "古代", "difficulty": 4, "type": "short", "question": "入唐して学問を修め、帰国後は橘諸兄のもとで吉備真備とともに重用されたが、その処遇への反発が藤原広嗣の乱を誘発する一因ともなった学僧は誰か。", "choices": [], "answer": "玄昉", "modelAnswer": "玄昉", "explanation": "吉備真備と玄昉は入唐して学問・仏教を修め、帰国後は橘諸兄政権のもとで重用されたが、これに反発した藤原広嗣が両名の排除を掲げて乱を起こした。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12088", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代、商工業の発達や流通の活発化を背景に、交通の要地で月に3回ほど開かれるようになった定期市を何というか。", "choices": [], "answer": "三斎市", "modelAnswer": "三斎市", "explanation": "三斎市は月3回開催される定期市で、『一遍上人絵伝』に描かれた備前国福岡の市はその活況を伝える代表例として知られる。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12089", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代、港湾において年貢などの保管・輸送を請け負い、物資流通の発展に寄与した業者を何というか。", "choices": [], "answer": "問丸", "modelAnswer": "問丸", "explanation": "問丸は港湾での年貢米や商品の保管・輸送を担った業者で、のちの問屋の原型ともされ、水上交通の発達とともに重要な役割を果たした。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12090", "field": "中世", "difficulty": 3, "type": "short", "question": "室町時代、質物を取って高利貸を営み、幕府に営業税を上納する見返りに保護を受けた金融業者で、酒屋とならび徳政一揆の主要な襲撃対象となったものを何というか。", "choices": [], "answer": "土倉", "modelAnswer": "土倉", "explanation": "土倉は質草を取って金銭を貸し付ける金融業者で、酒屋とともに室町幕府に土倉役・酒屋役を上納して保護を受けたが、徳政を求める土一揆・徳政一揆ではしばしば襲撃・破壊の対象となった。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12091", "field": "近世", "difficulty": 3, "type": "short", "question": "戦国大名や織田信長・豊臣秀吉が、城下町などの商業振興のために発布した、座による営業独占を排して自由な商売を認めた法令を何というか。", "choices": [], "answer": "楽市令", "modelAnswer": "楽市令", "explanation": "楽市令は座商人の特権や関銭などを排し、新興商人も自由に営業できるようにする法令で、信長は安土などで発布し、城下町の繁栄を図った。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12092", "field": "近世", "difficulty": 4, "type": "short", "question": "大名家当主が死の間際に急遽養子を立てることを厳しく制限していた規定は、大名家の断絶による牢人増加の一因となっていたが、4代将軍徳川家綱の時代に大幅に緩和された。この規定を何というか。", "choices": [], "answer": "末期養子の禁", "modelAnswer": "末期養子の禁", "explanation": "末期養子の禁は大名家当主が死の間際に急養子を立てることを制限する規定で、これによる大名家の改易が牢人増加の一因となっていた。家綱政権はこの禁を大幅に緩和し、大名家の取り潰しを減らして牢人問題の緩和を図った。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12093", "field": "近世", "difficulty": 3, "type": "short", "question": "1663年、徳川家綱が武家諸法度を公布した際に口頭で申し渡した、主君の死に際して家臣が後を追って死ぬことを禁じる方針を何というか。", "choices": [], "answer": "殉死の禁", "modelAnswer": "殉死の禁", "explanation": "殉死の禁は、主君個人への忠誠よりも主家(役職)への奉公を重んじる方向への転換を示すもので、以後、跡を継いだ新しい主君への奉公が義務づけられるようになった。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12094", "field": "近世", "difficulty": 3, "type": "truefalse", "question": "1665年、江戸幕府は大名の重臣の子弟を人質として幕府に差し出させる証人の制度を廃止し、大名統制の方針を緩和した。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "証人の制度は大名の忠誠を担保するために重臣の子弟を人質として幕府に差し出させたもので、1665年に廃止され、幕府による大名統制はより緩やかな方向へ転換していった。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12095", "field": "近代", "difficulty": 4, "type": "short", "question": "地租改正に対する農民の反発が激化し、政府が地価に対する税率を当初の3%から引き下げることを余儀なくされた際、その新税率を揶揄して「竹槍でドンと突き出す◯◯◯◯」と言われた、この空欄に入る4字の言葉は何か。", "choices": [], "answer": "二分五厘", "modelAnswer": "二分五厘", "explanation": "地租改正反対一揆の高まりを受け、政府は1877年に地租率を地価の3%から2.5%(二分五厘)に引き下げた。この経緯は「竹槍でドンと突き出す二分五厘」という言葉で当時の民衆の間に語られた。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12096", "field": "近代", "difficulty": 3, "type": "short", "question": "明治10年代、たびたび流行して政府に「伝染病予防規則」の制定を促した急性感染症は何か。", "choices": [], "answer": "コレラ", "modelAnswer": "コレラ", "explanation": "コレラは明治期に何度も流行し、多数の死者を出したことから、政府は1880年に伝染病予防規則を制定したが、患者の隔離や消毒などの取締りをめぐって民衆の反発を招き、各地でコレラ騒動と呼ばれる反対一揆も発生した。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12097", "field": "近代", "difficulty": 3, "type": "short", "question": "北洋の蟹工船で働く労働者の過酷な状況をリアルに描いた小説『蟹工船』を著したプロレタリア文学の作家は誰か。", "choices": [], "answer": "小林多喜二", "modelAnswer": "小林多喜二", "explanation": "小林多喜二は『蟹工船』などの作品を通じて労働者の搾取や連帯を描き、プロレタリア文学を代表する作家となったが、当局の弾圧を受け、1933年に検挙後の拷問により獄死した。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12098", "field": "現代", "difficulty": 3, "type": "short", "question": "大気汚染や水質汚濁など高度経済成長期の公害問題への対応として、1967(昭和42)年に制定された法律を何というか。", "choices": [], "answer": "公害対策基本法", "modelAnswer": "公害対策基本法", "explanation": "公害対策基本法は産業公害の防止と生活環境の保全を目的として制定され、1993年の環境基本法制定にともない発展的に解消された。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12099", "field": "文化史", "difficulty": 3, "type": "short", "question": "唐から渡来して日本に戒律を伝えた僧の、脱活乾漆造による肖像彫刻で、日本最古の肖像彫刻の一つとされ、唐招提寺に伝来するものは何か。", "choices": [], "answer": "鑑真和上像", "modelAnswer": "鑑真和上像", "explanation": "鑑真和上像は唐招提寺に伝わる脱活乾漆造の肖像彫刻で、鑑真の弟子である唐僧の関与によって造立されたと考えられ、日本最古の肖像彫刻の一つとして知られる。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12100", "field": "文化史", "difficulty": 3, "type": "choice", "question": "室町時代、宋・元から伝えられ禅僧の間で好まれた水墨画を、日本的な様式として大成させ、「四季山水図巻(山水長巻)」などの傑作を残した画僧は誰か。", "choices": ["雪舟", "狩野永徳", "長谷川等伯", "土佐光信", "仙厓義梵"], "answer": 0, "modelAnswer": "", "explanation": "雪舟は明に渡って本格的に水墨画を学び、帰国後は「四季山水図巻(山水長巻)」などの傑作を描いて日本の水墨山水画を大成させた。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12101", "field": "文化史", "difficulty": 4, "type": "short", "question": "明清の南宗画の影響のもとで生まれた日本の絵画を南画というが、その大成者とされる池大雅と与謝蕪村が分担して描いた合作の画帖を何というか。", "choices": [], "answer": "十便十宜図", "modelAnswer": "十便十宜図", "explanation": "「十便十宜図」は池大雅と与謝蕪村が分担して描いた南画の画帖で、日本南画の到達点を示す作品として知られる。(文学部2009年で問われた論点)", "source": "2009", "faculty": "文学部"},
  {"id": "q12120", "field": "古代", "difficulty": 4, "type": "essay", "question": "旧石器時代から縄文時代を経て弥生時代に至る過程で、日本列島に住む人々の生業・住居のあり方や社会のしくみはどのように変化していったか。150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "旧石器時代の人々は採集・狩猟を中心に移動しながら生活していたが、縄文時代になると土器の使用や弓矢の発明とともに、堅穴住居を営む定住的な環状集落が各地に形成され、一部では植物の栽培も行われた。弥生時代に入ると大陸から水稲耕作と金属器が伝えられ、生産の余剰をめぐる争いから環濠集落や高地性集落が営まれ、身分の差が生じて各地に小さな政治勢力(くにぐに)が分立するようになった。", "explanation": "旧石器→縄文→弥生の推移は生業(採集狩猟→漁労採集狩猟に加え一部栽培→水稲農耕)、住居・集落(移動生活→定住的環状集落→環濠集落・高地性集落)、社会(平等的→身分差の芽生えと小国分立)の三点で整理すると答えやすい。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12121", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文時代に多く作られ女性をかたどったものが多いとされる土製品と、古墳時代に墳丘上や周囲に立て並べられた土製品を、それぞれ漢字で答えなさい。", "choices": [], "answer": "土偶、埴輪", "modelAnswer": "土偶、埴輪", "explanation": "土偶は生殖(多産)や収穫(豊穣)を祈る呪術的な儀礼に用いられたと考えられ、女性像が多い。埴輪は円筒埴輪と形象埴輪(人物・動物・家形・器財など)に大別され、古墳における被葬者の葬送儀礼に関わる遺物とされる。両者は時代も用途も異なる別個の土製品である点に注意したい。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12122", "field": "古代", "difficulty": 3, "type": "essay", "question": "3世紀半ば以降、近畿地方を中心に出現し、後に列島各地へ広まった円形部と方形部を組み合わせた墳丘をもつ古墳の形式名を答えなさい。またこの形式の古墳が広範囲に分布することは、当時の政治情勢について何を示すと考えられているか、簡潔に述べなさい。", "choices": [], "answer": "", "modelAnswer": "前方後円墳。この形式の古墳が近畿から東北地方南部・九州地方まで広く分布することは、ヤマト政権を中心とする首長連合(政治的まとまり)が列島各地の在地首長を服属・編成し、共通の葬送儀礼を通じてその支配・同盟関係を列島規模で及ぼしていたことを示すと考えられている。", "explanation": "前方後円墳の分布範囲=ヤマト政権の勢力・同盟関係の及ぶ範囲とみなす視点が重要。古墳の形式そのものが政治的な結びつきを表す点をおさえる。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12123", "field": "古代", "difficulty": 3, "type": "short", "question": "7世紀半ばに出されたとされる、簡素な墓を推奨する法令は何と呼ばれるか。また、この時期以降に築造された終末期古墳のうち、四神などの壁画で知られる明日香村の代表的な二つの古墳の名を答えなさい。", "choices": [], "answer": "大化の薄葬令(薄葬令)。高松塚古墳とキトラ古墳。", "modelAnswer": "大化の薄葬令(薄葬令)。高松塚古墳とキトラ古墳。", "explanation": "646年(大化2年)に出されたとされる薄葬令により身分に応じた墳墓の規模が制限され、大型古墳の造営は終息に向かった。あわせて仏教の普及にともない火葬も広まり、古墳は衰退していく。7世紀末から8世紀にかけての終末期古墳である高松塚古墳・キトラ古墳は、精緻な四神図や星宿図などの壁画を持つことで知られる。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12124", "field": "古代", "difficulty": 3, "type": "choice", "question": "古墳時代の副葬品の変化について述べた文として、最も適切なものを1つ選びなさい。", "choices": ["前期古墳では武器・馬具・金銀製品が中心で、中期以降は鏡や玉類など呪術的色彩の強い副葬品が増える。", "前期古墳では鏡や玉類など呪術的・宗教的色彩の強い副葬品が中心であったが、中期以降は武器・武具・馬具など軍事的性格を示す副葬品が増加する。", "前期・中期・後期を通じて副葬品の内容にはほとんど変化が見られなかった。", "後期古墳ではすべて円墳が姿を消し、前方後円墳のみが築造されるようになった。"], "answer": 1, "modelAnswer": "", "explanation": "古墳時代前期の副葬品は鏡・玉類・腕輪形石製品など呪術的・宗教的色彩が濃いが、中期になると武器・武具・馬具・金銀製品などが増加し、被葬者の軍事的・政治的性格を強く反映するようになる。後期には各地に小型の群集墳が営まれ、横穴式石室を持つものが多くなる。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12125", "field": "社会経済", "difficulty": 3, "type": "short", "question": "律令制における調・庸は、都まで運ばれる際にどのような木製の札を荷につけて発送されたか。この札の名称を漢字で答え、これが多数出土する代表的な都城の名を1つ挙げなさい。", "choices": [], "answer": "木簡。平城京(平城京跡)。", "modelAnswer": "木簡。平城京(平城京跡)。", "explanation": "調・庸として集められた布や諸国の特産物には、貢進者の国郡郷名・品目・数量などを記した木簡が荷札として付けられ、都まで運ばれた。平城京跡をはじめとする都城跡からは大量の木簡が出土しており、律令制下の税制や地方支配の実態を知る一級の文字資料となっている。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12126", "field": "社会経済", "difficulty": 3, "type": "truefalse", "question": "律令制下の出挙について、「出挙は稲を貸し付ける制度で、公出挙は国司が財源確保のために農民へ稲を貸し付け、秋の収穫後に利息とともに徴収する強制的な性格の強いものであった」という記述は正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "出挙は春から夏にかけて稲を貸し付け、秋の収穫後に利息を付けて回収する制度で、公出挙は国司(諸国)が行い諸国の重要な財源となった一方、農民にとっては事実上強制的な貸付として重い負担となった。私出挙は貴族・寺院などが行うもので、利率の高さなどからたびたび禁令の対象となった。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12127", "field": "古代", "difficulty": 3, "type": "choice", "question": "律令制の兵役制度について述べた文として、誤っているものを1つ選びなさい。", "choices": ["成人男性のおよそ3〜4人に1人程度の割合で兵士が徴発され、諸国に置かれた軍団で訓練を受けた。", "軍団で訓練を受けた兵士の一部は都に上って宮門の警備などにあたる衛士となった。", "兵士の一部は九州沿岸の防備にあたる防人として派遣され、その多くは東国出身者であった。", "防人は主として西国の兵士から選ばれ、任期は1年であった。", "兵役は農民にとって、労働力の損失や往復の負担も大きく、重い負担であった。"], "answer": 3, "modelAnswer": "", "explanation": "防人は主に東国(坂東)の兵士から徴発されて大宰府に配属され九州沿岸の防備にあたった点が特徴で、その任期は3年であった。西国の兵士から選ばれたとする点、任期を1年とする点はいずれも誤り。軍団での訓練・衛士・防人のいずれも農民にとって大きな負担であった。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12128", "field": "中世", "difficulty": 4, "type": "essay", "question": "『保元物語』『平治物語』『平家物語』『源平盛衰記』は、成立した時期や内容の点でどのように異なるか。150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "『保元物語』『平治物語』は鎌倉時代初期に成立したとされる軍記物語で、保元の乱・平治の乱という個別の争乱を主題とする。これに対し『平家物語』は鎌倉時代前半を中心に長期間かけて成立し、源氏と平氏の争いという一貫した視点のもとに盛者必衰の理を説く、文学的完成度の高い作品である。『源平盛衰記』は『平家物語』と内容がほぼ重なる異本の一つで、『平家物語』本文には見えない文書史料や説話を多く取り込んでいる点に特色がある。", "explanation": "軍記物語の系譜は、保元・平治物語(個別事件を扱う先駆的作品)から平家物語(統一的視点・完成度の高い作品)、さらに源平盛衰記などの異本(内容増補)へという展開で整理すると理解しやすい。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12129", "field": "中世", "difficulty": 4, "type": "choice", "question": "治承・寿永の内乱(1180〜85年)の経過について、起こった順に正しく配列したものを1つ選びなさい。①養和の大飢饉が起こった ②木曽義仲が倶利伽羅峠の戦いで勝利した ③平重衡が興福寺・東大寺を焼き討ちした ④平氏が福原京に都を移した ⑤源頼朝が後白河法皇と交渉して東海・東山両道の東国支配権を得た", "choices": ["④→③→①→②→⑤", "③→④→①→②→⑤", "④→①→③→②→⑤", "①→④→③→⑤→②"], "answer": 0, "modelAnswer": "", "explanation": "1180年6月に平氏が福原京へ遷都(④)、同年12月に平重衡が南都(興福寺・東大寺)を焼き討ち(③)、1181年に養和の大飢饉が発生(①)、1183年5月に木曽義仲が倶利伽羅峠の戦いで平氏に勝利(②)、同年10月に頼朝が東海・東山両道の実質的支配権を後白河法皇から承認される(⑤)という順序になる。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12130", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "南北朝期に足利尊氏派と足利直義派が対立して起こった観応の擾乱は、鎌倉幕府の残党を巻き込んで発生した全国的な動乱であり、この争乱によって室町幕府の支配は14世紀半ばには全国的に安定した、という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "観応の擾乱は足利尊氏・高師直ら急進派と足利直義ら旧来の法秩序を重んじる勢力との対立、すなわち室町幕府内部の二頭政治の矛盾が表面化した争乱であり、鎌倉幕府の残党による中先代の乱とは別の事件である。またこの争乱により南朝が一時勢力を回復するなど政局は混乱し、室町幕府の支配がこの時期に安定したとは言えない。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12131", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉幕府に対して籠城戦を続けて粘り強く抵抗し、幕府滅亡のきっかけをつくった武将は誰か。またこの人物の戦法は、近世にどのような分野で活用されたか答えなさい。", "choices": [], "answer": "楠木正成。近世には軍学(兵学)の教材・手本として広められた。", "modelAnswer": "楠木正成。近世には軍学(兵学)の教材・手本として広められた。", "explanation": "楠木正成は河内の悪党出身とされる武将で、赤坂城・千早城での籠城戦により鎌倉幕府の大軍を長期間ひきつけ、幕府滅亡の一因をつくった。後世、その巧みなゲリラ的戦術は軍学・兵学の題材として重視され、江戸時代の武士教育にも取り入れられた。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12132", "field": "中世", "difficulty": 3, "type": "short", "question": "文永・弘安の役における自らの戦功を訴えるため、蒙古襲来の様子を描かせた絵巻を作らせた肥後の御家人は誰か。また、この人物が恩賞を求めて訴えた、当時幕府の実力者であった御家人は誰か、それぞれ答えなさい。", "choices": [], "answer": "竹崎季長。安達泰盛。", "modelAnswer": "竹崎季長。安達泰盛。", "explanation": "『蒙古襲来絵詞』は竹崎季長が自身の戦功を後世に伝えるために制作させた絵巻で、季長は文永の役での恩賞に不満を持ち、鎌倉に赴いて有力御家人安達泰盛に直訴し、恩賞を得たとされる。この絵巻は元寇の実態を伝える貴重な絵画資料である。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12133", "field": "外交史", "difficulty": 3, "type": "short", "question": "豊臣秀吉による朝鮮出兵ののち、江戸幕府は朝鮮との講和には成功したが、明との関係修復には失敗した。日明間の勘合貿易の名で知られるこの貿易形態を漢字で答えなさい。またこの貿易が江戸時代に復活しなかった背景を簡潔に述べなさい。", "choices": [], "answer": "日明貿易(勘合貿易)。明が秀吉の朝鮮侵略への反発や、その後の明・清交替の混乱により日本との国交回復に応じなかったため。", "modelAnswer": "日明貿易(勘合貿易)。明が秀吉の朝鮮侵略への反発や、その後の明・清交替の混乱により日本との国交回復に応じなかったため。", "explanation": "室町時代に行われた日明間の勘合貿易は、秀吉の朝鮮侵略により断絶した。江戸幕府は朝鮮とは講和を実現させたが、明との国交回復は果たせず、日明貿易は復活しなかった。ただし長崎に来航する中国船を通じて中国産物は間接的に入手できた。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12134", "field": "外交史", "difficulty": 4, "type": "essay", "question": "1609年前後に対馬藩・薩摩藩がそれぞれ朝鮮・琉球との間で結んだ関係について、条約(取決め)の名称や内容を含めて150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "対馬藩は1609年に朝鮮との間で己酉約条を結び、宗氏に歳遣船の派遣が認められ、釜山の倭館を通じて朝鮮との外交・貿易を担った。一方、同じ1609年に薩摩藩は琉球に侵攻してこれを服属させ、1611年には掟を定めて年貢の徴収などを行いつつ、琉球王国の存続と中国への朝貢貿易を維持させ、日中間の間接的な貿易利益を得た。", "explanation": "対馬藩=朝鮮(己酉約条・歳遣船・倭館)、薩摩藩=琉球(侵攻・掟・王国存続と中国への朝貢貿易の継続)という対比で押さえる。琉球が日中両属的な立場に置かれた点も重要。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12135", "field": "外交史", "difficulty": 3, "type": "truefalse", "question": "江戸幕府の対外政策は、キリスト教禁教と貿易統制を目的として来航地・相手国を限定するもので、近年の研究では「鎖国」ではなく「海禁」という概念で理解されることがある、という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "いわゆる「鎖国」は、幕府がキリスト教の禁教を徹底しつつ、長崎を中心に貿易相手・来航地を限定・管理する政策であり、中国(明清)や朝鮮などにも見られた海禁政策の一種として理解する見方が近年広まっている。「鎖国」という語自体は江戸時代後期に生まれた概念である点にも注意したい。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12136", "field": "外交史", "difficulty": 4, "type": "choice", "question": "江戸時代の長崎貿易・生糸貿易の変遷について述べた文として、誤っているものを1つ選びなさい。", "choices": ["幕府は当初、生糸の輸入価格をめぐる混乱を抑えるため、特定の商人集団に一括購入させる糸割符制度を設けた。", "糸割符制度は当初ポルトガル商人を対象に導入され、のちに対象が拡大された。", "1688年に幕府は定高貿易仕法を定め、長崎における貿易額に上限を設けた。", "1715年に幕府は正徳新例(海舶互市新例)を定め、中国船の来航数や貿易額を制限した。", "糸割符制度の導入以降、生糸貿易における日本商人の主導権は完全に失われ、幕末までポルトガル商人が貿易を独占した。"], "answer": 4, "modelAnswer": "", "explanation": "糸割符制度は1604年にポルトガル商人を対象に始まり、のちに中国船やオランダにも適用が拡大された。1688年の定高貿易仕法、1715年の正徳新例(海舶互市新例)は、いずれも金銀の海外流出を抑えるため貿易額を制限する政策である。糸割符制度により日本側(特定商人)が生糸価格の決定権を握るようになったのであり、ポルトガル商人が貿易を独占し続けたわけではない。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12137", "field": "外交史", "difficulty": 3, "type": "short", "question": "江戸幕府の命を受けて蝦夷地からさらに北方を探検し、樺太が島であることを確認するとともに、大陸を流れる大河の下流域の住人を通じて中国産の絹織物(蝦夷錦)がもたらされるルートを確認した人物は誰か。またその大河の名を漢字で答えなさい。", "choices": [], "answer": "間宮林蔵。黒竜江(アムール川)。", "modelAnswer": "間宮林蔵。黒竜江(アムール川)。", "explanation": "間宮林蔵は幕命により樺太・北方を探検し、樺太が島であることを確認(間宮海峡)するとともに、黒竜江(アムール)下流域の住人を介して、中国製の絹織物である蝦夷錦などが山丹交易を通じて蝦夷地にもたらされ、松前藩がアイヌ交易(商場知行制)を通じてこれを入手していた交易ルートの一端を明らかにした。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12138", "field": "近代", "difficulty": 5, "type": "essay", "question": "1874年の民撰議院設立建白書の提出から、自由民権運動の高まりを経て、政府が国会開設の勅諭を出すに至るまでの経緯を、私擬憲法の作成や政府内部の対立にも触れながら200字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "1874年、板垣退助らは民撰議院設立の建白書を政府に提出し、新聞報道を通じて世論の反響を呼んだ。これを契機に自由民権運動が全国に広まり、憲法制定・国会開設を求める声が高まる中、植木枝盛の東洋大日本国国憲按や千葉卓三郎らの五日市憲法草案など民間による私擬憲法の起草も進んだ。政府内部では急進的な国会即時開設論を唱えた大隈重信が、開拓使官有物払下げ事件を機に罷免される政変(明治十四年の政変)が起こり、これと同時に政府は10年後の国会開設を約束する国会開設の勅諭を出し、立憲制導入の基本方針を確定した。", "explanation": "建白書提出→自由民権運動の拡大→私擬憲法の起草→明治十四年の政変(大隈重信罷免)→国会開設の勅諭、という一連の流れを因果関係とともに整理することが重要。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12139", "field": "近代", "difficulty": 4, "type": "choice", "question": "大正政変から護憲三派内閣成立に至る時期の出来事について、誤っているものを1つ選びなさい。", "choices": ["1912年、2個師団増設問題をめぐり陸軍と立憲政友会が対立し、西園寺内閣は総辞職に追い込まれた。", "桂太郎内閣の成立に対し、「閥族打破・憲政擁護」をスローガンとする第一次護憲運動が起こった。", "1918年には原敬を首班とする、日本で最初の本格的な政党内閣が成立した。", "1924年の第二次護憲運動の結果成立した護憲三派内閣は、憲政会・立憲政友会・革新倶楽部の3党によって組織された。", "護憲三派内閣以後は、政党の力が完全に否定され、藩閥・軍部出身者のみが首相に就任する体制が続いた。"], "answer": 4, "modelAnswer": "", "explanation": "護憲三派内閣成立(1924年)以後、五・一五事件で犬養毅内閣が倒れるまで、衆議院で多数を占める政党が政権を担当する「憲政の常道」と呼ばれる慣行が続いた。したがって藩閥・軍部出身者のみが首相となったとする記述は誤り。他の選択肢はいずれも大正政変から護憲三派内閣に至る経緯として正しい。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12140", "field": "文化史", "difficulty": 3, "type": "short", "question": "1774年に刊行された『解体新書』の翻訳事業に取り組んだ中心人物で、その刊行後も蘭学の普及に尽力し、後年その回想録を著したことでも知られる人物は誰か。また、その挿絵を担当した秋田藩出身の藩士画家は誰か、それぞれ漢字で答えなさい。", "choices": [], "answer": "杉田玄白。小田野直武。", "modelAnswer": "杉田玄白。小田野直武。", "explanation": "杉田玄白は前野良沢らとともにオランダ語の解剖書を翻訳し『解体新書』として刊行した中心人物で、晩年に蘭学の歩みを回想した『蘭学事始』を著した。挿絵は秋田藩士で平賀源内の指導を受けた小田野直武が担当し、西洋画法を取り入れた精緻な図版で知られる。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12141", "field": "文化史", "difficulty": 3, "type": "short", "question": "江戸の蘭学者大槻玄沢が営んだ私塾で、西暦の元日を祝う会(通称オランダ正月)が開かれたことで知られる塾の名を答えなさい。また、大坂で緒方洪庵が開いた蘭学塾で、明治期に活躍する多くの人材を輩出したことで知られる塾の名も答えなさい。", "choices": [], "answer": "芝蘭堂。適塾(適々斎塾)。", "modelAnswer": "芝蘭堂。適塾(適々斎塾)。", "explanation": "大槻玄沢が江戸に開いた蘭学塾「芝蘭堂」では、1795年以降、西洋暦の元日を祝う「オランダ正月」の会が催され、蘭学者たちの交流の場となった。大坂の緒方洪庵が開いた「適塾」からは、福沢諭吉をはじめ明治期に諸方面で活躍する多くの人材が育った。（文学部2010年で問われた論点）", "source": "2010", "faculty": "文学部"},
  {"id": "q12160", "field": "古代", "difficulty": 3, "type": "essay", "question": "日本列島における水稲耕作は、まず北部九州に定着したのち、どのようなルートを経て東日本にまで拡大していったか、経由した地域名を挙げながら100字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "水稲耕作は縄文時代晩期後半頃に北部九州へ最初に定着し、そこから瀬戸内地方を経て近畿地方まで広がり、さらに東海地方を経て東日本へと伝播していった。この間、沖積平野を中心に多くの水田が形成され、狩猟・採集・漁労中心の生活から農耕を基盤とする生活へと構造的な変革がもたらされた。", "explanation": "水稲耕作の伝播経路(北部九州→瀬戸内→近畿→東海→東日本)は弥生文化拡大の基本ルートとして重要。地域ごとの伝播の時間差にも注意したい。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12161", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代に築造された高地性集落について述べた文として、最も適切なものを1つ選びなさい。", "choices": ["標高1000メートル以上の山岳地帯にのみ営まれた、一般的な居住のための集落である。", "周囲を溝で囲んだ低地の集落で、稲作に不便な立地に営まれた。", "眺望のよい高所に営まれ、戦闘など非常時への備えとしての性格をもつ集落と考えられている。", "近畿地方の大阪平野周辺にのみ限定して分布し、他地域には見られない。"], "answer": 2, "modelAnswer": "", "explanation": "高地性集落は見晴らしのよい丘陵や山地に営まれ、防御的な性格をもつ集落と考えられている。標高の下限は必ずしも1000メートルに限られず、瀬戸内海沿岸を中心に近畿・四国など広い範囲に分布しており、地域間の緊張・戦闘の高まりを示す遺構として重視される。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12162", "field": "古代", "difficulty": 3, "type": "short", "question": "3世紀の倭国の様子を伝える中国の史書に記された、邪馬台国の女王の名を答えなさい。またこの人物についての記載として、政治にはあまり関与せず何を行っていたとされるか、簡潔に述べなさい。", "choices": [], "answer": "卑弥呼。自ら政務(労働)に従事することはなく、鬼道と呼ばれる呪術を行い、まつりごと(祭祀)に専念していたとされる。", "modelAnswer": "卑弥呼。自ら政務(労働)に従事することはなく、鬼道と呼ばれる呪術を行い、まつりごと(祭祀)に専念していたとされる。", "explanation": "『魏志』倭人伝によれば、卑弥呼は倭国内の争乱を経て諸国の共立により女王に立てられ、鬼道(呪術的な能力)をもって人心を掌握し、政務の実務は弟が補佐したと伝えられる。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12163", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "弥生時代のクニ(首長国)における政治権力について、「首長を補佐する役割は多くの場合、血縁関係にある親族から登用され、外部の人材が用いられることはほとんどなかった」という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "実際には、クニの政治権力においては首長の補佐役として、血縁関係の有無にかかわらず、外部から有能な人材が登用されることが多く、必ずしも親族組織の支援のみに依拠していたわけではないと考えられている。首長権力にはある種の霊性・神聖さも伴い、経済的な富とともに威信財の保有が社会的地位を左右した。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12164", "field": "外交史", "difficulty": 3, "type": "short", "question": "江戸時代に筑前国志賀島で発見された金印には、どの中国王朝の皇帝からいつ倭国王に下賜されたと考えられているか。またその下賜の記載がある中国の史書名を答えなさい。", "choices": [], "answer": "後漢の光武帝から建武中元2年(57年)に下賜されたと考えられている。『後漢書』東夷伝。", "modelAnswer": "後漢の光武帝から建武中元2年(57年)に下賜されたと考えられている。『後漢書』東夷伝。", "explanation": "志賀島出土の金印は「漢委奴国王」と刻まれ、『後漢書』東夷伝の記載にもとづき、後漢の光武帝が建武中元年間に倭の奴国王に下賜したものと考えられている。この金印は古代中国の冊封体制下に倭が組み込まれていたことを端的に示す資料である。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12165", "field": "古代", "difficulty": 3, "type": "short", "question": "橘氏の祖とされる、県犬養氏出身で橘宿禰の姓を賜った女性は誰か。またその子で、聖武朝以降政界の中心人物となった人物は誰か、それぞれ答えなさい。", "choices": [], "answer": "県犬養三千代(橘三千代)。橘諸兄。", "modelAnswer": "県犬養三千代(橘三千代)。橘諸兄。", "explanation": "県犬養三千代は橘宿禰の姓を賜り、橘氏の祖となった。その子である橘諸兄は、藤原氏の勢力が一時後退した聖武朝以降に政界の中心人物として活躍し、橘氏の勢力を伸張させた。ただし三千代と光明子(諸兄の異父妹)は父を異にする関係にあった。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12166", "field": "古代", "difficulty": 3, "type": "short", "question": "嵯峨上皇の死の直後に起こり、伴健岑と橘逸勢がしりぞけられる結果となった政変を何と呼ぶか。またこの政変で急速に勢力を強めた氏族は何氏か答えなさい。", "choices": [], "answer": "承和の変。藤原氏(藤原北家)。", "modelAnswer": "承和の変。藤原氏(藤原北家)。", "explanation": "842年、嵯峨上皇の死の直後に起こった承和の変では、伴健岑・橘逸勢らが謀反の疑いで排斥され、これにより藤原良房を中心とする藤原北家が勢力を拡大・強化する契機となった。橘氏はこの政変を経て地位を低下させ、10世紀末以降は公卿を出す家柄ではなくなっていく。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12167", "field": "文化史", "difficulty": 4, "type": "essay", "question": "法隆寺に伝来した白鳳期を代表する金銅仏があり、ある人物の念持仏であったとも伝えられている。この時期(白鳳文化)の仏像彫刻に見られる特色を、それ以前の飛鳥文化の仏像と比較して150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "飛鳥文化の仏像(飛鳥寺釈迦如来像など)が正面性の強い硬い表情や左右対称の衣文表現を特色とするのに対し、白鳳文化の仏像は童子のような若々しくおおらかな表情、豊かで柔らかみのある肉体表現、動きのある衣文表現など、より写実的で生き生きとした造形へと発展している点に特色がある。", "explanation": "飛鳥文化(北魏様式・硬い表情)から白鳳文化(唐初期様式・若々しく柔らかな表現)への様式変化を対比させて理解する。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12168", "field": "文化史", "difficulty": 3, "type": "short", "question": "東大寺再建に尽力し、播磨国大部荘に阿弥陀堂を建立するなど篤い阿弥陀信仰でも知られる、鎌倉時代前期の勧進僧は誰か。またこの人物が登用した仏師で、東大寺南大門の金剛力士像制作を分担して担った二人の名を答えなさい。", "choices": [], "answer": "重源。運慶と快慶。", "modelAnswer": "重源。運慶と快慶。", "explanation": "重源は東大寺の勧進職として大仏殿など伽藍の復興に尽力した僧で、南無阿弥陀仏と称するほど篤く阿弥陀信仰に帰依していた。彼が登用した仏師のうち、運慶と快慶は東大寺南大門の金剛力士像を分担して制作したことで知られ、快慶はまた優美な阿弥陀如来像などでも高く評価されている。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12169", "field": "文化史", "difficulty": 3, "type": "short", "question": "当初延暦寺で修行していたが、次第に阿弥陀仏への専修念仏に深く帰依し、九条兼実など貴族や熊谷直実など武士にも教えを広めて一つの宗派の開創を目指した人物は誰か。またこの人物の教えを継承し、悪人正機説を唱えた弟子は誰か答えなさい。", "choices": [], "answer": "法然。親鸞。", "modelAnswer": "法然。親鸞。", "explanation": "法然はひたすら阿弥陀仏の名号を称える専修念仏の教えを説き、浄土宗の開創を目指した。旧仏教側からの弾圧を受けつつも、貴族から武士・庶民まで幅広い帰依者を得た。弟子の親鸞はその教えをさらに深め、悪人こそが阿弥陀仏の救いの対象であるとする悪人正機説を立て、浄土真宗の教団の基礎を築いた。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12170", "field": "文化史", "difficulty": 3, "type": "truefalse", "question": "法然の教えとその布教をめぐっては、旧仏教側からの批判や弾圧があり、法然自身も流罪に処されるなど、その普及は決して容易なものではなかった、という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "法然の専修念仏の教えに対しては、法相宗の僧貞慶が興福寺奏状を起草して厳しく批判するなど旧仏教側からの反発が強く、法然自身も弾圧を受けて讃岐に配流され、のちに赦されて京都近郊に戻るなど、布教の道は平坦ではなかった。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12171", "field": "文化史", "difficulty": 3, "type": "short", "question": "南宋から日本に臨済宗を伝え、鎌倉幕府の帰依を受けて上層武士の間に禅宗を広める契機をつくった僧は誰か。またこの人物の伝来以降、幕府や有力守護・地頭の帰依を受けて禅宗寺院が相次いで建立された都市はどこか答えなさい。", "choices": [], "answer": "栄西。鎌倉。", "modelAnswer": "栄西。鎌倉。", "explanation": "栄西は南宋に渡って臨済禅を学び帰国後にこれを伝えた。その教えは上層武士の間に広く受け入れられ、高名な禅僧を招いて鎌倉に規模の大きな禅宗寺院が次々と建立された。禅宗はやがて貴族層にも広がり、幕府との連携を保った九条道家が東福寺を建立するなど、京都でも大寺院の建立が進んだ。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12172", "field": "文化史", "difficulty": 3, "type": "short", "question": "後醍醐天皇や北条高時の帰依を受け、鎌倉時代後期を代表する臨済僧として知られ、のちに足利尊氏の求めに応じて後醍醐天皇の菩提を弔う寺院の開山となった人物は誰か。またその寺院の名も答えなさい。", "choices": [], "answer": "夢窓疎石。天龍寺。", "modelAnswer": "夢窓疎石。天龍寺。", "explanation": "夢窓疎石は後醍醐天皇・北条高時ら両陣営から帰依を受けた鎌倉末〜南北朝期の代表的臨済僧で、足利尊氏の求めに応じ、後醍醐天皇の菩提を弔う寺院として建立された天龍寺の開山となった。夢窓疎石は五山文学や作庭にも大きな足跡を残している。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12173", "field": "文化史", "difficulty": 3, "type": "short", "question": "室町幕府は禅宗寺院を統制するため、寺格を定めて有力寺院を官寺として位置づける制度を設けた。この制度を何と呼ぶか。また、この制度に組み込まれず自由な活動を行った、曹洞宗の永平寺・総持寺や臨済宗の大徳寺・妙心寺などの寺院を一般に何と呼ぶか、それぞれ答えなさい。", "choices": [], "answer": "五山・十刹の制。林下。", "modelAnswer": "五山・十刹の制。林下。", "explanation": "足利義満は五山・十刹の制を整備し、有力な禅宗寺院を幕府の官寺として位置づけ公家政権の吸収を意図した。これに対し、この制度の枠組みに組み込まれず自由な活動を続けた曹洞宗の永平寺・総持寺や臨済宗の大徳寺・妙心寺などの寺院は「林下」と呼ばれ、応仁の乱後もそれぞれ独自の発展を遂げた。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12174", "field": "近世", "difficulty": 3, "type": "short", "question": "1837年に大坂町奉行所の元与力であった人物が、天保の飢饉による窮状を見かねて武装蜂起した事件がある。この人物の名と、この乱に影響を受けて越後で一揆を起こした国学者の名を、それぞれ答えなさい。", "choices": [], "answer": "大塩平八郎。生田万。", "modelAnswer": "大塩平八郎。生田万。", "explanation": "大塩平八郎は陽明学を教える私塾洗心洞を主宰した元大坂町奉行所与力で、天保の飢饉による窮状を見かね、1837年に武装蜂起した(大塩平八郎の乱)。この乱に刺激を受け、同年、国学者の生田万が越後柏崎で一揆を起こしている。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12175", "field": "外交史", "difficulty": 3, "type": "short", "question": "1825年に幕府が出した、日本近海に出没する外国船の撃退を命じた法令を何と呼ぶか。また、この法令が適用されて攻撃を受けた、日本人漂流民の送還と貿易開始を求めて来航したアメリカ商船の名を答えなさい。", "choices": [], "answer": "異国船打払令(無二念打払令)。モリソン号。", "modelAnswer": "異国船打払令(無二念打払令)。モリソン号。", "explanation": "1825年(文政8年)、幕府はそれまでの薪水・食糧を与えて帰帆させる方針を転換し、外国船の撃退を命じる異国船打払令を出した。1837年、日本人漂流民の送還と通商を求めて来航したアメリカ商船モリソン号は、相模浦賀と薩摩山川でこの法令が適用されて攻撃を受けた(モリソン号事件)。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12176", "field": "外交史", "difficulty": 3, "type": "truefalse", "question": "モリソン号事件を批判した『戊戌夢物語』の著者である蘭学者は、1839年の弾圧事件で渡辺崋山とともに幕府によって処罰された、という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "モリソン号事件の翌年、高野長英は『戊戌夢物語』を著して幕政を批判した。幕府は1839年、蛮社の獄と呼ばれる弾圧事件において、高野長英や、『慎機論』で幕府の対外政策を批判した渡辺崋山をはじめとする蘭学者グループを処罰・逮捕した。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12177", "field": "近世", "difficulty": 4, "type": "essay", "question": "老中水野忠邦が天保の改革で行った、株仲間解散令・人返しの法・上知令のねらいと結果について、150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "水野忠邦は物価高騰を抑えるため株仲間の解散を命じたが、流通の混乱を招いて効果は上がらなかった。また江戸に流入した貧民を帰郷させる人返しの法により農村の再建を図った。さらに幕府財政の立て直しと対外的防備の強化を目的に、江戸・大坂周辺の土地を直轄地とする上知令を出したが、大名・旗本の反対にあい撤回され、天保の改革は失敗に終わった。", "explanation": "株仲間解散(物価抑制)→人返しの法(農村人口の回復)→上知令(財政再建・対外防備)という改革の流れと、いずれも実効性を欠き最終的に忠邦失脚に至る結末をおさえる。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12178", "field": "近代", "difficulty": 3, "type": "short", "question": "五・一五事件で犬養毅内閣が倒れたのち、衆議院第一党である立憲政友会に大命が降下せず、海軍大将であった人物を首班とする、政党と官僚・軍部などが連立する内閣が成立した。この人物は誰か。またこのような形態の内閣は一般に何と呼ばれるか答えなさい。", "choices": [], "answer": "斎藤実。挙国一致内閣。", "modelAnswer": "斎藤実。挙国一致内閣。", "explanation": "五・一五事件で政党内閣の慣行(憲政の常道)は崩れ、元老は衆議院第一党の党首ではなく海軍大将の斎藤実に組閣の大命を降下した。斎藤実内閣は立憲政友会・立憲民政党を与党としつつ官僚・軍人も加えた「挙国一致内閣」であり、この事件を境に政党内閣の時代は終わりを告げた。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12179", "field": "近代", "difficulty": 4, "type": "short", "question": "1935年前後、憲法学者美濃部達吉が唱えた統治権に関する学説をめぐり、貴族院や在郷軍人会などから激しい排撃運動が起こった事件を何と呼ぶか。また、この事件を受けて岡田啓介内閣が発した、この学説を否定する声明を何と呼ぶか答えなさい。", "choices": [], "answer": "天皇機関説事件。国体明徴声明(国体明徴に関する声明)。", "modelAnswer": "天皇機関説事件。国体明徴声明(国体明徴に関する声明)。", "explanation": "美濃部達吉の天皇機関説(統治権は法人としての国家に属し天皇はその最高機関として統治権を行使するという学説)は、貴族院で菊池武夫らにより反国体的であると攻撃され、在郷軍人会など国家主義勢力からの排撃運動に発展した(天皇機関説事件)。政府はこの圧力に屈し、国体明徴声明を発して天皇機関説を公式に否定した。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12180", "field": "外交史", "difficulty": 4, "type": "essay", "question": "1937年に勃発した盧溝橋事件から日中戦争が全面化していく経緯について、当時の内閣の対応や中国側の情勢にも触れながら150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "1937年7月、北京郊外で盧溝橋事件が勃発すると、当時の第1次近衛文麿内閣は当初不拡大方針を声明した。しかし軍部の強い要求を受け、方針を転換して中国本土への大規模な派兵に踏み切り、戦火は華北から華中へと拡大した。一方、中国側では1936年の西安事件を契機に国民党と共産党の対立が緩和され、翌1937年に第二次国共合作が成立して抗日民族統一戦線が形成されていたため、日本軍への抵抗は強まり、戦争は短期終結の見通しを失って長期化していった。", "explanation": "盧溝橋事件→近衛内閣の不拡大方針表明→軍部圧力による方針転換・全面戦争化、および中国側の西安事件→第二次国共合作という文脈をあわせて押さえる必要がある。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12181", "field": "文化史", "difficulty": 3, "type": "short", "question": "18世紀後半、宝暦・天明期を中心に上方で活躍し、対象をありのままに描く写生画で一世を風靡した画家は誰か。また同時期、江戸で錦絵と呼ばれる多色刷版画を創始した浮世絵師は誰か、それぞれ答えなさい。", "choices": [], "answer": "円山応挙。鈴木春信。", "modelAnswer": "円山応挙。鈴木春信。", "explanation": "円山応挙は「雪松図屛風」「保津川図屛風」などを代表作とし、写生画と呼ばれる平明な画風で上方の画壇を風靡した。同じ頃、江戸では鈴木春信が1760年代に錦絵と呼ばれる多色刷浮世絵版画を創始し、江戸の浮世絵は庶民文化として全盛期を迎える契機となった。この時期は元禄文化と化政文化の中間に位置する、独自のピークを示す江戸中期文化として近年注目されている。（文学部2011年で問われた論点）", "source": "2011", "faculty": "文学部"},
  {"id": "q12200", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文時代は草創期・早期・前期・中期・後期・晩期の6期に区分される。このうち、氷期から後氷期への移行期にあたり、縄文時代の開始期に相当する最初の時期区分の名称を答えなさい。", "choices": [], "answer": "草創期", "modelAnswer": "草創期", "explanation": "縄文時代は草創期・早期・前期・中期・後期・晩期の6時期に区分され、このうち最初の草創期は更新世末から完新世初頭にかけての気候変動期にあたり、土器の出現などが見られる縄文文化の黎明期とされる。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12201", "field": "古代", "difficulty": 3, "type": "choice", "question": "縄文海進と呼ばれる現象について述べた文として、誤っているものを1つ選びなさい。", "choices": ["気候の温暖化にともない、氷雪の融解とともに世界的な規模で海水面が上昇した。", "低地部に海水が浸入し、複雑に入り組んだ遠浅の入り江が各地に出現した。", "この現象により大陸との間の陸橋が失われ、日本列島は大陸から隔絶されるようになった。", "気候の寒冷化にともない、針葉樹林が拡大しマンモスなどの北方系動物群が南下してきた。"], "answer": 3, "modelAnswer": "", "explanation": "縄文海進は更新世末から完新世初頭にかけての気候温暖化にともなう海水面上昇現象で、陸橋の消失による大陸からの隔絶や、落葉広葉樹林・照葉樹林への植生の変化をもたらした。寒冷化にともなう針葉樹林拡大やマンモスの南下は、これ以前の氷期の現象であり、縄文海進とは逆の説明である。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12202", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "縄文時代の生業について、「植物栽培や家畜の飼育(牧畜)が広く行われていた明確な証拠があり、狩猟・漁労はほとんど行われなくなっていた」という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "縄文時代には一部で植物栽培が行われていた形跡が指摘されているが、家畜飼育(牧畜)が広く行われていた明確な証拠はない。また弓矢を用いた狩猟や漁労は継続して行われており、採集・狩猟・漁労を基盤としつつ一部栽培も取り入れた複合的な生業構造であったと考えられている。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12203", "field": "古代", "difficulty": 3, "type": "short", "question": "縄文社会は、集落や墓の構成から見て血縁関係・地縁関係を基盤とする社会と考えられているが、それに加えて信仰や祭祀・儀礼を通じた社会的なまとまりも観察される。このような性格をもつ集団のあり方を何と表現するか、漢字4字で答えなさい。", "choices": [], "answer": "部族的な集合体(部族社会)", "modelAnswer": "部族的な集合体(部族社会)", "explanation": "縄文社会は地縁・血縁を基盤とした地方集団を単位としつつ、信仰や祭祀・儀礼を通じた広域的な結びつきをもつ「部族的な集合体」として機能していたと考えられている。10数人程度の小規模な集団の移動性と、定住性を高めた地方集団形成の両面をあわせもつ点も特徴である。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12204", "field": "古代", "difficulty": 3, "type": "short", "question": "縄文時代中期以降に多く生み出された、呪術や祭祀・儀礼に関わるとされる土製・石製の製品を3種類挙げなさい。またこうした製品が物語る、縄文人の精神活動を支えた信仰のあり方を何と呼ぶか答えなさい。", "choices": [], "answer": "土偶・石棒・土面。アニミズム(自然崇拝的な精神活動、シャーマニズム)。", "modelAnswer": "土偶・石棒・土面。アニミズム(自然崇拝的な精神活動、シャーマニズム)。", "explanation": "縄文時代中期以降、土偶・石棒・土面など呪術性・祭祀性の強い製品が多く作られるようになり、先祖祭祀や精霊崇拝に基づくアニミズム的信仰、シャーマニズムなどの精神活動をうかがうことができる。これらの儀礼は集団間の交流を促進する契機ともなった。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12205", "field": "古代", "difficulty": 4, "type": "essay", "question": "縄文文化から弥生文化への移行の背景にある、大陸系文化との接触・融合の過程を150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "紀元前1000年頃から、朝鮮半島を経由して稲作を中心とする大陸系の文化が日本列島に伝わり、主に北部九州を中心として在来の縄文文化との接触・融合が進んだ。渡来系の土器や石器・金属器の技術が縄文的な要素と混ざり合いながら文化変容が起こり、新たに弥生文化が形成された。この新しい文化はやがて広く列島各地に波及し、北海道など一部地域を除いて弥生文化圏が拡大していった。", "explanation": "弥生文化の成立を「渡来文化の一方的な流入」ではなく「渡来系文化と在来の縄文文化との接触・融合」というプロセスとして捉える視点が重要。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12206", "field": "古代", "difficulty": 3, "type": "short", "question": "『続日本紀』によれば、ある国の郡から自然銅が朝廷に献上されたことを機に、年号が改められるとともに新たな銭貨の鋳造が始まったとされる。この国名を漢字2字で答えなさい。またこの出来事にちなんで改元された年号は何か答えなさい。", "choices": [], "answer": "武蔵(国)。和銅。", "modelAnswer": "武蔵(国)。和銅。", "explanation": "『続日本紀』には、武蔵国秩父郡から「和銅」(精錬を要しない自然銅)が献上されたことを受けて、和銅への改元と銭貨(和同開珎)の鋳造が同時に行われたと記されている。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12207", "field": "古代", "difficulty": 3, "type": "short", "question": "和同開珎に先立って鋳造されたとみられる貨幣が、飛鳥池遺跡から大量に発見されている。この貨幣は銘にもとづき何と呼ばれているか、漢字3字で答えなさい。", "choices": [], "answer": "富本銭", "modelAnswer": "富本銭", "explanation": "飛鳥池遺跡からは「富本」の銘を持つ銅銭が大量に出土しており、これは和同開珎に先行して鋳造された貨幣で「富本銭」と呼ばれる。ただしその流通の実態については、まじない用や儀礼用であったとする説も含め議論がある。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12208", "field": "古代", "difficulty": 3, "type": "short", "question": "711年に律令国家が出した詔は、銭貨を用いて交易することを知らない習俗を改めるという理由のもと、蓄えた銭貨の額に応じてある褒賞を与えることを宣言し、銭貨の流通を促そうとするものであった。この詔を何と呼ぶか答えなさい。", "choices": [], "answer": "蓄銭叙位令", "modelAnswer": "蓄銭叙位令", "explanation": "711年に出された蓄銭叙位令は、一定額以上の銭貨を蓄えた者に位階を与えることを定めた法令で、まだ銭貨経済になじみのなかった社会に銭貨流通を根づかせようとする律令国家の苦心のあらわれであった。ただし8世紀末以降には逆に銭貨の蓄蔵が禁じられるなど、政策は動揺した。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12209", "field": "社会経済", "difficulty": 4, "type": "essay", "question": "律令国家の財政体系は、なぜ銭貨を用いた流通経済とはなじみにくい性格をもっていたのか。租・庸・調などの税制のあり方に触れながら150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "律令国家の財政は、租・庸・調や雑徭などの税を布・稲・穀物や労働力といった実物(人も含む)の形で徴収し、それを国家が現物のまま管理・分配する体系を基本としていた。このため、銭貨という抽象的な交換手段を用いる流通経済とは本来なじみにくく、律令国家は銭貨と布・稲との交換比率を明示したり、運脚に銭貨を用いた食糧調達を推奨したりするなど、現物本位の財政体系と銭貨流通とを無理に接合させる工夫を重ねる必要があった。", "explanation": "現物本位の財政体系(租・庸・調・雑徭など)と、抽象的な価値尺度である銭貨を用いる流通経済との間の根本的なズレが、蓄銭叙位令や交換比率の明示など一連の銭貨政策の動揺の背景にあった点を押さえる。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12210", "field": "中世", "difficulty": 3, "type": "short", "question": "3代将軍源実朝が暗殺された後、事実上の鎌倉殿として「尼将軍」とも称された北条政子を支え、幕政の実権を握った人物は誰か。またこの人物と、「御成敗式目」の制定で知られる北条泰時との続柄を答えなさい。", "choices": [], "answer": "北条義時。泰時の父。", "modelAnswer": "北条義時。泰時の父。", "explanation": "実朝暗殺後、北条政子を支えつつ幕政の実権を握ったのは北条義時であり、その子である北条泰時は「御成敗式目」の制定で知られる。泰時は叔父の北条時房と連署としてよく助けられており、両者の協力関係が執権政治の安定を支えた。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12211", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代後期、有力御家人であった安達泰盛が、内管領平頼綱と対立した末に一族とともに滅ぼされた事件を何と呼ぶか、漢字4字で答えなさい。", "choices": [], "answer": "霜月騒動", "modelAnswer": "霜月騒動", "explanation": "1285年、御家人の中でも有力であった安達泰盛が、得宗被官(御内人)の筆頭である内管領平頼綱と対立し、一族とともに滅ぼされた事件を霜月騒動と呼ぶ。この事件以降、得宗被官の政治的発言力がいっそう強まった。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12212", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "室町幕府の内紛である観応の擾乱において、足利尊氏の執事として急進的な改革路線を推し進めた高師直は、足利直義との対立の末に滅ぼされたが、その活躍ぶりは軍記物語『太平記』に生き生きと描かれている、という説明は正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "高師直は足利尊氏の執事として急進的な所領政策・改革路線を主導し、旧来の秩序を重んじる足利直義と激しく対立した。この対立は観応の擾乱に発展し、高師直は最終的に滅ぼされたが、その大胆な人物像や活躍は軍記物語『太平記』に生き生きと描かれている。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12213", "field": "中世", "difficulty": 3, "type": "short", "question": "室町幕府において将軍を直接補佐する最高職を何と呼ぶか。またこの職に任じられる家柄は特定の3氏に限られていたが、その3氏の名を答えなさい。", "choices": [], "answer": "管領。斯波氏・細川氏・畠山氏。", "modelAnswer": "管領。斯波氏・細川氏・畠山氏。", "explanation": "室町幕府では執事の職掌が発展して管領となり、将軍を直接補佐する最高職として位置づけられた。この職には斯波・細川・畠山の三氏(三管領)のみが就任することができた。なお鎌倉府においても同様に鎌倉公方を補佐する関東管領がおかれ、次第に山内上杉氏に固定化されていった。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12214", "field": "中世", "difficulty": 4, "type": "essay", "question": "応仁の乱の勃発と、その後に見られる「下剋上」の風潮の広まりについて、守護家の内紛にも触れながら150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "応仁の乱は、将軍家の後継争いに加え、畠山氏や斯波氏など有力守護家における家督争いが絡み合って勃発し、細川勝元・山名持豊(宗全)を中心とする東西両軍に諸大名が分かれて争う大乱となった。この乱を通じて幕府や守護の権威は大きく揺らぎ、守護代や国人など下位の者が実力によって上位の者にとって代わる下剋上の風潮が全国に広がり、各地で戦国大名が台頭する時代へとつながっていった。", "explanation": "応仁の乱=将軍家・守護家の内紛の連鎖が全国的動乱に発展した点、及びその帰結としての下剋上・戦国大名の登場という因果関係を押さえる。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12215", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸時代、幕府や大名などの領主が百姓から年貢を徴収する際、その年の収穫高を実際に調査して税率を決める徴収方法を何と呼ぶか。また、この方法に代わって後に広まった、一定期間同じ税率を据え置く徴収方法の名も答えなさい。", "choices": [], "answer": "検見法。定免法。", "modelAnswer": "検見法。定免法。", "explanation": "検見法は毎年の収穫状況を実地に調査して年貢率を決定する方式で、幕藩領主が当初百姓からぎりぎりまで年貢を取り立てる手段として用いられたが、手続きの煩雑さや不正の余地などから、江戸中期以降には一定期間税率を固定する定免法が広く採用されるようになった。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12216", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸幕府は本百姓の没落を防ぐため、田畑の売買を禁じる法令を出した。この法令を何と呼ぶか。また、農民が田畑を勝手に分割して相続することを制限した法令も答えなさい。", "choices": [], "answer": "田畑永代売買の禁令(田畑永代売買禁止令)。分地制限令。", "modelAnswer": "田畑永代売買の禁令(田畑永代売買禁止令)。分地制限令。", "explanation": "幕府は本百姓を年貢負担の基盤として維持するため、田畑永代売買の禁令によって田畑の売却による本百姓の没落を防ごうとし、さらに分地制限令によって田畑の細分化による経営規模の縮小を抑えようとした。「たわけ」という言葉は田畑を分割することの愚かさに由来するといわれる。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12217", "field": "近世", "difficulty": 3, "type": "short", "question": "17世紀後半以降、農業生産力を高めるための技術的知見をまとめた著作物が各地で著されるようになった。宮崎安貞が著した、代表的な農業技術書の名を答えなさい。", "choices": [], "answer": "農業全書", "modelAnswer": "農業全書", "explanation": "宮崎安貞は17世紀後半、実地の経験にもとづいて農作業や施肥・農具の使用法などをまとめた『農業全書』を著した。これは日本最初期の体系的な農書として、その後の農業技術の普及・向上に大きな影響を与えた。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12218", "field": "近代", "difficulty": 3, "type": "short", "question": "1873年にアメリカから帰国し、洋学者西村茂樹らと相談のうえ明六社を結成した人物は誰か。またこの人物はのち初代の何大臣に就任したか答えなさい。", "choices": [], "answer": "森有礼。初代文部大臣。", "modelAnswer": "森有礼。初代文部大臣。", "explanation": "森有礼は1873年にアメリカから帰国後、西村茂樹らと明六社を結成し、翌年創刊された機関誌『明六雑誌』を通じて西洋の知識の紹介に努めた。のちに初代文部大臣に就任し、学校令の制定など近代教育制度の整備に尽力した。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12219", "field": "近代", "difficulty": 5, "type": "essay", "question": "1874年の民撰議院設立建白書の提出から、自由民権運動が全国に広まり、明治十四年の政変を経て国会開設の勅諭が出されるまでの経緯を200字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "1874年、征韓論争で政府を去った板垣退助ら元参議は民撰議院設立建白書を提出し、議会開設をめぐる論争が全国に広がった。国会即時開設を主張する大井憲太郎ら急進派と、漸進的な立憲制導入を説く加藤弘之らとの間で論争が交わされる中、自由民権運動は組織化されて全国に拡大した。政府内部でも憲法制定・国会開設を求める動きがあり、イギリス流の政党内閣制導入とあわせて国会の早期開設を主張した参議大隈重信が、明治十四年の政変によって政府から追放されると、伊藤博文らを中心に君主権の強いドイツ流の憲法制定に向けた準備が進められ、10年後の国会開設を約束する勅諭が出された。", "explanation": "民撰議院設立建白書→自由民権運動の全国的拡大(急進派と漸進派の論争)→大隈重信の政変による追放(明治十四年の政変)→国会開設の勅諭、という流れをおさえる。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12220", "field": "近代", "difficulty": 4, "type": "essay", "question": "大正時代から昭和初期にかけての「憲政の常道」と呼ばれる時代がどのようにして終わりを迎えたか、五・一五事件と二・二六事件に触れながら150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "大正末期から昭和初期にかけて、二大政党(立憲政友会・立憲民政党)が交代で政権を担当する「憲政の常道」と呼ばれる慣行が続いた。しかし1932年の五・一五事件で立憲政友会の犬養毅首相が海軍青年将校らによって殺害されると、元老は政党の党首ではなく穏健派の人物に組閣の大命を降下するようになり、政党内閣の時代は終わりを告げた。その後も陸軍青年将校らによるクーデタの動きはやまず、1936年の二・二六事件では首相官邸や警視庁などが襲撃され、以後軍部の政治的発言力がいっそう強まっていった。", "explanation": "「憲政の常道」(二大政党交代)→五・一五事件(犬養毅暗殺・政党内閣の終焉)→軍部の台頭→二・二六事件(クーデタ・軍部発言力の増大)という流れを整理する。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12221", "field": "文化史", "difficulty": 4, "type": "essay", "question": "室町時代から安土桃山時代にかけて、狩野派が「天下画工の長」として画壇を支配する地位を築いていく過程を、狩野正信・元信・永徳の3代にわたる展開に触れながら150字程度で説明しなさい。", "choices": [], "answer": "", "modelAnswer": "狩野派の初代狩野正信は、東山文化の時代に足利義政の邸宅の障子絵を制作するなど室町幕府の御用絵師として活躍した。2代目の元信は土佐派の大和絵の手法を取り入れて漢画主体であった狩野派のレパートリーを拡大し、一族門弟による工房体制を築いて量産を可能にした。元信の孫にあたる永徳は、雄大な城郭の障壁画をモチーフを単純化した大画様式によって効率的に量産する体制を完成させ、狩野派を流派をこえて時代を代表する画風へと押し上げた。", "explanation": "正信(御用絵師としての基盤形成)→元信(大和絵との融合・工房体制)→永徳(大画様式・障壁画の量産体制)という3代にわたる発展の流れを因果関係とともに整理する。（文学部2012年で問われた論点）", "source": "2012", "faculty": "文学部"},
  {"id": "q12240", "field": "古代", "difficulty": 2, "type": "short", "question": "弥生時代の農耕集落において、竪穴住居とともに造られた掘立柱建物で、収穫した稲などの穀物を湿気やネズミの害から守るために床を高くした倉庫を何と呼ぶか。漢字4字で答えよ。", "choices": [], "answer": "高床倉庫", "modelAnswer": "高床倉庫", "explanation": "弥生時代の農耕集落には竪穴住居のほか、収穫物を貯蔵するための高床倉庫が建てられた。床を高くすることで湿気やネズミの害を防ぐ工夫がなされ、単なる貯蔵施設にとどまらず農耕儀礼の場としての性格も持ったと考えられている。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12241", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代後期(2〜3世紀)の倭の政治状況を伝える中国の史書に関する説明として正しいものを1つ選べ。", "choices": ["『後漢書』東夷伝には、107年に帥升らが生口160人を献じて後漢の皇帝に謁見を求めたことが記されている", "『魏志』倭人伝には、卑弥呼が共立される以前に倭国で長期にわたる争乱があったと記されている", "『漢書』地理志には、倭には百余りの国があり、楽浪郡へ定期的に使者を送っていたことが記されている", "上記はすべて正しい"], "answer": 3, "modelAnswer": "", "explanation": "『漢書』地理志は倭が百余国に分かれ楽浪郡に使者を送っていたことを、『後漢書』東夷伝は107年の帥升による朝貢を、『魏志』倭人伝は卑弥呼共立以前の倭国の争乱をそれぞれ伝えており、これらはいずれも弥生時代後期の倭の政治状況を知る基本史料である。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12242", "field": "古代", "difficulty": 4, "type": "essay", "question": "古墳時代開始期の大型前方後円墳が奈良盆地のどの地域に集中して分布しているか地名を挙げたうえで、そのことが古墳時代の開始について何を示すと考えられているか、100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "奈良盆地南東部(纒向地域)に出現期の大型前方後円墳が集中しており、纒向遺跡を中心とする勢力が古墳時代開始に主導的役割を果たし、後のヤマト政権の中核となる首長連合が同地域を基盤に形成されたことを示すと考えられている。", "explanation": "箸墓古墳をはじめとする最古級の前方後円墳は奈良盆地南東部の纒向地域に集中しており、この地に王権の源流となる勢力が成立していたことを示す証拠とされる。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12243", "field": "古代", "difficulty": 2, "type": "short", "question": "藤原鎌足の子で、大宝律令の編纂に尽力し、平城京への遷都にも協力した人物は誰か。", "choices": [], "answer": "藤原不比等", "modelAnswer": "藤原不比等", "explanation": "中臣鎌足の子・藤原不比等は大宝律令の編纂を主導し、娘の宮子を文武天皇に、光明子を聖武天皇にそれぞれ嫁がせるなど、藤原氏の外戚としての権力基盤確立に尽力した。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12244", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "藤原光明子(光明皇后)は、皇族以外の出身者として初めて立后した例であり、これ以降藤原氏は天皇の外戚としての地位を確立していく足がかりを得た。正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原不比等の娘光明子は聖武天皇の皇后となり、皇族以外から立后した最初の例とされる。以後藤原氏は娘を皇后・后妃として天皇家に送り込み、外戚として政治権力を握る手法を確立していった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12245", "field": "古代", "difficulty": 3, "type": "short", "question": "承和の変で伴健岑・橘逸勢らを排斥し、応天門の変では伴善男を失脚させて、人臣として初めて摂政となった人物は誰か。", "choices": [], "answer": "藤原良房", "modelAnswer": "藤原良房", "explanation": "藤原良房は承和の変・応天門の変を通じて政敵の伴・橘両氏を退け、清和天皇の摂政に就任した。これは人臣摂政の初例であり、藤原氏による摂関政治確立の出発点となった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12246", "field": "古代", "difficulty": 3, "type": "short", "question": "969年、左大臣源高明が大宰権帥として左遷された政変を何と呼ぶか。", "choices": [], "answer": "安和の変", "modelAnswer": "安和の変", "explanation": "安和の変により源高明が失脚したことで、以後藤原氏(北家)が摂政・関白の地位をほぼ独占するようになり、摂関政治が確立していった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12247", "field": "古代", "difficulty": 3, "type": "choice", "question": "摂関政治期の内部抗争について、正しいものを1つ選べ。", "choices": ["藤原兼通と藤原兼家は実の兄弟でありながら、関白の地位をめぐって激しく対立した", "藤原道長は甥の藤原伊周との政争に勝利し、摂関政治の全盛期を築いた", "藤原道長の子頼通は後一条・後朱雀・後冷泉の3代にわたって摂政・関白を務めた", "上記はすべて正しい"], "answer": 3, "modelAnswer": "", "explanation": "藤原兼通・兼家兄弟の対立や、藤原道長が甥の伊周を排して権力を握った政争は摂関政治確立過程における内部抗争の代表例である。道長の子頼通も長期にわたり摂政・関白を務め、摂関政治の全盛期を支えた。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12248", "field": "中世", "difficulty": 3, "type": "short", "question": "中世荘園における年貢・公事の徴収単位として設定された土地区画を何と呼ぶか。ひらがな2字で答えよ。", "choices": [], "answer": "名(みょう)", "modelAnswer": "名(みょう)", "explanation": "荘園・公領では耕地が名という単位に編成され、名を請け負う名主が年貢・公事の納入責任を負った。荘園内には公文・下司・預所などの荘官が置かれ、荘園経営の実務にあたった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12249", "field": "中世", "difficulty": 2, "type": "short", "question": "1185年、源頼朝が朝廷から諸国の荘園・公領に任命する権限を認められた、御家人が任じられた職を何というか。", "choices": [], "answer": "地頭", "modelAnswer": "地頭", "explanation": "1185年、頼朝は諸国の荘園・公領に地頭を設置・任免する権限を朝廷から獲得し、御家人を地頭に任じることで荘園公領制の中に幕府の支配を組み込んでいった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12250", "field": "中世", "difficulty": 3, "type": "short", "question": "承久の乱後、新たに任命された地頭(新補地頭)の得分の基準を定めた法を何というか。", "choices": [], "answer": "新補率法", "modelAnswer": "新補率法", "explanation": "承久の乱で幕府側が勝利したことにより、没収された貴族・武士の所領に新たに地頭が補任された(新補地頭)。その得分の基準として新補率法が定められ、田畑11町ごとに1町の免田を与えるなどの規定がなされた。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12251", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "室町幕府が発した半済令は、当初近江・美濃・尾張の3国を対象に、荘園・公領の年貢の半分を軍費として守護に徴収することを認めたものであった。正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "1352年(観応3年)の半済令は近江・美濃・尾張3国を対象に始まり、のち対象国・内容が拡大していった。守護は年貢の半分を兵粮料所として徴収する権限を得て、これが守護の権限拡大・守護大名化を促す一因となった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12252", "field": "近世", "difficulty": 2, "type": "short", "question": "1615年、江戸幕府が天皇・公家の行動を規制するために制定した法度を何というか。", "choices": [], "answer": "禁中並公家諸法度", "modelAnswer": "禁中並公家諸法度", "explanation": "禁中並公家諸法度は天皇の第一の務めを学問にあると定め、武家と公家の官位を別立てにするなど、幕府が朝廷を統制する法的根拠となった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12253", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸幕府が朝廷を監視・統制するために公家の中から任命し、幕府と朝廷の間の連絡・交渉にあたらせた役職を何というか。", "choices": [], "answer": "武家伝奏", "modelAnswer": "武家伝奏", "explanation": "幕府は公家から武家伝奏を任命して朝廷との連絡・交渉にあたらせる一方、京都所司代を置いて朝幕間の折衝や京都の警護・訴訟にあたらせ、朝廷を二重に監視・統制した。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12254", "field": "近世", "difficulty": 3, "type": "short", "question": "後水尾天皇が幕府の許可なく突然譲位した後、跡を継いで即位した、徳川秀忠の娘和子(東福門院)を母とする女性天皇は誰か。", "choices": [], "answer": "明正天皇", "modelAnswer": "明正天皇", "explanation": "後水尾天皇は幕府への抗議の意もこめて突然譲位し、秀忠の娘和子との間に生まれた娘が即位して明正天皇となった。これは奈良時代の称徳天皇以来、実に約860年ぶりの女性天皇であった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12255", "field": "近世", "difficulty": 3, "type": "short", "question": "渋川春海が平安時代以来用いられてきた宣明暦の誤りを修正して作成した暦を何というか。", "choices": [], "answer": "貞享暦", "modelAnswer": "貞享暦", "explanation": "渋川春海は天体観測にもとづき、800年以上用いられてきた宣明暦の誤差を修正して貞享暦を作成し、幕府の天文方に任じられた。同時期、歌学の分野では北村季吟が『源氏物語湖月抄』を著し、初代歌学方に任じられている。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12256", "field": "近代", "difficulty": 3, "type": "choice", "question": "1874年の台湾出兵に関する説明として誤っているものを1つ選べ。", "choices": ["琉球漂流民殺害事件を契機として出兵が行われた", "出兵は西郷従道の指揮のもとで行われた", "清国は台湾先住民に関する責任を全面的に認め、ただちに賠償に応じた", "この出兵は近代日本にとって最初の海外派兵であった"], "answer": 2, "modelAnswer": "", "explanation": "台湾出兵は琉球漂流民殺害事件を理由に西郷従道の指揮で行われた近代日本最初の海外派兵である。清国は当初台湾先住民への責任を否定する姿勢を示し、日本の出兵は不当だと抗議したが、最終的にイギリスの調停もあり事件処理費用の支払いに応じて決着した。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12257", "field": "外交史", "difficulty": 3, "type": "truefalse", "question": "1876年に結ばれた日朝修好条規は、朝鮮に対して日本の領事裁判権を認めさせる一方、日本商品への関税免除も付属の取り決めで定められた、朝鮮にとって一方的に不利な条約であった。正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "日朝修好条規は前年の江華島事件を機に締結され、朝鮮に釜山など3港の開港と日本の領事裁判権を認めさせた一方、付属の取り決めで日本商品への関税免除も定めるなど、朝鮮側に一方的に不利な不平等条約であった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12258", "field": "外交史", "difficulty": 3, "type": "short", "question": "1884年、朝鮮で日本と結んだ急進開化派(金玉均ら)が起こしたが、清国軍の介入により失敗したクーデター事件を何というか。", "choices": [], "answer": "甲申事変(甲申政変)", "modelAnswer": "甲申事変(甲申政変)", "explanation": "1884年、金玉均ら急進開化派は日本公使館・駐留日本軍と結んでクーデターを起こしたが、清国軍の介入により失敗し、事件後には漢城条約が結ばれた。前年の1882年には旧式軍隊の反乱をきっかけとする壬午軍乱もおこっており、朝鮮をめぐる日清の対立が深まっていった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12259", "field": "外交史", "difficulty": 3, "type": "short", "question": "1894年、外相陸奥宗光のもとで調印され、日英間の領事裁判権撤廃を実現した条約を何というか。", "choices": [], "answer": "日英通商航海条約", "modelAnswer": "日英通商航海条約", "explanation": "日清戦争開戦直前の1894年、外相陸奥宗光はイギリスとの間に日英通商航海条約を結び、領事裁判権の撤廃に成功した。関税自主権の完全回復は含まれなかったが、条約改正における画期的な成果となった。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12260", "field": "文化史", "difficulty": 3, "type": "choice", "question": "平安時代後期の大和絵に関する説明として正しいものを1つ選べ。", "choices": ["「源氏物語絵巻」は藤原隆能の作と伝えられ、引目鉤鼻や吹抜屋台などの技法を特色とする", "平清盛ら平家一門が厳島神社に奉納した「平家納経」には、「源氏物語絵巻」と共通する優美な装飾感覚が見られる", "大和絵は中国風の唐絵から分かれて成立し、日本人好みの主題と美意識を反映した", "上記はすべて正しい"], "answer": 3, "modelAnswer": "", "explanation": "藤原隆能作と伝わる「源氏物語絵巻」は引目鉤鼻・吹抜屋台などを特色とする大和絵の典型であり、平清盛ら平家一門が厳島神社に奉納した「平家納経」にも同様の優美な装飾感覚が表れている。大和絵は中国風の唐絵から分かれ、日本的な美意識を反映して発達した。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12261", "field": "文化史", "difficulty": 4, "type": "essay", "question": "鎌倉時代に成立した「似絵」とはどのような絵画か説明したうえで、その後大和絵の系譜が室町・江戸時代を通じてどのように展開したか、代表的な画家・流派を挙げながら100〜120字程度で述べよ。", "choices": [], "answer": "", "modelAnswer": "似絵は俗人の容姿を写実的に描いた肖像画で、藤原隆信・信実父子が代表的作者として知られる。室町時代には土佐光信らの土佐派が宮廷絵所預として大和絵の伝統を継承し、江戸時代には俵屋宗達・本阿弥光悦が新様式(琳派)を開き、住吉派や菱川師宣の浮世絵版画にも大和絵の伝統が受け継がれた。", "explanation": "似絵は鎌倉時代の写実主義を反映して俗人を対面描写した肖像画で、藤原隆信・信実父子がその名手として知られる。以後、大和絵の伝統は室町期の土佐派(土佐光信ら)、江戸初期の俵屋宗達・本阿弥光悦による琳派(のち尾形光琳へ継承)、住吉如慶・具慶の住吉派、さらに菱川師宣の浮世絵版画へと多様に展開した。（文学部2013年で問われた論点）", "source": "2013", "faculty": "文学部"},
  {"id": "q12280", "field": "古代", "difficulty": 2, "type": "short", "question": "約258万年前から約1万1000年前まで続いた、氷期と間氷期の交代が繰り返され気候寒冷化がおこった地質時代を何というか。", "choices": [], "answer": "更新世", "modelAnswer": "更新世", "explanation": "更新世は氷期・間氷期が交互に訪れた寒冷な地質時代であり、日本列島の後期旧石器時代の人々はこの時代の環境に適応してナイフ形石器や尖頭器を用いた狩猟採集生活を営んだ。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12281", "field": "古代", "difficulty": 2, "type": "short", "question": "クリ林の管理・半栽培が明らかになったことで知られる、青森市に所在する縄文時代前期から中期の大規模集落遺跡は何か。", "choices": [], "answer": "三内丸山遺跡", "modelAnswer": "三内丸山遺跡", "explanation": "三内丸山遺跡では大型掘立柱建物跡や大量のクリの遺存体が出土し、縄文人がクリ林を管理・半栽培していたことが明らかになった。竪穴住居のほか貯蔵穴や墓地を伴う集落が営まれ、定住的な生活の実態を伝えている。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12282", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代の社会変化に関する説明として正しいものを1つ選べ。", "choices": ["九州北部で始まった支石墓は、弥生時代後期には全国的に広まった", "食料生産社会となった弥生時代には、余剰生産物の蓄積を背景に貧富の差や階層分化が進んだ", "弥生時代を通じて鉄はきわめて貴重であり、農工具に用いられることはなかった", "弥生時代と同時代の北海道では、水稲耕作を基盤とする文化が展開した"], "answer": 1, "modelAnswer": "", "explanation": "弥生時代には水稲農耕による余剰生産物の蓄積を背景に、集落間や集落内部で貧富の差・階層分化が進んだ。支石墓は九州北部を中心とした一時期の墓制で全国的に広まったわけではなく、同時代の北海道は続縄文文化の段階にあり水稲耕作は行われていない。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12283", "field": "古代", "difficulty": 3, "type": "short", "question": "律令制下、地方から中央政府へ調・庸などの税を運搬するために課された労役を何というか。", "choices": [], "answer": "運脚", "modelAnswer": "運脚", "explanation": "調・庸などの中央政府への貢納物は、諸国から徴発された運脚と呼ばれる人々によって都まで運ばれた。長い道のりを徒歩で往還する負担は重く、途中で逃亡する者も少なくなかった。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12284", "field": "古代", "difficulty": 2, "type": "short", "question": "律令制下、諸国の軍団兵士から選ばれ、主に東国から九州北部の防衛にあたった兵士を何というか。", "choices": [], "answer": "防人", "modelAnswer": "防人", "explanation": "防人は諸国の軍団兵士の中から徴発され、主に東国から九州北部沿岸の防衛に派遣された。交替制で任務にあたったが、望郷の念を歌に託した防人歌が『万葉集』に多数収められている。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12285", "field": "古代", "difficulty": 3, "type": "short", "question": "律令制において、親王や少納言以上あるいは一定の位階・官職を有する者に与えられ、身辺警護や雑務にあたった従者を何というか。", "choices": [], "answer": "資人", "modelAnswer": "資人", "explanation": "資人は親王・内親王や、少納言以上あるいは一定の位階・官職を持つ官人に与えられた従者で、身辺警護や雑務に従事した。当時の官人社会における身分に応じた特権の一例である。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12286", "field": "古代", "difficulty": 3, "type": "short", "question": "律令国家が蝦夷経営のため東北地方に設けた城柵に、防衛や周辺開拓のため諸国から組織的に移住させられた人々を何と呼ぶか。漢字2字で答えよ。", "choices": [], "answer": "柵戸", "modelAnswer": "柵戸", "explanation": "東北経営のため設けられた城柵には、周辺諸国から柵戸と呼ばれる人々が組織的に移住させられ、柵の維持・防衛とともに周辺の開拓にあたった。逆に朝廷に帰順した蝦夷は俘囚として諸国に移住させられることもあった。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12287", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉時代初期、平氏滅亡直後に起こった1185年の地震を、平清盛が竜となって引き起こしたという噂話と結びつけて著書に記した、関白藤原兼実の弟でもあった天台座主は誰か。", "choices": [], "answer": "慈円", "modelAnswer": "慈円", "explanation": "慈円は『愚管抄』の中で、平氏滅亡の直後に起こった大地震を平清盛の怨霊と結びつけて語るなど、中世の人々が地震と政変を密接に結びつけて理解していたことを示す好例を残している。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12288", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "藤原定家の日記『明月記』には、1204年(元久元年)に起こった地震について、過去に経験した元暦の大地震と比較しながら記した記述が見られる。正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "藤原定家は日記『明月記』の中で1204年の地震について、過去に体験した元暦の大地震には及ばないものの大地震であったと記し、地震の記憶を記録にとどめている。中世の公家の日記には、こうした地震に関する記述がしばしば見られる。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12289", "field": "中世", "difficulty": 3, "type": "short", "question": "1293年(正応6年)の鎌倉大地震の直後、混乱に乗じて有力御家人平頼綱が滅ぼされた政変を何というか。", "choices": [], "answer": "平禅門の乱", "modelAnswer": "平禅門の乱", "explanation": "1293年の鎌倉大地震では将軍御所や鶴岡八幡宮をはじめ多くの建物が損壊し、この混乱に乗じて平頼綱が滅ぼされる平禅門の乱が起こった。地震と政変が結びつく事例は室町幕府のもとでも見られ、中世を通じた特徴であった。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12290", "field": "近世", "difficulty": 3, "type": "short", "question": "明清交代の動乱の中、オランダ勢力を駆逐して台湾を奪い、これを拠点として清に抵抗した人物は誰か。", "choices": [], "answer": "鄭成功", "modelAnswer": "鄭成功", "explanation": "明清交代に際し、鄭成功はオランダ勢力を台湾から駆逐してこれを拠点とし、清に対する抵抗を続けた。近松門左衛門の時代物「国性爺合戦」のモデルとしても知られる。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12291", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸幕府の儒学者で、長崎に来航する中国船がもたらす海外情報をまとめ、明から清への王朝交代を「華夷変態」と題して著した人物は誰か。", "choices": [], "answer": "林鵞峰", "modelAnswer": "林鵞峰", "explanation": "林鵞峰は中国船がもたらした情報を集成し、明から清への王朝交代を華(文明)から夷(未開)への変化ととらえて『華夷変態』と題した。日本が中国大陸の動向を注視していたことを示す史料である。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12292", "field": "近世", "difficulty": 3, "type": "short", "question": "新井白石が著した、中華15省と外国・外夷などの地誌を記した書物は何か。", "choices": [], "answer": "華夷通商考", "modelAnswer": "華夷通商考", "explanation": "新井白石は『華夷通商考』を著し、中国本土15省をはじめ諸外国・諸民族の地理や事情を記録した。海外情報への関心が儒学者の間でも高まっていたことを示す。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12293", "field": "近世", "difficulty": 3, "type": "short", "question": "「鎖国」という語のもとになった訳語を、ケンペルの著書の翻訳を通じて作った蘭学者は誰か。", "choices": [], "answer": "志筑忠雄", "modelAnswer": "志筑忠雄", "explanation": "「鎖国」の語は、志筑忠雄がケンペルの著書を訳した際に作った訳語に由来する。江戸時代当時の幕府自身が用いていた語ではなく、後の時代に対外政策を理解する概念として定着していった。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12294", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸幕府が19世紀に西洋諸国の通商要求へ対処する中で編纂した、16世紀後半以降の外交関係史料をまとめた書物は何か。", "choices": [], "answer": "通航一覧", "modelAnswer": "通航一覧", "explanation": "幕府は対外政策の整理・理論化を図る中で、通信国(朝鮮・琉球)と通商国(中国・オランダ)を区別する論理を形成する一方、16世紀後半以降の外交関係史料を集成した『通航一覧』を編纂した。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12295", "field": "近代", "difficulty": 2, "type": "short", "question": "明治政府が1880年代前半以降、財政負担の大きい鉱山・工場などの官営事業を三井・三菱などの特定の政商に売却した政策を何というか。", "choices": [], "answer": "官営事業払下げ", "modelAnswer": "官営事業払下げ", "explanation": "大隈重信の主導で始まった官営事業払下げにより、三井は三池炭鉱を、三菱は長崎造船所をそれぞれ払い下げられて経営基盤を拡大し、政商から財閥へと成長する足がかりを得た。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12296", "field": "近代", "difficulty": 4, "type": "choice", "question": "1927年の昭和金融恐慌に関する説明として誤っているものを1つ選べ。", "choices": ["蔵相の失言をきっかけに取り付け騒ぎが全国に広がり、銀行の休業・破綻が相次いだ", "若槻礼次郎内閣は台湾銀行救済のための緊急勅令発布を枢密院に承認され、危機を収拾した", "田中義一内閣は支払猶予令(モラトリアム)を発し、日本銀行からの特別融資で沈静化をはかった", "金融恐慌の結果、中小銀行の整理・合併が進み、資本金・預金が少数の大銀行に集中した"], "answer": 1, "modelAnswer": "", "explanation": "昭和金融恐慌は蔵相片岡直温の失言をきっかけに取付け騒ぎが広がったが、若槻礼次郎内閣は台湾銀行救済のための緊急勅令発布を枢密院に拒否され、総辞職に追い込まれた。後継の田中義一内閣がモラトリアムと日銀の特別融資により事態を収拾し、恐慌後は銀行の整理・合併が進んで大銀行への資金集中が加速した。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12297", "field": "近代", "difficulty": 4, "type": "essay", "question": "昭和恐慌期における大蔵大臣井上準之助と高橋是清の財政政策の違いを、それぞれのキーワードを挙げながら100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "井上準之助は金解禁と緊縮財政によるデフレ政策で経済の立て直しを図ったが、世界恐慌と重なり深刻な昭和恐慌を招いた。高橋是清は金輸出再禁止(金本位制停止)により金融緩和を進め、赤字国債発行や積極財政で景気回復を実現した。", "explanation": "井上準之助蔵相は金解禁を断行し緊縮財政をとったが、世界恐慌の波及により深刻なデフレ不況(昭和恐慌)をまねいた。後任の高橋是清蔵相は金輸出再禁止による金本位制停止、赤字国債の発行、低為替による輸出増進など積極財政に転じ、比較的早期の景気回復を実現した。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12298", "field": "近代", "difficulty": 4, "type": "choice", "question": "GHQによる財閥解体政策に関する説明として誤っているものを1つ選べ。", "choices": ["GHQはまず15財閥に資産の凍結と解体を命じた", "持株会社整理委員会が設置され、財閥家族や指定された会社役員の持株が公開・処分された", "独占禁止法の制定にともない、独占的企業結合を監視する公正取引委員会が設置された", "過度経済力集中排除法にもとづき、指定された325社すべてが実際に分割・解体された"], "answer": 3, "modelAnswer": "", "explanation": "過度経済力集中排除法により325社が分割対象に指定されたが、占領政策の転換(いわゆる逆コース)もあって、実際に分割されたのは日本製鉄・三菱重工業など十数社にとどまった。GHQは15財閥の資産凍結・解体を命じ、持株会社整理委員会による株式処分、独占禁止法にもとづく公正取引委員会の設置など、財閥解体のための諸施策を進めた。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12299", "field": "文化史", "difficulty": 3, "type": "short", "question": "将軍足利義持の注文により、京都五山の禅僧31名が詩を寄せ、相国寺の画僧が「ひょうたんでなまずを押さえることができるか」という禅問答を絵画化した水墨画作品を何というか。", "choices": [], "answer": "瓢鮎図", "modelAnswer": "瓢鮎図", "explanation": "「瓢鮎図」は相国寺の画僧如拙が、公案(禅の修行課題)である「瓢箪でなまずを押さえられるか」という問いを絵画化した作品で、京都五山の禅僧31名の詩を添えて将軍足利義持の注文により制作された。室町時代の禅僧による文芸サロンのあり方を示す遺品である。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12300", "field": "文化史", "difficulty": 3, "type": "short", "question": "明に渡って本格的な水墨画技法を学び、帰国後は山口の大内氏の保護を受けて日本的な水墨画様式を大成した禅僧画家は誰か。", "choices": [], "answer": "雪舟", "modelAnswer": "雪舟", "explanation": "雪舟は明に渡って本格的な水墨画技法を学び、帰国後は大内氏の保護のもと山口を拠点に活動して日本的な水墨画様式を大成した。禅僧の文芸から出発した水墨画は、雪舟や常陸国出身で東国を中心に活動した雪村らによって全国的に広まっていった。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12301", "field": "文化史", "difficulty": 4, "type": "essay", "question": "室町時代に成立した書院造の建築的特徴と、それにともなう庭園について、床の間・違い棚などの語句を用いて100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "禅宗寺院の方丈が書斎を伴ったことに由来する書院造は、床の間や違い棚を備え、そこに中国伝来の絵画・陶磁器・文房具・書籍などの唐物が飾られた。建物の周囲には自然を象徴的に構成する枯山水などの庭園が配され、禅の哲学的空間を表現した。", "explanation": "書院造は禅宗寺院の方丈建築に由来し、床の間・違い棚を備えて唐物を飾る空間を持つ点に特色があり、後世の御殿建築・住宅建築に受け継がれた。あわせて枯山水庭園などが配され、慈照寺・竜安寺・鹿苑寺の庭園に代表されるように、禅の思想を視覚化する空間として発展した。（文学部2014年で問われた論点）", "source": "2014", "faculty": "文学部"},
  {"id": "q12320", "field": "古代", "difficulty": 2, "type": "short", "question": "107年、後漢の安帝に生口160人を献じて朝貢したと『後漢書』東夷伝に記される倭国王は誰か。", "choices": [], "answer": "帥升", "modelAnswer": "帥升", "explanation": "107年、倭国王帥升は後漢の安帝に生口160人を献じて朝貢したことが『後漢書』東夷伝に記されている。これは倭に関する中国側の記録の中でも早い時期の朝貢記事である。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12321", "field": "古代", "difficulty": 3, "type": "choice", "question": "2世紀後半に起こったとされる倭国大乱に関連する説明として適切でないものを1つ選べ。", "choices": ["この時代、殺傷を示すような人骨が発掘されることがある", "縄文時代には見られなかった環濠集落が出現するが、これは紛争に備えたものと考えられる", "近畿地方から瀬戸内一帯にかけて高地性集落が出現した", "倭国大乱の鎮静化には、邪馬台国と対立していた狗奴国の全面降伏が決定的な役割を果たした"], "answer": 3, "modelAnswer": "", "explanation": "倭国大乱は2世紀後半、倭国内の小国間の争いが激化した時期とされ、殺傷人骨の出土や環濠集落・高地性集落の出現がその痕跡と考えられている。この争乱は諸小国が卑弥呼を共立することでいったん収まったとされ、狗奴国が全面降伏して終息したとする記録は存在しない。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12322", "field": "古代", "difficulty": 2, "type": "short", "question": "239年、女王卑弥呼が魏の明帝に使者を遣わした際、金印とともに授けられた称号は何か。漢字4字で答えよ。", "choices": [], "answer": "親魏倭王", "modelAnswer": "親魏倭王", "explanation": "239年、卑弥呼は魏に使者を送り、明帝から「親魏倭王」の称号と金印・銅鏡などを授けられた。これは魏の権威を借りて倭国内での自らの立場を強化しようとしたものと考えられている。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12323", "field": "古代", "difficulty": 3, "type": "short", "question": "478年、宋に使者を遣わし、順帝から安東大将軍の称号を授かった倭王は誰か。", "choices": [], "answer": "倭王武", "modelAnswer": "倭王武", "explanation": "倭の五王(讃・珍・済・興・武)は5世紀を通じて中国の南朝に朝貢し、478年には倭王武が宋の順帝から安東大将軍の称号を授かった。これは朝鮮半島南部諸国に対する軍事的優位を国際的に承認させようとする外交であった。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12324", "field": "古代", "difficulty": 3, "type": "choice", "question": "律令制の口分田班給に関する説明として正しいものを1つ選べ。", "choices": ["良民男性への支給額は2段であった", "良民女性への支給額は男性の3分の1とされた", "私有の奴婢への支給額は、良人と全く同額であった", "口分田の支給額に性別・身分による差は設けられなかった"], "answer": 0, "modelAnswer": "", "explanation": "口分田は良民男性に2段が班給され、良民女性にはその3分の2、家人・私有の奴婢には良民の3分の1が支給されるなど、性別や身分に応じた差が設けられていた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12325", "field": "古代", "difficulty": 3, "type": "short", "question": "班田収授制のもとで、口分田を班給した後に残った、原則として1年契約で賃租された余りの土地を何というか。漢字2字で答えよ。", "choices": [], "answer": "乗田", "modelAnswer": "乗田", "explanation": "口分田班給の後に残った余剰の土地は乗田と呼ばれ、原則として1年を単位に賃租され、耕作者から地子(賃料)を徴収する仕組みがとられた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12326", "field": "古代", "difficulty": 3, "type": "short", "question": "桓武天皇が、戸籍の偽りなどで実施が困難になりつつあった班田収授を維持するため、班田の周期を6年から改めた制度を何というか。", "choices": [], "answer": "一紀一班(12年一班)", "modelAnswer": "一紀一班(12年一班)", "explanation": "桓武天皇は戸籍の偽り(偽籍)などによって実施が困難になりつつあった班田収授制を維持するため、班田の周期を6年から12年(一紀)に改める一紀一班の制を打ち出した。しかしその後もほぼ1世紀を経て班田は事実上途絶えた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12327", "field": "古代", "difficulty": 3, "type": "short", "question": "902年(延喜2年)、醍醐天皇のもとで出された、日本で最初の荘園整理令を何というか。", "choices": [], "answer": "延喜の荘園整理令", "modelAnswer": "延喜の荘園整理令", "explanation": "班田収授が途絶するのと前後して、902年に延喜の荘園整理令が出され、違法な土地集積の停止が図られた。同じ頃、公領・荘園の田地耕作と納税を請け負う田堵が台頭し、大規模な田堵は大名田堵と呼ばれた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12328", "field": "中世", "difficulty": 4, "type": "choice", "question": "保元の乱・平治の乱に関する政治情勢の説明として正しいものを1つ選べ。", "choices": ["崇徳上皇が弟の後白河天皇を退位させようとしたことが保元の乱の一因となった", "保元の乱では、藤原忠通と藤原頼長という摂関家内部の対立が皇位継承問題と結びついた", "平治の乱では、源義朝と平清盛はともに後白河上皇側について戦った", "平治の乱で敗れた源義朝は、その後も東国で勢力を維持し続けた"], "answer": 1, "modelAnswer": "", "explanation": "保元の乱は皇位・院政をめぐる対立が複合したもので、摂関家内部でも藤原忠通・頼長兄弟が対立し、それぞれ天皇方・上皇方に分かれて戦った。続く平治の乱では源義朝と平清盛が対立する側について戦い、敗れた義朝はまもなく尾張で家臣に殺害された。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12329", "field": "中世", "difficulty": 2, "type": "short", "question": "1189年、源頼朝が滅ぼした、平泉を本拠に東北地方で栄えた勢力を何というか。", "choices": [], "answer": "奥州藤原氏", "modelAnswer": "奥州藤原氏", "explanation": "源頼朝は1189年に平泉を本拠とする奥州藤原氏を滅ぼし、東国における軍事的覇権を確立した。これは鎌倉幕府成立過程における重要な画期の一つとされる。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12330", "field": "中世", "difficulty": 3, "type": "short", "question": "室町幕府初期、将軍足利尊氏とその弟足利直義との対立に端を発し、南北朝内乱を長期化させる一因となった幕府内部の抗争を何というか。", "choices": [], "answer": "観応の擾乱", "modelAnswer": "観応の擾乱", "explanation": "観応の擾乱は足利尊氏と弟直義の対立を中心とする幕府内部の抗争で、これに高師直らも関わって全国的な争乱に発展し、南北朝内乱が60年近くにわたって長期化する大きな要因となった。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12331", "field": "中世", "difficulty": 3, "type": "short", "question": "中世の惣村において、寄合を通じて村人自身が定め、自治的に運営された規約を何というか。漢字2字で答えよ。", "choices": [], "answer": "村掟(地下掟)", "modelAnswer": "村掟(地下掟)", "explanation": "惣村では寄合を通じて村人自身が村掟(地下掟)を定め、山野・用水の利用や治安維持などについて自治的なルールを運営した。惣村どうしの山野・用水をめぐる争いも中世の「たたかい」の一形態であった。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12332", "field": "近世", "difficulty": 2, "type": "short", "question": "1635年、3代将軍徳川家光が武家諸法度を改定して制度化した、大名を1年おきに江戸と国元に居住させる制度を何というか。", "choices": [], "answer": "参勤交代", "modelAnswer": "参勤交代", "explanation": "参勤交代は1635年、徳川家光による武家諸法度の改定で制度化され、大名は原則として1年ごとに江戸と国元を往復して生活することとなった。大名の妻子は人質として江戸藩邸に居住し、幕府による大名統制の柱の一つとなった。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12333", "field": "近世", "difficulty": 3, "type": "short", "question": "参勤交代のもとで江戸藩邸に常駐し、幕府や他藩との連絡・交渉、情報収集にあたった藩の役職を何というか。", "choices": [], "answer": "留守居(江戸留守居)", "modelAnswer": "留守居(江戸留守居)", "explanation": "参勤交代により藩主が江戸と国元を往復する中、江戸藩邸には留守居が置かれ、幕府や他藩との連絡・交渉、情報収集にあたった。江戸藩邸は単なる住居ではなく諸藩の対幕府・対他藩外交の拠点でもあった。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12334", "field": "近世", "difficulty": 3, "type": "short", "question": "大坂中之島にあった、諸藩の蔵物である米が現物取引されるだけでなく、先物取引(帳合米取引)も行われた米市場を何というか。", "choices": [], "answer": "堂島米市場", "modelAnswer": "堂島米市場", "explanation": "大坂中之島の堂島米市場では現米の売買に加え、帳合米取引と呼ばれる先物取引もおこなわれ、全国の米価形成に大きな影響を与えた。蔵物の売却代金は両替商を通じて江戸でも受け取ることができ、藩は現金輸送の必要を省くことができた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12335", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸時代の貨幣制度に関する説明として正しいものを1つ選べ。", "choices": ["金貨の単位は両・分・朱であったが、江戸中期以降に鋳造された一分銀は銀貨であった", "金座は江戸・京都・大坂の3カ所に置かれ、いずれも幕末まで存続した", "江戸は主に銀遣い、大坂は主に金遣いの経済圏であった", "江戸時代を通じて紙幣は一切発行されなかった"], "answer": 0, "modelAnswer": "", "explanation": "江戸時代には金貨(両・分・朱)、銀貨(貫・匁)、銭貨(文)の三貨が並行して流通し、天保年間に鋳造された一分銀のように金貨の単位で呼ばれる銀貨も存在した。江戸は金遣い、大坂は銀遣いの経済圏として知られ、両替商が三貨間の換算を担った。また多くの藩は財政難から独自に藩札を発行した。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12336", "field": "近代", "difficulty": 3, "type": "short", "question": "1873年の太政官布達により公園制度が始まったのち、東京上野の寛永寺境内跡地を利用した上野公園で1877年に内務省の提案により開催された博覧会を何というか。", "choices": [], "answer": "内国勧業博覧会(第1回内国勧業博覧会)", "modelAnswer": "内国勧業博覧会(第1回内国勧業博覧会)", "explanation": "1873年の太政官布達により公園制度が始まり、上野の寛永寺境内の一部を利用した上野公園では、内務省の提案により第1回内国勧業博覧会が開催された。以後、博物館や動物園も開設され、文化施設の集まる土地として発展した。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12337", "field": "近代", "difficulty": 3, "type": "short", "question": "1903年に開園した、旧陸軍用地を利用して一から設計された日本最初の洋式公園を何というか。", "choices": [], "answer": "日比谷公園", "modelAnswer": "日比谷公園", "explanation": "日比谷公園は1903年、旧陸軍用地を利用して一から設計された日本最初の洋式公園であり、開園2年後には日露戦争の講和条約に反対する国民大会(日比谷焼打事件)の会場となるなど、その後も政治的集会の場として利用された。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12338", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "日比谷公園は、1930年代に国会議事堂の近くに仮議事堂が置かれていたこともあり、護憲運動など政治運動に関する大会の会場としてしばしば利用された。正しいか。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "日比谷公園は日露講和反対の国民大会をはじめ、大正期の護憲運動など、民衆の政治運動の集会場として繰り返し利用された。1960年には公園内の建物で日本社会党委員長浅沼稲次郎が演説中に刺殺される事件も起きている。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12339", "field": "文化史", "difficulty": 2, "type": "short", "question": "江戸時代前期、版画による浮世絵制作を始め、浮世絵の量産・普及に道を開いた人物は誰か。", "choices": [], "answer": "菱川師宣", "modelAnswer": "菱川師宣", "explanation": "菱川師宣は版画による浮世絵制作を始めた人物として知られ、これにより浮世絵は量産可能となり、広く民間に普及するようになった。安房出身で、自らの作品を「日本絵」と称したことでも知られる。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12340", "field": "文化史", "difficulty": 3, "type": "short", "question": "18世紀後半、喜多川歌麿や東洲斎写楽を世に送り出し、浮世絵界の黄金時代を支えたプロデューサー的な版元(出版業者)は誰か。", "choices": [], "answer": "蔦屋重三郎", "modelAnswer": "蔦屋重三郎", "explanation": "蔦屋重三郎は美人画を得意とする喜多川歌麿や、個性的な役者絵を手がけた東洲斎写楽を世に送り出し、18世紀後半の浮世絵界の黄金時代を支えた版元として知られる。この時代には鈴木春信が始めた多色刷りの錦絵の技法がさらに洗練されていた。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12341", "field": "文化史", "difficulty": 4, "type": "essay", "question": "19世紀に入って浮世絵版画による風景画が民衆の人気を集めるようになった状況について、代表的な作者・作品名を挙げながら100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "葛飾北斎は「富嶽三十六景」で各地から眺めた富士山を描き、歌川広重は「東海道五十三次」で街道の宿場風景を描くなど、浮世絵版画による風景画(名所絵)が相次いで世に出て民衆の人気を集めた。広重が属した歌川派はその後も浮世絵の最大流派として明治期の開化絵にまで影響を及ぼした。", "explanation": "19世紀には葛飾北斎の「富嶽三十六景」や歌川広重の「東海道五十三次」など、浮世絵版画による風景画(名所絵)が相次いで発表され、民衆に広く人気を博した。広重が属した歌川派はその後も浮世絵界最大の流派としての地位を保ち、その系譜は明治初頭の開化錦絵や近代の日本画家にも及んでいる。（文学部2015年で問われた論点）", "source": "2015", "faculty": "文学部"},
  {"id": "q12360", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文時代の後期から晩期にかけて東日本を中心に築かれた、列石を円形に配置した大規模な記念物を何と呼ぶか。", "choices": [], "answer": "環状列石(ストーンサークル)", "modelAnswer": "環状列石(ストーンサークル)", "explanation": "秋田県の大湯環状列石などが代表例で、縄文後期・晩期の東日本に見られる共同祭祀の場と考えられている。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12361", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "縄文文化は土器製作や磨製石器の使用を伴っていたが、本格的な農耕や家畜飼育を欠いていたため、世界史上の「新石器文化」の要件を完全には満たさないと評価されることがある。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "縄文文化は土器・磨製石器を持つ点で新石器的要素を備えるが、本格的な農耕と牧畜を伴わないため、真の新石器革命とは性格を異にすると位置づけられている。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12362", "field": "古代", "difficulty": 3, "type": "short", "question": "縄文時代の精神文化を担った土偶に見られる呪術的・儀礼的造形の系譜は、後の古墳時代のどのような造形物に引き継がれたと考えられているか。", "choices": [], "answer": "埴輪", "modelAnswer": "埴輪", "explanation": "土偶に表れた精神世界に関わる造形は、古墳時代に入ると埴輪という新たな造形物に受け継がれたと考えられている。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12363", "field": "外交史", "difficulty": 2, "type": "truefalse", "question": "663年に唐・新羅連合軍に大敗した白村江の戦いの後、倭国は国内の防衛体制を強化するため水城や朝鮮式山城の築造を進めた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "百済復興を支援するため出兵した倭国軍は白村江で大敗し、その後の脅威に備えて大宰府周辺に水城や朝鮮式山城を築くなど防衛体制を急速に整えた。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12364", "field": "外交史", "difficulty": 3, "type": "short", "question": "白村江での敗戦後、大宰府防衛のために水城とともに築かれた、百済からの亡命貴族の技術指導による山城を1つ答えよ。", "choices": [], "answer": "大野城(または基肄城・金田城)", "modelAnswer": "大野城(または基肄城・金田城)", "explanation": "敗戦後の倭国は百済からの亡命貴族の指導のもと、大野城・基肄城・金田城といった朝鮮式山城を各地に築き、水城とともに大宰府防衛の要とした。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12365", "field": "古代", "difficulty": 2, "type": "short", "question": "天智天皇の死後に起こった壬申の乱で、大海人皇子が挙兵に先立ち一時身を隠していた地はどこか。", "choices": [], "answer": "吉野", "modelAnswer": "吉野", "explanation": "皇位継承をめぐる危険を察知した大海人皇子は、いったん出家して吉野に隠遁したのち東国に脱出して兵を集め、大友皇子を破って即位した。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12366", "field": "古代", "difficulty": 4, "type": "truefalse", "question": "壬申の乱に勝利して即位した天武天皇の治世に、戸籍である庚寅年籍が作成された。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "庚寅年籍が作成されたのは690年、持統天皇の治世である。天武天皇の治世には八色の姓の制定や富本銭の鋳造、国史編纂の着手などが行われた。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12367", "field": "古代", "difficulty": 4, "type": "choice", "question": "桓武天皇の時代に行われた蝦夷平定策について、正しいものを1つ選べ。", "choices": ["坂東諸国から動員された兵士による大規模な征夷が行われた", "阿倍比羅夫を派遣して日本海側の蝦夷地に遠征させた", "徳政相論の結果、征夷と造都の事業をさらに継続する方針が採られた", "口分田の班給がこの時代に初めて全国的に開始された"], "answer": 0, "modelAnswer": "", "explanation": "桓武朝では坂東諸国から多い時で十万人規模の兵士が動員され大規模な征夷が行われた。阿倍比羅夫の遠征は7世紀斉明朝の事績であり、徳政相論の結果は征夷・造都の停止であり、班田収授は701年の大宝律令以降既に実施されていた。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12368", "field": "中世", "difficulty": 3, "type": "choice", "question": "10世紀に起こった平将門の乱について、正しいものを1つ選べ。", "choices": ["平将門は東国で新皇を自称して独立を宣言したが、平貞盛や藤原秀郷らによって討たれた", "平将門は西国で反乱を起こし大宰府などを焼き討ちにした", "平将門の乱は藤原純友の乱よりものちの時代に起こった", "平将門は関白藤原忠平の要請を受けて反乱の鎮圧にあたった"], "answer": 0, "modelAnswer": "", "explanation": "平将門は東国で新皇を自称し独立を宣言したが、平貞盛・藤原秀郷らに討たれた。大宰府焼き討ちは西国で反乱を起こした藤原純友の事績であり、両者の乱はほぼ同時期に起こった。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12369", "field": "中世", "difficulty": 2, "type": "short", "question": "鎌倉幕府の守護に与えられた基本的な職権(大番催促・謀反人の逮捕・殺害人の逮捕)を総称して何と呼ぶか。", "choices": [], "answer": "大犯三カ条", "modelAnswer": "大犯三カ条", "explanation": "守護は原則として国ごとに1名任命され、大犯三カ条を基本的な職権として在地の軍事・警察権を担った。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12370", "field": "中世", "difficulty": 3, "type": "short", "question": "1221年、北条義時追討を掲げて挙兵したが敗れ、隠岐に配流された上皇は誰か。", "choices": [], "answer": "後鳥羽上皇", "modelAnswer": "後鳥羽上皇", "explanation": "後鳥羽上皇は承久の乱で幕府方に敗れて隠岐に配流された。乱後、幕府は京都に六波羅探題を設置して朝廷監視を強化した。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12371", "field": "中世", "difficulty": 2, "type": "short", "question": "承久の乱後、朝廷の監視と西国御家人の統轄のために幕府が京都に設置した機関を答えよ。", "choices": [], "answer": "六波羅探題", "modelAnswer": "六波羅探題", "explanation": "承久の乱に勝利した幕府は京都に六波羅探題を置き、乱に敗れた上皇方の所領を没収して御家人を配置するなど西国支配を強化した。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12372", "field": "中世", "difficulty": 3, "type": "choice", "question": "南北朝の動乱期に守護の権限が大幅に拡大した背景として、正しいものを1つ選べ。", "choices": ["観応の擾乱をはじめとする幕府内部の対立の中で、守護の軍事動員力が重視されたため", "守護職がすべて将軍の一門によって独占されるようになったため", "地頭職が全廃され守護に権限が一元化されたため", "六波羅探題が廃止され、その権限が守護に移譲されたため"], "answer": 0, "modelAnswer": "", "explanation": "南北朝の動乱や観応の擾乱による幕府内部の確執の中で、守護は軍事動員のための権限を大幅に拡大し、各地に大名としての実力を蓄えていった。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12373", "field": "中世", "difficulty": 3, "type": "short", "question": "1441年、有力守護の勢力削減を進めた将軍足利義教が播磨の守護赤松満祐によって暗殺された事件を何と呼ぶか。", "choices": [], "answer": "嘉吉の変(嘉吉の乱)", "modelAnswer": "嘉吉の変(嘉吉の乱)", "explanation": "専制的な統制を強めていた足利義教は、自らの勢力削減を恐れた赤松満祐によって謀殺された。この事件を嘉吉の変(嘉吉の乱)という。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12374", "field": "近世", "difficulty": 2, "type": "truefalse", "question": "豊臣秀吉が実施した太閤検地により、全国の田畑の生産力は米の量に換算した石高として統一的に把握されるようになった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "秀吉は検地竿・枡を統一して全国的に検地を実施し、生産力を石高として一元的に把握した。石高は大名の軍役や農民の年貢負担の基準となった。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12375", "field": "近世", "difficulty": 4, "type": "truefalse", "question": "江戸幕府は寛文年間、すべての大名に一斉に知行を保証する文書を発給し、これによって将軍家と大名家という「家」同士の関係が強調されるようになった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "寛文年間の一斉判物・朱印状発給(寛文印知)により、将軍と大名の関係は個人的な主従関係から、家格に基づく家と家との関係へと性格を強めていったとされる。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12376", "field": "近世", "difficulty": 2, "type": "short", "question": "江戸幕府が大名統制の手段として行った、大名の所領を没収する処分を漢字2字で答えよ。", "choices": [], "answer": "改易", "modelAnswer": "改易", "explanation": "幕府は大名統制のため、所領を没収する改易のほか、減封や国替を行い、大名の力を抑制した。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12377", "field": "近代", "difficulty": 3, "type": "short", "question": "1912年、陸軍の2個師団増設要求を第二次西園寺内閣が拒否したことをきっかけに陸軍大臣が辞表を提出し内閣が総辞職した後、内大臣兼侍従長の地位から組閣し、第一次護憲運動によって短期間で退陣に追い込まれた人物は誰か。", "choices": [], "answer": "桂太郎", "modelAnswer": "桂太郎", "explanation": "内大臣兼侍従長であった桂太郎の組閣は宮中と政府の領分を乱すとの批判を招き、尾崎行雄や犬養毅らを中心とする護憲運動が全国的に広がって、第三次桂内閣は1913年2月に退陣した(大正政変)。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12378", "field": "近代", "difficulty": 5, "type": "essay", "question": "吉野作造が1916年に発表した論文で提唱した「民本主義」とはどのような政治思想か。天皇主権の枠組みとの関係にふれながら100字程度で説明せよ。", "choices": [], "answer": "", "modelAnswer": "天皇主権そのものは否定せず、その法的枠組みを前提としつつも、政治の目的を一般民衆の利益と幸福の実現に置き、政策決定において民衆の意向を重視すべきだとする思想。普通選挙による議会政治の充実を主張し、大正デモクラシーの理論的支柱となった。", "explanation": "民本主義は主権の所在を問う欧米流の民主主義(デモクラシー)とは区別され、天皇主権下でも民衆本位の政治運営を目指す独自の理論として、大正期の政党政治・普通選挙運動を支える思想的基盤となった。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12379", "field": "近代", "difficulty": 3, "type": "truefalse", "question": "1925年に成立した普通選挙法は、25歳以上の男性に衆議院議員の選挙権を認めたが、女性の選挙権は認められなかった。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "1925年の普通選挙法により納税額による制限が撤廃され、25歳以上の男性に選挙権が認められて有権者数は大きく増加したが、女性参政権が認められるのは1945年の改正まで待たねばならなかった。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12380", "field": "文化史", "difficulty": 3, "type": "short", "question": "唐招提寺に伝わる鑑真和上像は、生けるが如き姿を表す肖像彫刻の古い現存例として知られるが、これはどのような技法によって製作された彫刻か。", "choices": [], "answer": "乾漆像(脱活乾漆造)", "modelAnswer": "乾漆像(脱活乾漆造)", "explanation": "鑑真和上像は脱活乾漆造による乾漆像であり、鑑真の没後まもない時期に礼拝対象としての聖なる像として製作されたと考えられている。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12381", "field": "文化史", "difficulty": 2, "type": "choice", "question": "1654年に中国福建省から来日した隠元隆琦が日本に伝えた禅宗の一派は何と呼ばれるか、次から1つ選べ。", "choices": ["臨済宗", "曹洞宗", "黄檗宗", "浄土真宗"], "answer": 2, "modelAnswer": "", "explanation": "隠元隆琦は1654年に来日し、黄檗宗を伝えた。その頂相(肖像画)には、西洋から中国経由で伝わった陰影法を用いた立体的な表現が見られる。（文学部2016年で問われた論点）", "source": "2016", "faculty": "文学部"},
  {"id": "q12400", "field": "古代", "difficulty": 2, "type": "short", "question": "旧石器時代の石器づくりに用いられた黒曜石やサヌカイトなどの石材は、産地が特定の地域に限られる一方、原産地から遠く離れた範囲でも出土している。これを可能にした地域間のやりとりを何というか、漢字2字で答えよ。", "choices": [], "answer": "交易", "modelAnswer": "交易", "explanation": "黒曜石やサヌカイトのように原産地が限定される石材が広範囲から出土する事実は、旧石器時代にすでに地域間の交易が行われていたことを示す証拠とされる。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12401", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "縄文時代のほぼ全時期を通じて主要な食料であった堅果類の調理には、石皿やすり石などの加工具が用いられた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "クリやドングリなどの堅果類は縄文時代を通じて主要な植物性食料であり、その調理・加工には石皿やすり石が広く使われた。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12402", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "縄文時代後半期に磨製技術で作られた石棒・石剣・独鈷石などの祭祀的な石器の多くは、弥生時代に入っても継続して製作された。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "石棒・石剣・独鈷石などの縄文後期の祭祀的石器は縄文時代の宗教・精神生活を反映するものだが、弥生時代まで継続して製作されたものは少ないとされる。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12403", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代に新たに登場した武器のうち、その系譜について正しい組み合わせを1つ選べ。", "choices": ["磨製石剣は朝鮮半島に系譜をもち、磨製石鏃は縄文時代の系譜を引く", "磨製石剣は縄文時代の系譜を引き、磨製石鏃は朝鮮半島に系譜をもつ", "磨製石剣・磨製石鏃はともに朝鮮半島に系譜をもつ", "磨製石剣・磨製石鏃はともに弥生文化の中で独自に発明された"], "answer": 0, "modelAnswer": "", "explanation": "弥生時代に登場した磨製石剣は朝鮮半島に由来するのに対し、磨製石鏃は縄文時代以来の系譜を引くと考えられている。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12404", "field": "古代", "difficulty": 2, "type": "short", "question": "6世紀末に即位し、隋という新王朝の成立という国際環境の変化のもとで遣隋使の派遣など数々の政策を実行した、かつて用明天皇の后であった女性天皇は誰か。", "choices": [], "answer": "推古天皇", "modelAnswer": "推古天皇", "explanation": "推古天皇は用明天皇の后であったが即位し、隋という新王朝の成立という国際環境の変化に対応して遣隋使を派遣するなど新たな政策を展開した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12405", "field": "古代", "difficulty": 2, "type": "short", "question": "推古天皇の時代、隋の建国後20年以上を経てはじめて隋に派遣され、翌年には隋の答礼使裴世清を伴って帰国した人物は誰か。", "choices": [], "answer": "小野妹子", "modelAnswer": "小野妹子", "explanation": "小野妹子は遣隋使として派遣され、翌年には隋からの答礼使裴世清を伴って帰国するなど、日隋間の外交を担った。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12406", "field": "古代", "difficulty": 3, "type": "short", "question": "皇極天皇は一度皇位を退いたのち、国際的な緊張が高まる中で斉明天皇として再び即位した。このように同一人物が二度即位することを何と呼ぶか、漢字2字で答えよ。", "choices": [], "answer": "重祚", "modelAnswer": "重祚", "explanation": "皇極天皇は一度譲位したのち斉明天皇として再び即位しており、このように同一人物が再度即位することを重祚という。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12407", "field": "文化史", "difficulty": 2, "type": "short", "question": "美術史家辻惟雄は、日本美術の特徴を「かざり」「あそび」ともう一つのキーワードで要約した。素朴な精霊信仰に裏づけられた性格を表すこの語をカタカナで答えよ。", "choices": [], "answer": "アニミズム", "modelAnswer": "アニミズム", "explanation": "辻惟雄は日本美術の特徴を「かざり」(装飾性)「あそび」(遊戯性)「アニミズム」(精霊信仰に基づく性格)の3つに要約した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12408", "field": "古代", "difficulty": 3, "type": "short", "question": "孝謙天皇が重祚した称徳天皇は仏教政治に傾斜し、百万塔を造って諸寺に分置する契機となった寺院を創建した。この寺院を答えよ。", "choices": [], "answer": "西大寺", "modelAnswer": "西大寺", "explanation": "孝謙天皇は重祚して称徳天皇となり、仏教政治に傾斜して西大寺を創建し、百万塔を造って諸寺に分置した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12409", "field": "中世", "difficulty": 2, "type": "short", "question": "承久の乱後、幕府が京都に設置した、朝廷監視と西国御家人統轄を目的とする機関を答えよ。", "choices": [], "answer": "六波羅探題", "modelAnswer": "六波羅探題", "explanation": "承久の乱で幕府方が勝利すると、京都には六波羅探題が置かれ、朝廷監視や西国支配の拠点として機能した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12410", "field": "中世", "difficulty": 3, "type": "short", "question": "足利義満が京都に営んだ豪壮な邸宅で、将軍が京都の支配者であることを象徴する存在となったものを何と呼ぶか。", "choices": [], "answer": "花の御所(室町殿・室町第)", "modelAnswer": "花の御所(室町殿・室町第)", "explanation": "足利義満が造営したこの邸宅は「花の御所」とも呼ばれ、将軍が京都の政治・文化の中心に君臨する存在であることを象徴した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12411", "field": "中世", "difficulty": 4, "type": "truefalse", "question": "室町時代の京都では、侍所が都市の警察権を掌握する一方、五山派の禅僧は非課税の特権を得ており、土倉・酒屋には土倉役・酒屋役が幕府によって課された。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "室町幕府は侍所によって京都の治安維持にあたる一方、五山の禅僧には非課税の特権を与え、金融業者である土倉・酒屋には土倉役・酒屋役という課税を行い財源とした。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12412", "field": "中世", "difficulty": 3, "type": "short", "question": "戦国時代、越前の朝倉氏が本拠を置いて城下町として繁栄させたが、朝倉氏の滅亡とともに衰退した都市を答えよ。", "choices": [], "answer": "一乗谷", "modelAnswer": "一乗谷", "explanation": "越前の朝倉氏は一乗谷を本拠として城下町を繁栄させたが、織田信長によって朝倉氏が滅ぼされると一乗谷も衰退した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12413", "field": "近世", "difficulty": 2, "type": "short", "question": "江戸幕府による大名統制の手段の一つで、広島城の無断修築を理由に領地を没収された福島正則の事例に代表される処分を何というか。", "choices": [], "answer": "改易", "modelAnswer": "改易", "explanation": "福島正則は広島城の無断修築を理由に改易された。改易は大名の所領を没収する処分で、幕府による大名統制の重要な手段であった。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12414", "field": "近世", "difficulty": 4, "type": "truefalse", "question": "1651年の慶安の変(由井正雪の乱)ののち、幕府は死に際して願い出た相続人(末期養子)を一定の条件のもとで認めるようになり、これによって大名が改易を免れる道が開かれた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "慶安の変を契機に、幕府は末期養子の禁を緩和し、50歳未満の大名に限り末期養子を認めるようになった。これにより不用意な改易による大名家の断絶が減少した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12415", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸幕府が江戸から離れた直轄地を支配するために置いた遠国奉行のうち、九州で貿易・外交の実務を担ったものを答えよ。", "choices": [], "answer": "長崎奉行", "modelAnswer": "長崎奉行", "explanation": "幕府は江戸から離れた直轄地に遠国奉行を置いて統治にあたらせたが、長崎奉行はそのうち貿易・外交の実務を担う重要な役職であった。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12416", "field": "近世", "difficulty": 3, "type": "short", "question": "天明の飢饉による農村荒廃と江戸への人口流入を受けて、老中松平定信が農村人口の回復を図るために発した法令を何というか。", "choices": [], "answer": "旧里帰農令", "modelAnswer": "旧里帰農令", "explanation": "天明期の飢饉と凶作により農村人口が減少し江戸に無宿人が増加したことを受け、松平定信は旧里帰農令を発して農村への帰農を奨励した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12417", "field": "外交史", "difficulty": 2, "type": "short", "question": "1879年、日本政府が琉球王国を廃止し沖縄県を設置した一連の措置を何と呼ぶか。", "choices": [], "answer": "琉球処分", "modelAnswer": "琉球処分", "explanation": "1879年、日本政府は軍隊を派遣して琉球王国を廃止し沖縄県を設置したが、清はこれを認めず、日清間の外交問題となった。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12418", "field": "外交史", "difficulty": 3, "type": "short", "question": "1894年、日清戦争中に調印され、日本がイギリスとの間で領事裁判権(治外法権)の撤廃に成功した条約を答えよ。", "choices": [], "answer": "日英通商航海条約", "modelAnswer": "日英通商航海条約", "explanation": "陸奥宗光外相のもとで調印された日英通商航海条約により、日本はイギリスとの間で法権(領事裁判権)を回復した。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12419", "field": "外交史", "difficulty": 4, "type": "truefalse", "question": "1941年、日米交渉が不成立に終わった際、アメリカ側が提示したハル=ノートは満州事変以前の状態への復帰などを要求する内容であり、日本側はこれを最後通牒とみなして開戦の判断材料とした。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "ハル=ノートは中国・仏印からの全面撤兵など満州事変以前の状態への復帰を求める強硬な内容であり、日本側はこれを最後通牒と受け止め、対米開戦の決意を固める要因となった。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12420", "field": "外交史", "difficulty": 3, "type": "short", "question": "1951年に調印されたサンフランシスコ平和条約と同時に締結され、占領終結後もアメリカ軍が日本に駐留し続けることを認めた条約を答えよ。", "choices": [], "answer": "日米安全保障条約", "modelAnswer": "日米安全保障条約", "explanation": "サンフランシスコ平和条約と同時に調印された日米安全保障条約により、日本は独立回復後もアメリカ軍の駐留を認め、沖縄はその後もアメリカの施政権下に置かれ続けた。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12421", "field": "文化史", "difficulty": 3, "type": "short", "question": "江戸時代、俵屋宗達が描いた屛風で、「かざり」「あそび」「アニミズム」の三要素を融合させた日本美術史上の傑作とされ、のちに尾形光琳が模写し、酒井抱一がその画風を慕ったことで知られる作品は何か。", "choices": [], "answer": "風神雷神図屏風", "modelAnswer": "風神雷神図屏風", "explanation": "俵屋宗達の「風神雷神図屏風」は装飾性・遊戯性・アニミズム的な感性を融合させた傑作とされ、尾形光琳が模写し、光琳の画風を慕った酒井抱一が私淑の証として関連作品を残すなど、「琳派」の系譜に受け継がれた。（文学部2017年で問われた論点）", "source": "2017", "faculty": "文学部"},
  {"id": "q12440", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "弥生時代の稲作では、短粒米を中心とする栽培が行われており、短粒米と長粒米がほぼ同じ割合で半分ずつ栽培されていたわけではないと考えられている。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "弥生時代の稲は短粒のジャポニカ種を中心に栽培されたと考えられており、短粒米と長粒米が半々の割合で栽培されたとする見方は誤りとされる。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12441", "field": "古代", "difficulty": 3, "type": "short", "question": "倭の奴国王が57年に後漢に朝貢して金印を授けられたことなど、倭に関する記述の中でも特に古い時代の出来事を伝える中国の史書は何か。", "choices": [], "answer": "『後漢書』東夷伝", "modelAnswer": "『後漢書』東夷伝", "explanation": "『後漢書』東夷伝には57年の奴国王の朝貢や107年の帥升らの朝貢など、倭に関する記事の中でも古い時代の出来事が記されている。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12442", "field": "古代", "difficulty": 2, "type": "short", "question": "邪馬台国の女王卑弥呼が魏に使いを送った際、朝鮮半島に置かれ経由地となった中国の出先機関を答えよ。", "choices": [], "answer": "帯方郡", "modelAnswer": "帯方郡", "explanation": "卑弥呼は帯方郡を経由して魏に使者を送り、皇帝から「親魏倭王」の称号や金印などを授けられた。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12443", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "『魏志』倭人伝が伝える3世紀の倭人社会では、稲作や養蚕は行われていたが、牛馬の牧畜は行われていなかったとされる。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "『魏志』倭人伝には倭人社会で稲作・養蚕が行われていたことが記されるが、牛馬の飼育については触れられておらず、当時の倭では牧畜が行われていなかったと考えられている。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12444", "field": "文化史", "difficulty": 2, "type": "short", "question": "『日本書紀』によれば、6世紀に日本へ公式に仏教を伝えたとされる朝鮮半島の国はどこか。", "choices": [], "answer": "百済", "modelAnswer": "百済", "explanation": "『日本書紀』の記述によれば仏教は百済から公伝し、その受容をめぐる論争を経て倭国は仏教を受け入れることとなった。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12445", "field": "文化史", "difficulty": 3, "type": "short", "question": "日本で最初に本格的に建立された寺院である飛鳥寺は、1つの塔といくつの金堂から成る伽藍配置をとっていたか、算用数字で答えよ。", "choices": [], "answer": "3", "modelAnswer": "3", "explanation": "飛鳥寺は百済からの技術者の指導のもと、1つの塔と3つの金堂を配置する一塔三金堂式(飛鳥寺式)の伽藍をもつ、日本最初の本格的寺院として建立された。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12446", "field": "文化史", "difficulty": 2, "type": "short", "question": "聖武天皇が仏教による鎮護国家を願い、光明皇后の庇護のもと諸国に建立を命じた寺院を、対になる2種の名称で答えよ。", "choices": [], "answer": "国分寺・国分尼寺", "modelAnswer": "国分寺・国分尼寺", "explanation": "聖武天皇は仏教による鎮護国家を願って諸国に国分寺・国分尼寺を建立させるとともに、東大寺に大仏を造立した。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12447", "field": "文化史", "difficulty": 2, "type": "short", "question": "苦難の末に来日し、日本に戒律を伝えたことでよく知られる唐の僧は誰か。", "choices": [], "answer": "鑑真", "modelAnswer": "鑑真", "explanation": "鑑真は幾度もの苦難を乗り越えて来日し、日本に戒律を伝えた奈良時代の著名な渡来僧である。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12448", "field": "文化史", "difficulty": 3, "type": "short", "question": "後白河上皇が当代の著名な絵師たちに命じて作成させ、宮廷の年中行事や賀茂祭などの神事仏事、庶民の遊興までを描いた絵巻物を何と呼ぶか。", "choices": [], "answer": "年中行事絵巻", "modelAnswer": "年中行事絵巻", "explanation": "後白河上皇は『年中行事絵巻』の作成を命じ、蓮華王院に隣接する法住寺殿の宝蔵に納めたとされる。宮廷儀式のみならず庶民の遊興や祭礼までも描いた点に特色がある。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12449", "field": "中世", "difficulty": 3, "type": "short", "question": "鎌倉幕府を倒した後醍醐天皇が、建武新政に際して和文体で著し、朝儀の再興を図ったことで知られる書物は何か。", "choices": [], "answer": "建武年中行事", "modelAnswer": "建武年中行事", "explanation": "後醍醐天皇は建武新政に際して『建武年中行事』を著し、和文で書かれたこの書は政治的対立を超えて南北朝双方で参照・引用され、伝統文化の持続性を示す好例となった。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12450", "field": "中世", "difficulty": 3, "type": "short", "question": "1467年から1477年まで続き、この乱の後に町衆の経済力と結束力を背景として、山鉾を中心とする形で祇園祭が復活する契機となった戦乱を何というか。", "choices": [], "answer": "応仁の乱", "modelAnswer": "応仁の乱", "explanation": "応仁の乱による中断を経て、祇園祭は町衆の経済力・結束力を背景に「祇園祭」として復興し、山鉾を各町が競って作成し大路を練り歩く形式が祭礼の中心的位置を占めるようになった。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12451", "field": "中世", "difficulty": 3, "type": "short", "question": "後醍醐天皇を補佐して南朝勢力の保持に努め、南朝の正統性を主張する歴史書『神皇正統記』を著した人物は誰か。", "choices": [], "answer": "北畠親房", "modelAnswer": "北畠親房", "explanation": "北畠親房は後醍醐天皇・後村上天皇を補佐して南朝方の勢力保持に努め、その正統性の根拠を説く『神皇正統記』を著した。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12452", "field": "文化史", "difficulty": 3, "type": "truefalse", "question": "16世紀に作成された『洛中洛外図屏風』の中には、狩野永徳の筆によるもので、戦国大名の上杉氏に贈られたと伝えられる作品がある。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "狩野永徳の描いた『洛中洛外図屏風』(上杉本)は、上杉氏に贈られたと伝えられる華麗な作品で、再興された祇園御霊会の様子などが描かれている。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12453", "field": "社会経済", "difficulty": 2, "type": "short", "question": "江戸時代、東廻り海運および西廻り海運を整備・確立させ、水上交通網の発達に貢献した人物は誰か。", "choices": [], "answer": "河村瑞賢", "modelAnswer": "河村瑞賢", "explanation": "河村瑞賢は東廻り海運・西廻り海運を確立させ、諸国の物資を主要都市へ効率的に輸送する水上交通網の整備に貢献した。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12454", "field": "社会経済", "difficulty": 3, "type": "short", "question": "大坂で堂島の米市場と並んで活発な取引が行われた、青物(野菜)を扱う市場が置かれた地名を漢字2字で答えよ。", "choices": [], "answer": "天満", "modelAnswer": "天満", "explanation": "大坂は「天下の台所」と呼ばれ、堂島の米市場のほか、天満の青物市場でも活発な取引が行われた。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12455", "field": "社会経済", "difficulty": 3, "type": "choice", "question": "江戸時代、赤穂を中心とする瀬戸内海地域で発達した、土木技術を用いて潮の干満を利用し海水を砂浜に引き込んで製塩する方式を何式というか、1つ選べ。", "choices": ["入浜式", "揚浜式", "流下式", "枝条架式"], "answer": 0, "modelAnswer": "", "explanation": "赤穂などの瀬戸内海地域では、人力で海水を汲み上げる古くからの揚浜式に代わり、潮の干満を利用して海水を引き込む入浜式塩田が発達し、生産量を大きく増大させた。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12456", "field": "社会経済", "difficulty": 3, "type": "short", "question": "鮑・いりこ・ふかひれなど、長崎から中国へ輸出された海産物の乾物を総称して何と呼ぶか。", "choices": [], "answer": "俵物", "modelAnswer": "俵物", "explanation": "鮑・いりこ・ふかひれなどの海産物の乾物は俵物と呼ばれ、長崎貿易において中国向けの主要な輸出品となった。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12457", "field": "近代", "difficulty": 3, "type": "short", "question": "1878年に制定された郡区町村編制法・府県会規則・地方税規則の3つの法令を総称して何と呼ぶか。", "choices": [], "answer": "地方三新法", "modelAnswer": "地方三新法", "explanation": "郡区町村編制法・府県会規則・地方税規則の3法令は地方三新法と呼ばれ、明治政府による地方制度整備の初期の到達点となった。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12458", "field": "近代", "difficulty": 4, "type": "truefalse", "question": "日露戦争後の1908年、第二次桂太郎内閣は国民道徳の強化を図るため戊申詔書を発し、翌年から地方改良運動を推進して地方社会の統制を進めた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "第二次桂太郎内閣は1908年に戊申詔書を発して国民道徳の強化を掲げ、翌年から地方改良運動を推進して町村財政の立て直しや地方社会の統制強化を図った。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12459", "field": "近代", "difficulty": 3, "type": "short", "question": "1947年に地方自治法が成立した後、翌年施行された法律によって人口5000人以上の市町村に設置されることになった組織を何というか。", "choices": [], "answer": "自治体警察", "modelAnswer": "自治体警察", "explanation": "1947年の地方自治法に続き、1948年施行の警察法により人口5000人以上の市町村には自治体警察が設置され、戦前の官僚的な中央集権体制からの転換が図られた。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12460", "field": "文化史", "difficulty": 3, "type": "short", "question": "尾形光琳の代表作『燕子花図屏風』は、ある人物が三河国八橋で「かきつばた」の5文字を和歌に詠みこんだという故事(折句)にもとづくとされる。その典拠となった平安時代の文学作品は何か。", "choices": [], "answer": "伊勢物語", "modelAnswer": "伊勢物語", "explanation": "『伊勢物語』東下りの段で、在原業平とされる人物が三河国八橋で「かきつばた」の5文字を句頭に折り込んだ和歌を詠んだ故事が、光琳の『燕子花図屏風』の典拠になったとされる。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12461", "field": "文化史", "difficulty": 2, "type": "short", "question": "「特撮の神様」と呼ばれ、1966年公開の『フランケンシュタインの怪獣 サンダ対ガイラ』などで特殊技術撮影を手がけた人物は誰か。", "choices": [], "answer": "円谷英二", "modelAnswer": "円谷英二", "explanation": "円谷英二はゴジラをはじめ数々の特撮キャラクターを生み出し、「特撮の神様」と呼ばれる映画監督・特殊技術者である。俵屋宗達の風神雷神の図像は、こうした現代の特撮映画の宣伝美術にも影響を与えたとされる。（文学部2018年で問われた論点）", "source": "2018", "faculty": "文学部"},
  {"id": "q12480", "field": "古代", "difficulty": 3, "type": "short", "question": "沖縄県石垣島の洞穴遺跡で発見された、後期旧石器時代人の人骨を多数含み墓域であった可能性が指摘される遺跡の名称を答えよ。", "choices": [], "answer": "白保竿根田原洞穴(遺跡)", "modelAnswer": "白保竿根田原洞穴(遺跡)", "explanation": "石垣島の白保竿根田原洞穴では旧石器時代人骨が十数体分発見され、後期旧石器人の墓域であったと推定されている。日本列島では旧石器時代の墓の発見例自体が乏しく、貴重な事例である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12481", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代の北部九州で成立した、中国製青銅鏡や武器形青銅器などを多量に副葬する墓制として最も適切なものはどれか。", "choices": ["支石墓", "甕棺墓", "方形周溝墓", "前方後円墳", "積石塚"], "answer": 1, "modelAnswer": "", "explanation": "弥生時代中期の北部九州では甕棺墓の中に多くの金属製品を副葬する例が現れ、有力な「クニ」の王墓と考えられている。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12482", "field": "古代", "difficulty": 3, "type": "truefalse", "question": "山陰地方を中心に分布する四隅突出型墳丘墓は、方形の墳丘の四隅に突出部を持つ弥生時代の墓制である。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "四隅突出型墳丘墓は山陰地方を中心にみられる弥生後期の大型墳丘墓で、地域の有力な支配者層の出現を示す遺構とされる。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12483", "field": "古代", "difficulty": 2, "type": "short", "question": "古墳時代の豪族が、民衆の住む集落とは離れた場所に営んだ、濠や柵で区画されることもある居住施設を何と呼ぶか。", "choices": [], "answer": "豪族居館", "modelAnswer": "豪族居館", "explanation": "古墳時代の支配層である豪族は、一般集落とは区別された豪族居館に居住し、まつりごとを行っていたと考えられている。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12484", "field": "古代", "difficulty": 3, "type": "short", "question": "712年、蝦夷支配強化のため日本海側に新設され、続いて秋田城が築かれる契機となった国の名を答えよ。", "choices": [], "answer": "出羽国", "modelAnswer": "出羽国", "explanation": "712年に出羽国が設置され、まもなく秋田城が築城された。太平洋側の多賀城とあわせ、両面から蝦夷支配が進められた。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12485", "field": "古代", "difficulty": 3, "type": "short", "question": "太平洋側の蝦夷支配拠点として8世紀前半に築かれ、木簡や漆紙文書の出土でも知られる陸奥国の城柵の名を答えよ。", "choices": [], "answer": "多賀城", "modelAnswer": "多賀城", "explanation": "多賀城は陸奥国府と鎮守府を兼ねる拠点として築かれ、木簡・漆紙文書などの出土史料でも著名である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12486", "field": "古代", "difficulty": 4, "type": "short", "question": "780年、帰順していた蝦夷の豪族が反乱を起こし、按察使を殺害して多賀城を焼き打ちした事件を何というか。", "choices": [], "answer": "伊治呰麻呂の乱", "modelAnswer": "伊治呰麻呂の乱", "explanation": "780年、蝦夷の豪族伊治呰麻呂が反乱を起こし、按察使紀広純を殺害して多賀城を焼き打ちした。蝦夷支配の動揺を示す事件である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12487", "field": "古代", "difficulty": 3, "type": "choice", "question": "802年に胆沢城を築き、鎮守府を多賀城から移した征夷大将軍は誰か。", "choices": ["文室綿麻呂", "坂上田村麻呂", "藤原保則", "大伴弟麻呂", "紀古佐美"], "answer": 1, "modelAnswer": "", "explanation": "桓武天皇の命を受けた征夷大将軍坂上田村麻呂は蝦夷の指導者阿弖流為を降し、802年に胆沢城を築いて鎮守府を移した。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12488", "field": "中世", "difficulty": 2, "type": "short", "question": "実在の武士の戦いをいきいきと描いた『平家物語』のように、合戦を主題として鎌倉・南北朝期に多く著された文学のジャンルを何と呼ぶか。", "choices": [], "answer": "軍記物語", "modelAnswer": "軍記物語", "explanation": "『平家物語』に代表される軍記物語は実際の戦乱や武士の活躍を題材とし、時代の転換や動乱を色濃く反映して数多く著された。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12489", "field": "中世", "difficulty": 4, "type": "short", "question": "『太平記』の誤りを正そうとする意図も込めて著され、俗に「難太平記」と呼ばれる著作を残した人物は誰か。", "choices": [], "answer": "今川了俊(貞世)", "modelAnswer": "今川了俊(貞世)", "explanation": "今川貞世(了俊)は自家の事績を弁明する目的も込めて著作を残し、『太平記』の誤りを正そうとしたことから「難太平記」と俗称される。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12490", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "南北朝時代に盛行した闘茶は、茶の産地などを飲み分けて勝敗を競い、賭け物を伴うこともあった遊興である。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "南北朝の動乱期には闘茶が流行し、茶の種類を飲み分けて勝敗や賭け物を競う遊びとして武家・庶民の間に広まった。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12491", "field": "中世", "difficulty": 3, "type": "short", "question": "足利義満の保護のもとで観阿弥・世阿弥が猿楽能を大成した際、大和猿楽四座がその本所として仰いだ寺院はどこか。", "choices": [], "answer": "興福寺", "modelAnswer": "興福寺", "explanation": "大和猿楽四座(観世・宝生・金春・金剛)は興福寺を本所とし、その保護のもとで活動した。室町時代の猿楽能大成は足利義満の保護に負うところが大きい。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12492", "field": "中世", "difficulty": 3, "type": "choice", "question": "6代将軍足利義教が赤松満祐の邸で謀殺された事件を何と呼ぶか。", "choices": ["応仁の乱", "嘉吉の変", "永享の乱", "観応の擾乱", "明徳の乱"], "answer": 1, "modelAnswer": "", "explanation": "1441年、6代将軍足利義教は赤松満祐によって謀殺された(嘉吉の変)。将軍権力の動揺と守護大名の台頭を象徴する事件である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12493", "field": "近世", "difficulty": 3, "type": "short", "question": "4代将軍徳川家綱が幼少で将軍職を継いだ際、叔父にあたる会津藩主として老中とともに幕政を支えた人物は誰か。", "choices": [], "answer": "保科正之", "modelAnswer": "保科正之", "explanation": "家綱が幼くして将軍となったため、徳川家光の異母弟にあたる会津藩主保科正之が老中とともに幕政を補佐した。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12494", "field": "近世", "difficulty": 3, "type": "short", "question": "8代将軍徳川吉宗が自らの子を分家させて創設した田安家・一橋家に、9代家重の子を初代とする清水家を加えた3家を総称して何というか。", "choices": [], "answer": "三卿(御三卿)", "modelAnswer": "三卿(御三卿)", "explanation": "吉宗の子を祖とする田安家・一橋家、家重の子を祖とする清水家をあわせて三卿と呼び、将軍家の血統を補う役割を担った。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12495", "field": "近世", "difficulty": 3, "type": "short", "question": "側用人から老中に進み、株仲間の公認や専売制など商業資本と結んだ積極的な産業振興策を採った人物の姓名を答えよ。", "choices": [], "answer": "田沼意次", "modelAnswer": "田沼意次", "explanation": "田沼意次は側用人から老中となり、株仲間の奨励・専売制・俵物輸出の奨励など商業資本と結んだ経済政策を展開した。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12496", "field": "近世", "difficulty": 4, "type": "truefalse", "question": "13代将軍徳川家定の継嗣をめぐる将軍継嗣問題では、一橋家出身の徳川慶喜を推す勢力を南紀派、紀伊藩主徳川慶福を推す勢力を一橋派と呼んだ。", "choices": ["正しい", "誤っている"], "answer": 0, "modelAnswer": "", "explanation": "実際には、一橋派が徳川斉昭の子で一橋家を継いだ慶喜を推し、南紀派が紀伊藩主徳川慶福(のち家茂)を推した。設問文はこの呼称を逆にしている。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12497", "field": "近代", "difficulty": 3, "type": "short", "question": "1882年創立の東京専門学校を前身とし、明治期に多くの清国人留学生を受け入れたことで知られる大学の名を答えよ。", "choices": [], "answer": "早稲田大学", "modelAnswer": "早稲田大学", "explanation": "早稲田大学(前身・東京専門学校)は法政大学とともに清国からの留学生を数多く受け入れ、宋教仁や陳独秀など中国近代史上の人物を輩出した。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12498", "field": "近代", "difficulty": 3, "type": "short", "question": "第一次世界大戦中、大隈重信内閣が中華民国政府に突きつけた要求で、山東省のドイツ権益継承や南満州・東部内蒙古権益の期限延長などを内容とするものを何というか。", "choices": [], "answer": "二十一カ条の要求", "modelAnswer": "二十一カ条の要求", "explanation": "1915年、大隈内閣は中華民国の袁世凱政府に二十一カ条の要求を突きつけ、山東省権益の継承や南満州・東部内蒙古権益の99カ年延長などを求めた。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12499", "field": "近代", "difficulty": 3, "type": "choice", "question": "満州事変に関する記述として正しいものはどれか。", "choices": ["関東軍による柳条湖での鉄道爆破を契機に始まった", "盧溝橋事件を契機に始まった", "事変直後に満州国が建国された", "国際連盟はただちに日本の連盟脱退を勧告した", "近衛文麿内閣の時に勃発した"], "answer": 0, "modelAnswer": "", "explanation": "満州事変は1931年、関東軍による柳条湖事件(南満州鉄道の爆破)を契機に始まった。満州国建国は翌1932年、当時の首相は若槻礼次郎である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12500", "field": "文化史", "difficulty": 3, "type": "short", "question": "福岡県志賀島で発見された金印に刻まれている、1世紀頃に倭の奴国王が後漢から授けられたことを示す5文字の銘文を答えよ。", "choices": [], "answer": "漢委奴国王", "modelAnswer": "漢委奴国王", "explanation": "志賀島で発見された金印には「漢委奴国王」と刻まれており、後漢の光武帝が倭の奴国王に授けたものとされる。中国から日本へ文字が渡来していたことを示す実例である。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12501", "field": "文化史", "difficulty": 3, "type": "choice", "question": "正倉院宝物に含まれる『楽毅論』の筆者とされ、六朝時代の書聖王羲之の書風を伝える人物として正しいものはどれか。", "choices": ["聖武天皇", "元明天皇", "阿倍仲麻呂", "吉備真備", "光明皇后"], "answer": 4, "modelAnswer": "", "explanation": "正倉院宝物中の『楽毅論』は光明皇后の筆と伝えられ、王羲之風の書として奈良時代における中国書法摂取の典型例とされる。（文学部2019年で問われた論点）", "source": "2019", "faculty": "文学部"},
  {"id": "q12520", "field": "古代", "difficulty": 3, "type": "short", "question": "旧石器時代、槍先形の石器に用いられた、長野県和田峠や北海道白滝などで産出するガラス質の火成岩の名称を答えよ。", "choices": [], "answer": "黒曜石", "modelAnswer": "黒曜石", "explanation": "旧石器時代には鋭利な刃部を作るため黒曜石などのガラス質火成岩が石器の原材料として広く利用された。産地は和田峠(長野)・神津島(東京)・腰岳(佐賀)・白滝(北海道)などが知られる。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12521", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代の水稲耕作に用いられた木製農具として適切でないものはどれか。", "choices": ["田下駄", "木鋤", "えぶり", "竪杵", "刀子"], "answer": 4, "modelAnswer": "", "explanation": "えぶり・木鋤・田下駄・竪杵はいずれも弥生時代の農作業に用いられた木製の道具だが、刀子は小型の刃物であり農具には分類されない。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12522", "field": "古代", "difficulty": 3, "type": "short", "question": "古墳時代中期、上毛野・吉備・日向などの地方にも巨大な前方後円墳が営まれたことは、当時の何を示すと考えられているか、簡潔に答えよ。", "choices": [], "answer": "これらの地域の豪族がヤマト政権の中で重要な位置を占めていたこと", "modelAnswer": "これらの地域の豪族がヤマト政権の中で重要な位置を占めていたこと", "explanation": "古墳時代中期、地方豪族の中にも大王墓に匹敵する規模の前方後円墳を営む者が現れ、ヤマト政権における各地域の有力豪族の地位の高さを反映していると考えられている。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12523", "field": "古代", "difficulty": 3, "type": "short", "question": "684年、天武天皇が皇親氏族に与える身分として制定した八色の姓のうち、最上位に位置づけられた姓を答えよ。", "choices": [], "answer": "真人", "modelAnswer": "真人", "explanation": "天武天皇は684年に八色の姓を制定し、皇親氏族に与えられる真人を最上位として、天皇を中心とする新しい身分秩序に豪族を再編成した。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12524", "field": "古代", "difficulty": 4, "type": "short", "question": "689年に施行された飛鳥浄御原令に基づき、翌690年に作成された戸籍を何というか。", "choices": [], "answer": "庚寅年籍", "modelAnswer": "庚寅年籍", "explanation": "持統天皇のもとで690年に作成された庚寅年籍は、飛鳥浄御原令にもとづく本格的な戸籍として民衆の把握を進めた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12525", "field": "古代", "difficulty": 3, "type": "short", "question": "701年に完成した、律令制度の根幹となった法典の編纂に刑部親王とともに中心的な役割を果たした人物は誰か。", "choices": [], "answer": "藤原不比等", "modelAnswer": "藤原不比等", "explanation": "大宝律令の完成には刑部親王とともに藤原不比等が中心的役割を果たしたとされ、律令制度による政治の仕組みがほぼ整った。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12526", "field": "古代", "difficulty": 3, "type": "short", "question": "嵯峨天皇のもとで編纂された、律令の補足・修正法令や施行細則を整理した最初の格式を何というか。", "choices": [], "answer": "弘仁格式", "modelAnswer": "弘仁格式", "explanation": "律令が社会の実態に合わなくなると格式編纂の動きが起こり、嵯峨天皇のもとで弘仁格式が編纂された。後に清和天皇の貞観格式、醍醐天皇の延喜格式が続いた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12527", "field": "中世", "difficulty": 3, "type": "short", "question": "承久の乱後、朝廷の監視と西国御家人の統率のために幕府が京都に設置した機関を何というか。", "choices": [], "answer": "六波羅探題", "modelAnswer": "六波羅探題", "explanation": "承久の乱の勝利後、幕府は京都に六波羅探題を設置し、朝廷の監視や西国御家人の監督にあたらせた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12528", "field": "中世", "difficulty": 3, "type": "short", "question": "1232年、御家人の権利義務や所領相続の基準を定めた御成敗式目を制定した際の鎌倉幕府執権は誰か。", "choices": [], "answer": "北条泰時", "modelAnswer": "北条泰時", "explanation": "3代執権北条泰時は1232年に御成敗式目を制定し、武家社会の慣習に基づく初の武家法典として後世に大きな影響を与えた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12529", "field": "中世", "difficulty": 3, "type": "choice", "question": "蒙古襲来期(13世紀後半)の文化について正しいものはどれか。", "choices": ["一遍の生涯を描いた絵巻に定期市の様子が描かれている", "日蓮が『歎異抄』を著した", "運慶が東大寺南大門金剛力士像を単独で制作した", "北条時宗が金沢文庫を設立した", "竹崎季長は元軍との戦いを『前九年合戦絵巻』に描かせた"], "answer": 0, "modelAnswer": "", "explanation": "一遍の生涯を描いた『一遍上人絵伝』には各地で発達した定期市の様子が描かれており、当時の社会経済の実態を伝える貴重な史料となっている。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12530", "field": "中世", "difficulty": 4, "type": "short", "question": "1391年、丹波・和泉の守護でありながら将軍足利義満と対立して幕府軍に敗れた山名氏の当主が起こした争乱を何というか。", "choices": [], "answer": "明徳の乱", "modelAnswer": "明徳の乱", "explanation": "山名氏清は複数国の守護を兼ねる有力守護であったが、勢力を警戒した足利義満と対立し、1391年の明徳の乱で敗死した。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12531", "field": "中世", "difficulty": 3, "type": "short", "question": "戦国時代、大友義鎮(宗麟)の保護のもとイエズス会が豊後府内に設立した、宣教師養成のための教育施設を何というか。", "choices": [], "answer": "コレジオ", "modelAnswer": "コレジオ", "explanation": "豊後府内では大友義鎮の保護のもと、イエズス会によりコレジオ(神学校)が設立され、キリスト教布教の拠点となった。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12532", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸時代、村や町で宗旨・檀那寺・家族の名前や年齢などを記載し、領民としての公的身分を証明する台帳を何というか。", "choices": [], "answer": "宗門人別改帳", "modelAnswer": "宗門人別改帳", "explanation": "宗門人別改帳への登録によって領民としての公的身分が成立し、結婚などで居住地を移す際には移転先で新たな帳面に記載された。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12533", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸時代の離婚に際して夫から妻へ渡された、その形式の短さから俗称でも呼ばれる文書は何か。", "choices": [], "answer": "三行半(離縁状)", "modelAnswer": "三行半(離縁状)", "explanation": "離縁状は俗に「三行半」と呼ばれ、かつては夫の一方的な離婚宣言と解釈されたが、近年では妻の再婚を証明する書類としての側面が注目されている。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12534", "field": "近世", "difficulty": 3, "type": "short", "question": "『塵劫記』の刊行などにより庶民に広まった日本独自の数学(和算)を大成し、代数計算(点竄術)の基礎を築いた人物は誰か。", "choices": [], "answer": "関孝和", "modelAnswer": "関孝和", "explanation": "関孝和は和算を大成した人物で、代数計算の基礎となる点竄術を考案した。和算は各地を巡る遊歴算家や独習書を通じて広く学ばれた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12535", "field": "近世", "difficulty": 2, "type": "truefalse", "question": "江戸時代、街道には1里ごとに一里塚が設けられ、江戸日本橋を起点として距離が測られた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "一里塚は街道に1里ごとに設置され、江戸日本橋を起点として全国の主要街道の距離の目安とされた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12536", "field": "近世", "difficulty": 3, "type": "short", "question": "東海道の難所として知られ、架橋や渡船が禁じられていたため川越人足を利用して渡らなければならなかった川はどこか。", "choices": [], "answer": "大井川", "modelAnswer": "大井川", "explanation": "「箱根八里は馬でも越すが、越すに越されぬ大井川」と歌われたように、大井川では架橋・渡船が認められず川越人足による徒歩渡しが行われた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12537", "field": "近代", "difficulty": 4, "type": "short", "question": "1880年代、「東洋大日本国国憲按」の起草者として知られ、「万国共議政府」の設置などを構想した論説「無上政法論」を著した自由民権運動の思想家は誰か。", "choices": [], "answer": "植木枝盛", "modelAnswer": "植木枝盛", "explanation": "自由民権運動の思想家植木枝盛は「東洋大日本国国憲按」を起草したことで知られ、国際機構による戦争回避を構想する「無上政法論」も著した。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12538", "field": "近代", "difficulty": 3, "type": "short", "question": "1901年、片山潜・幸徳秋水・安部磯雄らが結成した、軍備全廃などを掲げた日本初の社会主義政党は何か。", "choices": [], "answer": "社会民主党", "modelAnswer": "社会民主党", "explanation": "1901年に結成された社会民主党は軍備全廃や普通選挙の実施などを政策に掲げたが、結成直後に治安警察法によって解散を命じられた。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12539", "field": "近代", "difficulty": 3, "type": "choice", "question": "1928年にパリで調印された不戦条約に関する説明として正しいものはどれか。", "choices": ["国家の政策の手段としての戦争を放棄することを宣言した", "軍縮の数値目標を初めて明記した", "日本はこの条約への調印を拒否した", "調印時の日本の外相は幣原喜重郎ではなかった", "この条約により国際連盟が創設された"], "answer": 0, "modelAnswer": "", "explanation": "パリ不戦条約(1928年)は国家の政策の手段として戦争に訴えることを放棄すると宣言したが、日本では調印文言をめぐり統帥権干犯問題が議論された。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12540", "field": "文化史", "difficulty": 4, "type": "short", "question": "610年に高句麗から渡来し、紙・墨・彩色の技法を日本に伝えたとされる僧の名を答えよ。", "choices": [], "answer": "曇徴", "modelAnswer": "曇徴", "explanation": "高句麗僧曇徴は610年に来日し、紙・墨・彩色の技法や碾磑(水車を利用した石臼)の製法を伝えたと『日本書紀』に記されている。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12541", "field": "文化史", "difficulty": 3, "type": "short", "question": "平安時代、大和絵の祖とされ、紫宸殿の『賢聖障子』の図像制作にも携わった宮廷画家は誰か。", "choices": [], "answer": "巨勢金岡", "modelAnswer": "巨勢金岡", "explanation": "巨勢金岡は大和絵の祖といわれる平安時代の宮廷画家で、紫宸殿の『賢聖障子』に歴代の中国の名臣の図像を描いたと伝えられる。（文学部2020年で問われた論点）", "source": "2020", "faculty": "文学部"},
  {"id": "q12560", "field": "外交史", "difficulty": 3, "type": "short", "question": "『後漢書』東夷伝によれば、57年に倭のある国の王の使者が光武帝から授けられたとされる印綬は、江戸時代に何として発見されたか。", "choices": [], "answer": "漢委奴国王印(金印)", "modelAnswer": "漢委奴国王印(金印)", "explanation": "『後漢書』東夷伝には、57年に倭の奴国王の使者が後漢の光武帝から印綬を授かったと記され、これが江戸時代に志賀島で発見された金印「漢委奴国王」にあたるとされる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12561", "field": "外交史", "difficulty": 3, "type": "short", "question": "3世紀、邪馬台国の女王卑弥呼が魏に使いを送り、皇帝から与えられた称号を答えよ。", "choices": [], "answer": "親魏倭王", "modelAnswer": "親魏倭王", "explanation": "魏志倭人伝によれば、239年に卑弥呼は魏に使者を送り、「親魏倭王」の称号と金印紫綬などを与えられた。倭の小国分立の中で国内をまとめるため中国の権威を利用したものとされる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12562", "field": "古代", "difficulty": 3, "type": "short", "question": "247年、邪馬台国の女王卑弥呼が帯方郡に使いを送り交戦を報告した、邪馬台国の南に位置したとされる国はどこか。", "choices": [], "answer": "狗奴国", "modelAnswer": "狗奴国", "explanation": "魏志倭人伝には、卑弥呼が247年に帯方郡へ使者を送り、邪馬台国の南にある狗奴国との交戦を報告したことが記されている。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12563", "field": "外交史", "difficulty": 4, "type": "short", "question": "4世紀末から5世紀にかけて、朝鮮半島南部をめぐる高句麗と倭の交戦を伝える、吉林省集安に残る石碑を何というか。", "choices": [], "answer": "好太王碑(広開土王碑)", "modelAnswer": "好太王碑(広開土王碑)", "explanation": "好太王碑には高句麗が朝鮮半島北部から領土を拡大し、百済・加耶などを圧迫する中で、加耶と密接な関係にあった倭と直接交戦したことが記されている。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12564", "field": "外交史", "difficulty": 3, "type": "short", "question": "421年から502年の間に讃・珍・済・興・武の5人の王が中国の南朝に使いを送ったことを伝える中国の歴史書の、倭国に関する記述部分の名称を答えよ。", "choices": [], "answer": "『宋書』倭国伝", "modelAnswer": "『宋書』倭国伝", "explanation": "『宋書』倭国伝には、421年から502年の間に倭の五王(讃・珍・済・興・武)が相次いで宋など南朝に使いを送ったことが記されており、朝鮮半島での外交的・軍事的優位を確保しようとする意図がうかがえる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12565", "field": "古代", "difficulty": 4, "type": "short", "question": "倭の五王のうち「武」にあてる説が有力な、雄略天皇と同一視される大王の名を答えよ。", "choices": [], "answer": "ワカタケル大王(獲加多支鹵大王)", "modelAnswer": "ワカタケル大王(獲加多支鹵大王)", "explanation": "倭王武はワカタケル大王(雄略天皇)にあてる説が有力で、埼玉県稲荷山古墳出土の鉄剣や熊本県江田船山古墳出土の大刀にその名が刻まれている。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12566", "field": "古代", "difficulty": 3, "type": "short", "question": "743年、開墾した土地の永久私有を認め、初期荘園成立の契機ともなった法令を何というか。", "choices": [], "answer": "墾田永年私財法", "modelAnswer": "墾田永年私財法", "explanation": "743年に発布された墾田永年私財法は、開墾地の永久私有を認めるもので、これにより勢力ある家による大規模な開墾が進む一方、貧窮の百姓の開墾は困難になったとされる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12567", "field": "古代", "difficulty": 3, "type": "short", "question": "文武天皇の治世から桓武天皇の治世の終わりまでを収め、編年体で記された、六国史のうち2番目にあたる正史を何というか。", "choices": [], "answer": "続日本紀", "modelAnswer": "続日本紀", "explanation": "『続日本紀』は六国史の2番目の正史で、文武天皇の代から桓武天皇の代までを編年体で記録している。全40巻からなる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12568", "field": "中世", "difficulty": 3, "type": "short", "question": "中世、座を結成した商工業者のうち、大寺社に属して奉仕する者を何と呼ぶか(天皇家に属した供御人と対をなす呼称)。", "choices": [], "answer": "神人(じにん)", "modelAnswer": "神人(じにん)", "explanation": "座を結成した商工業者のうち、大寺社に属した者は神人と呼ばれ、天皇家に属した者は供御人と呼ばれた。いずれも本所の権威を背景に独占的な営業権を得た。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12569", "field": "中世", "difficulty": 3, "type": "short", "question": "足利義満のもとで開始された、明との朝貢形式による勘合を用いた貿易を何というか。", "choices": [], "answer": "日明貿易(勘合貿易)", "modelAnswer": "日明貿易(勘合貿易)", "explanation": "足利義満は明との国交を開き、勘合を用いた朝貢形式の日明貿易を開始した。これは外交上の意味だけでなく、関わる人々にとって商業上の利益も大きな関心事であった。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12570", "field": "中世", "difficulty": 3, "type": "short", "question": "室町幕府や戦国大名が、質の劣る私鋳銭の受け取りを制限・選別するために発した法令を何というか。", "choices": [], "answer": "撰銭令", "modelAnswer": "撰銭令", "explanation": "貨幣経済の発展にともない粗悪な私鋳銭が流通したため、幕府や戦国大名は精銭と悪銭の混用比率などを定める撰銭令を発して対応に苦慮した。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12571", "field": "近世", "difficulty": 2, "type": "short", "question": "1853年、アメリカ東インド艦隊司令長官として浦賀に来航し、日本に開国を迫った人物は誰か。", "choices": [], "answer": "ペリー", "modelAnswer": "ペリー", "explanation": "1853年、アメリカ東インド艦隊司令長官ペリーが浦賀に来航し、日本国内は騒然となった。翌年の日米和親条約、1858年の日米修好通商条約へとつながっていく。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12572", "field": "近世", "difficulty": 3, "type": "short", "question": "1858年に調印された日米修好通商条約で、日本に不利な内容として問題視された、外国人の犯罪を領事が裁く制度を何というか。", "choices": [], "answer": "領事裁判権(治外法権)", "modelAnswer": "領事裁判権(治外法権)", "explanation": "日米修好通商条約第6条には、アメリカ人が日本で法を犯した場合、アメリカ領事が裁くと定められており、日本の司法権が及ばない不平等な条項であった。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12573", "field": "近世", "difficulty": 3, "type": "choice", "question": "鎖国下の長崎貿易に関する記述として正しいものはどれか。", "choices": ["長崎からは生糸や絹織物などが輸出され、銅や海産物などが輸入された", "長崎からは銅や海産物などが輸出され、生糸や絹織物などが輸入された", "出島にはオランダ商館があり、清国人も同居していた", "長崎は日本で唯一の開港場として朝鮮や琉球との貿易も独占した", "出島にはイギリス商館が置かれた"], "answer": 1, "modelAnswer": "", "explanation": "鎖国下でも長崎からは銅や海産物などが輸出され、生糸や絹織物などが輸入された。清国人は出島ではなく唐人屋敷に居住し、朝鮮貿易は対馬藩、琉球貿易は薩摩藩がそれぞれ担った。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12574", "field": "近世", "difficulty": 3, "type": "short", "question": "オランダ商館の医師として来日し、帰国に際して国外持ち出し禁止の日本地図を所持していたことが発覚して国外追放となった人物は誰か。", "choices": [], "answer": "シーボルト", "modelAnswer": "シーボルト", "explanation": "シーボルトはオランダ商館医として鳴滝塾を開き高野長英らを育てたが、帰国時に伊能忠敬作成の日本地図の写しを持ち出そうとしたことが発覚し、国外追放処分となった(シーボルト事件)。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12575", "field": "近世", "difficulty": 3, "type": "short", "question": "1862年、薩摩藩主の父島津久光の行列を横切ったイギリス人が殺傷された、横浜近郊で起きた事件を何というか。", "choices": [], "answer": "生麦事件", "modelAnswer": "生麦事件", "explanation": "1862年、横浜近郊の生麦村で薩摩藩主の父島津久光の行列を横切ったイギリス人商人リチャードソンらが殺傷される生麦事件が起こり、翌年の薩英戦争の原因となった。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12576", "field": "近代", "difficulty": 3, "type": "short", "question": "明治末から大正初期にかけて3次にわたり内閣を組織し、巧みな政治交渉を行ったことから「ニコポン宰相」と評された人物は誰か。", "choices": [], "answer": "桂太郎", "modelAnswer": "桂太郎", "explanation": "桂太郎は3次にわたり内閣を組織し、愛想のよさを交えた巧みな政治交渉を行ったことから「ニコポン宰相」と呼ばれた。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12577", "field": "近代", "difficulty": 3, "type": "short", "question": "大正時代、軍艦・兵器の輸入をめぐる海軍高官の汚職が発覚し、山本権兵衛内閣(第1次)が退陣に追い込まれた事件を何というか。", "choices": [], "answer": "シーメンス事件", "modelAnswer": "シーメンス事件", "explanation": "1914年、ドイツのシーメンス社などをめぐる海軍高官の汚職(シーメンス事件)が発覚し、第1次山本権兵衛内閣は退陣を余儀なくされた。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12578", "field": "近代", "difficulty": 3, "type": "short", "question": "1918年、米価高騰を背景に富山県の漁村での主婦らの行動を起点として全国に広がり、時の内閣を総辞職に追い込んだ騒動を何というか。", "choices": [], "answer": "米騒動", "modelAnswer": "米騒動", "explanation": "1918年の米騒動は富山県の漁村での騒動を起点に全国へ広がり、寺内正毅内閣は総辞職に追い込まれた。寺内内閣はその風貌から「ビリケン内閣」とも評された。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12579", "field": "近代", "difficulty": 3, "type": "short", "question": "1955年、日本民主党と自由党が合同して結成された政党を何というか。", "choices": [], "answer": "自由民主党", "modelAnswer": "自由民主党", "explanation": "1955年、日本民主党と自由党が合同して自由民主党が結成された(保守合同)。この根回しに尽力した三木武吉は「野次将軍」の異名で知られた。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12580", "field": "文化史", "difficulty": 3, "type": "short", "question": "正倉院宝物のひとつで、樹下に立つ女性を描いた作品として知られる屏風は何か。", "choices": [], "answer": "鳥毛立女屏風", "modelAnswer": "鳥毛立女屏風", "explanation": "正倉院宝物の鳥毛立女屏風(樹下美人図)は奈良時代の作例で、中国や西域の影響が色濃い異国的な女性表現として知られる。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12581", "field": "文化史", "difficulty": 3, "type": "short", "question": "明治時代、フランス留学から帰国した洋画家で、全身ヌード像を発表して裸体画論争(「腰巻事件」)を引き起こした人物は誰か。", "choices": [], "answer": "黒田清輝", "modelAnswer": "黒田清輝", "explanation": "黒田清輝はフランスへ留学した洋画家で、全身ヌードの女性像を相次いで発表し公序良俗をめぐる裸体画論争を巻き起こした。1901年の白馬会展では下半身に布を巻いて陳列する「腰巻事件」に発展した。（文学部2024年で問われた論点）", "source": "2024", "faculty": "文学部"},
  {"id": "q12600", "field": "古代", "difficulty": 2, "type": "short", "question": "1949年に群馬県の関東ローム層中から打製石器を発見し、日本にも旧石器時代が存在したことをはじめて実証した在野の考古学研究者は誰か。", "choices": [], "answer": "相沢忠洋", "modelAnswer": "相沢忠洋", "explanation": "相沢忠洋は独学で考古学を学び、群馬県岩宿の関東ローム層から打製石器を発見(1949年)、日本旧石器時代の存在を実証した。以後全国で1万カ所を超える旧石器時代の遺跡が確認されている。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12601", "field": "古代", "difficulty": 2, "type": "short", "question": "縄文土器の型式変化にもとづく6時期区分のうち、最も古い時期を漢字で答えよ。", "choices": [], "answer": "草創期", "modelAnswer": "草創期", "explanation": "縄文時代は土器の変遷から草創期・早期・前期・中期・後期・晩期の6期に区分され、最古の時期は草創期と呼ばれる。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12602", "field": "古代", "difficulty": 3, "type": "short", "question": "約1万1500年前の気候温暖化を境として、それ以降現代までの地質時代の区分を漢字3字で答えよ。", "choices": [], "answer": "完新世", "modelAnswer": "完新世", "explanation": "更新世末期の温暖化により大型動物が姿を消し中小動物が繁栄するようになった。この温暖化以降、現代までの地質時代を完新世という。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12603", "field": "古代", "difficulty": 3, "type": "choice", "question": "弥生時代の集落について述べた文として正しいものはどれか。", "choices": ["余剰生産物や水利をめぐる争いが生じ、濠をめぐらせた環濠集落や丘陵・山上に立地する高地性集落など、防御性の高い集落がつくられた。", "稲作の広まりにより集落間の争いはほとんど見られなくなり、平和的な交流のみが支配的となった。", "高地性集落は主に灌漑用水の確保を目的として低地に営まれた集落である。", "環濠集落は身分秩序が存在しなかったことを示す平等な集落形態である。", "高地性集落は縄文時代から継続して営まれ、弥生時代に入ると急速に消滅した。"], "answer": 0, "modelAnswer": "", "explanation": "弥生時代には食料の余剰生産や水利をめぐる集落間の争いが生じ、濠をめぐらせた環濠集落や、防御に適した丘陵・山上に営まれる高地性集落が各地につくられた。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12604", "field": "古代", "difficulty": 2, "type": "short", "question": "239年、卑弥呼が魏に使者を送り、皇帝から与えられた称号を漢字で答えよ。", "choices": [], "answer": "親魏倭王", "modelAnswer": "親魏倭王", "explanation": "邪馬台国の女王卑弥呼は239年に魏へ使者を送り、「親魏倭王」の称号と金印、多数の銅鏡などを授けられた。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12605", "field": "古代", "difficulty": 3, "type": "short", "question": "文武天皇の治世に藤原不比等らによって完成した最初の本格的な律令法典が制定された年にあたる元号を、漢字2字で答えよ。", "choices": [], "answer": "大宝", "modelAnswer": "大宝", "explanation": "701年(大宝元年)、文武天皇のもとで藤原不比等らが大宝律令を完成させた。律と令がともに揃った日本ではじめての本格的な法典である。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12606", "field": "古代", "difficulty": 3, "type": "short", "question": "大宝律令に続き、養老律令の編纂においても中心的役割を果たした人物は誰か。", "choices": [], "answer": "藤原不比等", "modelAnswer": "藤原不比等", "explanation": "藤原不比等は大宝律令の編纂に続き、養老2年(718年)にも勅を奉じて養老律令を編纂した。ただしその施行は不比等の死後、孫の藤原仲麻呂の代になってからであった。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12607", "field": "古代", "difficulty": 4, "type": "short", "question": "天武天皇の代に編纂が始まり、689年、持統天皇の代に令のみが先行して施行された法令を何というか。", "choices": [], "answer": "飛鳥浄御原令", "modelAnswer": "飛鳥浄御原令", "explanation": "天武天皇の命により編纂が始まった浄御原令は、持統天皇3年(689年)に令22巻のみが先行して施行された。律と令がともに揃うのは大宝律令からである。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12608", "field": "中世", "difficulty": 2, "type": "short", "question": "派手な服飾や振る舞いを好んだ「バサラ大名」の代表格として知られ、闘茶や連歌の会を盛んに催した南北朝期の武将は誰か。", "choices": [], "answer": "佐々木導誉", "modelAnswer": "佐々木導誉", "explanation": "佐々木導誉(京極導誉)は綾羅錦繡をまとうなど華美な振る舞いを好み、バサラ大名の代表として知られる。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12609", "field": "中世", "difficulty": 3, "type": "choice", "question": "中世の和歌・連歌に関して述べた文として正しいものはどれか。", "choices": ["武士の家に生まれながら出家し、諸国を遍歴した西行は、私家集『山家集』を残した。", "『新古今和歌集』の編纂を命じたのは後鳥羽上皇ではなく後白河法皇である。", "源実朝は『金槐和歌集』を編み、生涯を通じて朝廷と幕府の融和に努めた。", "連歌集『菟玖波集』は室町幕府の成立以前に准勅撰の扱いを受けた。", "宗祇による『新撰菟玖波集』は鎌倉幕府の滅亡以前に成立した作品である。"], "answer": 0, "modelAnswer": "", "explanation": "西行はもと北面の武士であったが出家して諸国を遍歴し、私家集『山家集』を残した代表的な中世の歌人である。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12610", "field": "中世", "difficulty": 3, "type": "truefalse", "question": "御成敗式目は、子のいない女性が所領を養子に譲ることを、大将家以来の先例(不易の法)として認めていた。", "choices": ["正しい", "誤っている"], "answer": 1, "modelAnswer": "", "explanation": "御成敗式目は源頼朝(大将家)以来の先例として、子のいない女性が所領を養子に譲る女人養子を不易の法(変わることのない決まり)として認めていた。律令にはこうした規定はなく、武家社会の実情に即した独自の規定であった。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12611", "field": "中世", "difficulty": 4, "type": "short", "question": "御家人の困窮と所領売却をめぐる社会不安を背景に永仁の徳政令(1297年)が発布される契機の一つとなった、公暁によって暗殺された鎌倉幕府の将軍は誰か。", "choices": [], "answer": "源実朝", "modelAnswer": "源実朝", "explanation": "鎌倉幕府3代将軍源実朝は1219年、甥の公暁によって暗殺された。将軍暗殺後の政治的動揺や御家人の困窮化は、その後の徳政一揆的動きや永仁の徳政令発布の背景となった。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12612", "field": "中世", "difficulty": 3, "type": "short", "question": "「此頃都ニハヤル物」の書き出しで知られ、建武の新政期の社会の混乱や下剋上の風潮を風刺した文書を何というか。", "choices": [], "answer": "二条河原の落書き", "modelAnswer": "二条河原の落書き", "explanation": "建武の新政期、京都の二条河原に掲げられたとされる落書きは、当時の政治・社会の混乱を鋭く風刺した史料として著名である。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12613", "field": "近世", "difficulty": 3, "type": "choice", "question": "江戸時代の三都に関して述べた文として誤っているものはどれか。", "choices": ["江戸は主に金遣い、大坂は主に銀遣いであり、金・銀・銭の交換比率は公定されていたが実際にはつねに変動した。", "大坂は「天下の台所」と呼ばれ、堂島の米市場などを通じて全国の年貢米や特産物が集散した。", "京都では西陣織などの高度な手工業生産が発達し、幕府は京都所司代を置いて朝廷を統制した。", "江戸は17世紀後半には大規模な都市に成長し、近郊の農村だけではその消費をまかなえないほどの人口を擁するようになった。", "三都はいずれも当初から町人地のみで構成され、武家地や寺社地は区分されていなかった。"], "answer": 4, "modelAnswer": "", "explanation": "江戸をはじめとする三都の城下町は、武家地・寺社地・町人地など身分ごとに居住地域が区分されていた。三都はそれぞれ金銀遣いの違いや商業・手工業機能を持ちつつ発展した。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12614", "field": "近世", "difficulty": 3, "type": "choice", "question": "徳川吉宗が行った享保の改革の政策として正しいものはどれか。", "choices": ["庶民の意見を政治に反映させるため、評定所前に目安箱を設置した。", "生類憐みの令を新たに発布し、動物愛護の徹底を図った。", "幕府収入を増やすため、金の含有率を落とした元禄小判への改鋳を命じた。", "商人同士の金銭貸借について当事者間で解決するよう命じる相対済し令を廃止した。", "裁判や刑罰の基準を定めた公事方御定書の編纂を中止させた。"], "answer": 0, "modelAnswer": "", "explanation": "徳川吉宗は評定所前に目安箱を設置して庶民の意見を政治に取り入れようとしたほか、公事方御定書の編纂、相対済し令の発布など享保の改革を通じて幕政の再建をはかった。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12615", "field": "近世", "difficulty": 3, "type": "short", "question": "江戸時代前期、朱子学を批判して古学を提唱し、『中朝事実』において日本こそが中華に代わる「中朝」であると論じた儒学者は誰か。", "choices": [], "answer": "山鹿素行", "modelAnswer": "山鹿素行", "explanation": "山鹿素行は朱子学の観念的な学風を批判して古学を提唱し、『中朝事実』で日本中心の華夷観を説いた。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12616", "field": "近代", "difficulty": 4, "type": "choice", "question": "次のA〜Dの出来事を、鳥羽・伏見の戦いが勃発する前の時系列順に正しく並べたものはどれか。\nA：徳川慶喜による大政奉還の上表提出\nB：王政復古の大号令の宣言\nC：徳川慶喜に対する辞官納地の処分決定\nD：徳川慶喜の大坂城への引き上げ", "choices": ["A→B→C→D", "A→D→B→C", "B→C→A→D", "B→A→D→C", "C→A→B→D"], "answer": 0, "modelAnswer": "", "explanation": "1867年10月に大政奉還(A)がなされ、同年12月に王政復古の大号令(B)が発せられた。続く小御所会議で辞官納地が決定(C)され、これに反発した徳川慶喜は大坂城へ引き上げた(D)のち、翌年1月に鳥羽・伏見の戦いが勃発した。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12617", "field": "近代", "difficulty": 3, "type": "choice", "question": "民撰議院設立建白書に関して述べた文として正しいものはどれか。", "choices": ["征韓論政変で政府を去った板垣退助・後藤象二郎らが中心となって政府(左院)に提出した。", "政府はこの建白書の提出をただちに歓迎し、その場で国会開設の詔を出した。", "建白書は地租改正に反対する農民を主体として起草されたものである。", "この建白書の提出後、自由民権運動は急速に下火となっていった。", "建白書は薩摩藩出身者のみによって起草された。"], "answer": 0, "modelAnswer": "", "explanation": "征韓論をめぐる政変で下野した板垣退助・後藤象二郎らは1874年、民撰議院設立建白書を政府に提出し、自由民権運動の口火を切った。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12618", "field": "近代", "difficulty": 3, "type": "choice", "question": "日清戦争後の国際情勢とその国内への影響について述べた文として正しいものはどれか。", "choices": ["ロシア・ドイツ・フランスによる三国干渉で遼東半島の返還を余儀なくされたことは、国民のナショナリズムを高揚させる一因となった。", "三国干渉はイギリス・アメリカ・フランスの3カ国によって行われた。", "日清戦争の賠償金は軍備拡張にはあてられず、もっぱら国民への減税にあてられた。", "三国干渉の結果、日本は台湾の領有そのものを放棄した。", "三国干渉を受けて政府はただちに普通選挙の実施を決定した。"], "answer": 0, "modelAnswer": "", "explanation": "日清戦争後、ロシア・ドイツ・フランスによる三国干渉で遼東半島の返還を強いられたことは「臥薪嘗胆」を合言葉としたナショナリズムの昂揚を招き、後の政治動向にも影響を与えた。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12619", "field": "近代", "difficulty": 2, "type": "short", "question": "1925年、護憲三派を率いた加藤高明内閣のもとで成立し、満25歳以上のすべての男性に衆議院議員選挙権を認めた法律を何というか。", "choices": [], "answer": "普通選挙法", "modelAnswer": "普通選挙法", "explanation": "護憲三派内閣であった加藤高明内閣は1925年に普通選挙法を成立させ、選挙権における納税額の制限を撤廃した。同時に治安維持法も制定され、社会主義・共産主義への抑圧も強まった。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12620", "field": "現代", "difficulty": 2, "type": "short", "question": "1960年に成立し、中山マサが厚生大臣に就任したことで、日本の内閣として初めて女性閣僚が誕生した内閣は何内閣か。", "choices": [], "answer": "池田勇人内閣", "modelAnswer": "池田勇人内閣", "explanation": "1960年に成立した池田勇人内閣において中山マサが厚生大臣に就任し、日本ではじめての女性閣僚となった。女性が閣僚に就任するのは戦後、女性に参政権が認められて以降のことである。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"},
  {"id": "q12621", "field": "文化史", "difficulty": 4, "type": "choice", "question": "狩野永徳の作品について述べた文として誤っているものはどれか。", "choices": ["米沢市上杉博物館所蔵の『洛中洛外図屛風』は、制作当初から上杉謙信への贈答を目的として注文された作品である。", "永徳は大徳寺大仙院の襖絵の制作にも携わった。", "永徳の門人には狩野山楽がいる。", "永徳は豊臣秀吉や織田信長のもとで巨大な障壁画の制作にも携わったとされる。", "永徳は長谷川等伯より先に亡くなった。"], "answer": 0, "modelAnswer": "", "explanation": "上杉本『洛中洛外図屛風』は従来、織田信長から上杉謙信への贈答品として知られていたが、近年の研究で当初の注文主が13代将軍足利義輝であったことを示す史料が見つかり、義輝が横死したためのちに信長の手から謙信に贈られたと考えられるようになった。制作当初から謙信への贈答を目的としていたわけではない。（文学部2025年で問われた論点）", "source": "2025", "faculty": "文学部"}
];
